def _infer_button_role(btn_text: str, tooltip: str = "") -> str | None:
    t = (btn_text or "").strip().lower()
    tip = (tooltip or "").strip().lower()

    # Skip obvious color-picker / swatch buttons
    if any(k in t for k in ["color", "colour", "bg", "background", "font"]):
        return None
    if any(k in tip for k in ["color", "colour", "bg", "background", "font"]):
        return None

    # Browse / select inputs
    if t in {"browse", "select", "choose", "load"}:
        return "browse"
    if t.startswith("browse") or t.startswith("select") or t.startswith("choose"):
        return "browse"
    if "browse" in t or "select" in t:
        return "browse"

    if any(k in tip for k in ["select", "choose", "browse", "file", "folder", "directory"]):
        return "browse"

    # Open existing artifacts
    if t.startswith("open") or " open" in t or "open " in t or "open" in t:
        return "open"
    if t.startswith("view") or t.startswith("show"):
        return "open"
    if "open" in tip or "show" in tip or "view" in tip:
        return "open"

    # Run / build / draw / probe
    if t.startswith("run") or " run" in t or "run " in t or "run" in t:
        return "run"
    if t.startswith("draw") or t.startswith("build") or t.startswith("probe") or t.startswith("execute"):
        return "run"

    if any(k in tip for k in ["run", "execute", "start", "build", "draw", "probe"]):
        return "run"

    return None


def _apply_button_role(btn: QWidget):
    try:
        if btn.property("geNoAutoStyle"):
            return
    except Exception:
        pass

    try:
        role = btn.property("geRole")
    except Exception:
        role = None

    if not role:
        try:
            role = _infer_button_role(getattr(btn, "text", lambda: "")(), getattr(btn, "toolTip", lambda: "")())
        except Exception:
            role = None

    if not role:
        return

    # Clear legacy per-button background colors (we now centralize via QSS)
    try:
        ss = getattr(btn, "styleSheet", lambda: "")() or ""
        if "background-color" in ss and any(k in ss.lower() for k in ["lightblue", "dodgerblue", " orange", "background-color: blue", "background-color: orange"]):
            getattr(btn, "setStyleSheet", lambda _s: None)("")
    except Exception:
        pass

    try:
        btn.setProperty("geRole", role)
        # force re-polish so the stylesheet takes effect immediately
        btn.style().unpolish(btn)
        btn.style().polish(btn)
        btn.update()
    except Exception:
        pass


class _ButtonRoleFilter(QObject):
    """Auto-tag QPushButton/QToolButton by text to unify colors."""

    @staticmethod
    def _is_in_ge_window(obj: QWidget) -> bool:
        """Return True only for widgets belonging to the main GE window.

        We deliberately avoid touching Qt's built-in dialogs (e.g. QFileDialog)
        because re-styling them hurts usability and can trigger non-native
        dialog fallbacks.
        """
        try:
            win = obj.window()
            if win is None:
                return False
            return bool(win.property("geRoot"))
        except Exception:
            return False

    def eventFilter(self, obj, ev):
        try:
            if (
                isinstance(obj, (QPushButton, QToolButton))
                and ev.type() in (QEvent.Show, QEvent.Polish)
                and self._is_in_ge_window(obj)
            ):
                _apply_button_role(obj)
        except Exception:
            pass
        return False


