def tighten_form_row_spacing(root: QWidget, *, row_spacing: int = 6, form_v: int = 8, form_h: int = 10):
    """Tighten spacing for widgets using QFormLayout + row-wrapped QHBoxLayout.

    This is used mainly for RNA-seq tabs whose default QHBoxLayout margins
    can appear larger than other tabs.
    """
    widgets = [root] + root.findChildren(QWidget)
    for w in widgets:
        lay = w.layout()
        if lay is None:
            continue

        # row wrappers: QWidget(parent has QFormLayout) containing QHBoxLayout
        if isinstance(lay, QHBoxLayout):
            try:
                p = w.parentWidget()
                if p is not None and isinstance(p.layout(), QFormLayout):
                    lay.setContentsMargins(0, 0, 0, 0)
                    lay.setSpacing(int(row_spacing))
            except Exception:
                pass

        if isinstance(lay, QFormLayout):
            try:
                # keep existing margins if explicitly set small; otherwise normalize
                lay.setHorizontalSpacing(int(form_h))
                lay.setVerticalSpacing(int(form_v))
            except Exception:
                pass




def make_pairs_grid(pairs, per_row: int = 2, *, hspace: int = 12, vspace: int = 6) -> QWidget:
    """Create a compact grid widget for (label, widget) pairs.

    This helps avoid overly wide single-row option panels that trigger horizontal
    scrollbars inside QScrollArea.
    """
    per_row = max(1, int(per_row))
    grid = QGridLayout()
    grid.setContentsMargins(0, 0, 0, 0)
    grid.setHorizontalSpacing(int(hspace))
    grid.setVerticalSpacing(int(vspace))

    for i, (lab, w) in enumerate(pairs):
        r = i // per_row
        c0 = (i % per_row) * 2
        lbl = QLabel(str(lab))
        # PySide6 expects Qt.Alignment/AlignmentFlag, not int
        lbl.setAlignment(Qt.AlignLeft | Qt.AlignVCenter)
        try:
            if hasattr(w, 'setMinimumWidth'):
                w.setMinimumWidth(0)
        except Exception:
            pass
        grid.addWidget(lbl, r, c0)
        grid.addWidget(w, r, c0 + 1)

    for j in range(per_row):
        try:
            grid.setColumnStretch(j * 2 + 1, 1)
        except Exception:
            pass

    out = QWidget()
    out.setLayout(grid)
    return out



def show_df_in_table(table: QTableWidget, df: pd.DataFrame):
    """Populate QTableWidget from a DataFrame.

    Notes:
      - We set Qt.EditRole for numeric-like values so QTableWidget can sort numerically.
      - Sorting is disabled while populating to preserve order + avoid slow resort.
    """
    try:
        table.setSortingEnabled(False)
    except Exception:
        pass

    table.clear()
    table.setRowCount(len(df))
    table.setColumnCount(len(df.columns))
    table.setHorizontalHeaderLabels([str(c) for c in df.columns])

    for r in range(len(df)):
        for c, col in enumerate(df.columns):
            v = df.iloc[r, c]
            item = QTableWidgetItem()
            if pd.isna(v):
                item.setData(Qt.DisplayRole, "")
            else:
                s = str(v)
                item.setData(Qt.DisplayRole, s)
                # best-effort numeric role for correct numeric sorting
                try:
                    num = float(v)
                    item.setData(Qt.EditRole, num)
                    # Prefer the Qt.AlignmentFlag signature (Qt6). Fall back to int for older bindings.
                    try:
                        item.setTextAlignment(Qt.AlignVCenter | Qt.AlignRight)
                    except Exception:
                        item.setTextAlignment(int(Qt.AlignVCenter | Qt.AlignRight))
                except Exception:
                    pass
            table.setItem(r, c, item)

    table.resizeColumnsToContents()

    try:
        table.setSortingEnabled(True)
    except Exception:
        pass





def show_rows_in_table(table: QTableWidget, columns: list[str], rows: list[list]):
    """Render plain rows into QTableWidget without relying on pandas.

    This is a robustness fallback for environments where pandas/numpy combo is unstable.
    """
    try:
        table.setSortingEnabled(False)
    except Exception:
        pass

    table.clear()
    table.setRowCount(len(rows))
    table.setColumnCount(len(columns))
    table.setHorizontalHeaderLabels([str(c) for c in columns])

    for r, row in enumerate(rows):
        for c, v in enumerate(row):
            item = QTableWidgetItem()
            if v is None:
                item.setData(Qt.DisplayRole, "")
            else:
                s = str(v)
                item.setData(Qt.DisplayRole, s)
                # numeric-aware sorting
                try:
                    num = float(v)
                    item.setData(Qt.EditRole, num)
                    item.setTextAlignment(int(Qt.AlignVCenter | Qt.AlignRight))
                except Exception:
                    pass
            table.setItem(r, c, item)

    try:
        table.resizeColumnsToContents()
        table.setSortingEnabled(True)
    except Exception:
        pass


def read_table_light(path: Path, *, sep: str = "\t", comment_prefix: str = "#", max_rows: int | None = None) -> tuple[list[str], list[list[str]]]:
    """Lightweight delimited-table reader (no pandas).

    Returns: (columns, rows) where rows are lists of strings.
    - Skips comment lines starting with comment_prefix
    - Handles UTF-8 BOM on the first header cell
    """
    import csv
    path = Path(path)
    if not path.exists():
        return ([], [])

    cols: list[str] = []
    rows: list[list[str]] = []
    with open(path, "r", encoding="utf-8", errors="replace", newline="") as f:
        reader = csv.reader(f, delimiter=sep)
        for rec in reader:
            if not rec:
                continue
            if rec[0].startswith(comment_prefix):
                continue
            if not cols:
                cols = [str(x) for x in rec]
                if cols:
                    cols[0] = cols[0].lstrip("\ufeff")
                continue
            rows.append([str(x) for x in rec])
            if max_rows is not None and len(rows) >= int(max_rows):
                break
    return (cols, rows)


def read_gwas_top_records(path: Path, *, top_keep: int = 30000, sep: str = "\t", comment_prefix: str = "#") -> list[dict]:
    """Stream-read GWAS results and keep top_keep smallest p-values (no pandas).

    Returns list of standardized records with keys: marker, chr, pos, pvalue, qvalue.
    """
    import csv
    path = Path(path)
    if not path.exists():
        return []

    with open(path, "r", encoding="utf-8", errors="replace", newline="") as f:
        reader = csv.reader(f, delimiter=sep)
        header = None
        for rec in reader:
            if not rec:
                continue
            if rec[0].startswith(comment_prefix):
                continue
            header = [str(x) for x in rec]
            if header:
                header[0] = header[0].lstrip("\ufeff")
            break
        if not header:
            return []

        cols_map = {str(c).strip().lower(): i for i, c in enumerate(header)}

        def pick(cands: list[str]) -> int | None:
            for cand in cands:
                cand_l = cand.lower()
                if cand_l in cols_map:
                    return cols_map[cand_l]
            for name_l, i in cols_map.items():
                for cand in cands:
                    cand_l = cand.lower()
                    if name_l.endswith(cand_l) or cand_l in name_l:
                        return i
            return None

        i_chr = pick(["chr", "chrom", "chromosome", "seqid"])
        i_pos = pick(["pos", "bp", "position", "physical_pos"])
        i_p   = pick(["p", "pvalue", "p_value", "p.val", "pval"])
        i_q   = pick(["q", "qvalue", "q_value", "fdr", "padj", "adj_p"])
        i_m   = pick(["marker", "snp", "id", "rsid", "locus", "variant", "markerid"])

        if i_chr is None or i_pos is None or i_p is None:
            return []

        heap = []  # stores (-p, counter, rec) ; heap[0] is worst (largest p)
        counter = 0

        for rec in reader:
            if not rec:
                continue
            if rec[0].startswith(comment_prefix):
                continue
            try:
                chr_v = str(rec[i_chr]).strip()
                pos_v = float(str(rec[i_pos]).replace(",", ""))
                p_v = float(str(rec[i_p]))
                if not (p_v > 0.0):
                    continue
                q_v = None
                if i_q is not None and i_q < len(rec):
                    try:
                        q_v = float(str(rec[i_q]))
                    except Exception:
                        q_v = None
                m_v = None
                if i_m is not None and i_m < len(rec):
                    m_v = str(rec[i_m]).strip()

                r = {"marker": m_v, "chr": chr_v, "pos": pos_v, "pvalue": p_v, "qvalue": q_v}
                item = (-p_v, counter, r)
                counter += 1

                if top_keep and len(heap) >= int(top_keep):
                    # Keep only better hits (smaller p => larger -p)
                    if item[0] > heap[0][0]:
                        heapq.heapreplace(heap, item)
                else:
                    heapq.heappush(heap, item)
            except Exception:
                continue

        out = [t[2] for t in heap]
        out.sort(key=lambda d: float(d.get("pvalue", 1.0)))
        return out

def read_table_robust(path: Path) -> pd.DataFrame:
    '''Read TSV/CSV robustly.

    On some environments / outputs, pandas.read_csv() can raise unexpected
    TypeError during header/index construction. For GUI stability we try a few
    parsers and finally fall back to a manual header reader.
    '''
    path = Path(path)

    ext = path.suffix.lower()
    if ext == ".csv":
        seps = [",", "\t", ";"]
    else:
        seps = ["\t", ",", ";"]

    last_err = None
    for sep in seps:
        try:
            return pd.read_csv(path, sep=sep, comment="#", low_memory=False)
        except Exception as e:
            last_err = e
            try:
                return pd.read_csv(path, sep=sep, comment="#", low_memory=False, engine="python")
            except Exception:
                pass

    # Manual header fallback (avoids pandas header parsing issues)
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            header = f.readline().rstrip("\r\n")
        cols = header.split("\t")
        if cols:
            cols[0] = cols[0].lstrip("\ufeff")  # strip UTF-8 BOM if present
        return pd.read_csv(
            path,
            sep="\t",
            header=None,
            skiprows=1,
            names=cols,
            engine="python",
            low_memory=False,
        )
    except Exception as e:
        if last_err is None:
            last_err = e

    # Last resort: show raw lines so the GUI does not crash
    try:
        raw_lines = path.read_text(encoding="utf-8", errors="replace").splitlines()[:5000]
        return pd.DataFrame({"raw": raw_lines})
    except Exception:
        if last_err is not None:
            raise last_err
        raise

class CollapsibleSection(QWidget):
    """Simple collapsible section widget (no animation) for dense option panels."""

    def __init__(self, title: str, content: QWidget, collapsed: bool = True):
        super().__init__()
        self._content = content

        self._toggle = QToolButton(text=title)
        self._toggle.setCheckable(True)
        self._toggle.setChecked(not collapsed)
        self._toggle.setToolButtonStyle(Qt.ToolButtonTextBesideIcon)
        self._toggle.setArrowType(Qt.DownArrow if not collapsed else Qt.RightArrow)
        self._toggle.toggled.connect(self._on_toggled)

        line = QFrame()
        line.setFrameShape(QFrame.HLine)
        line.setFrameShadow(QFrame.Sunken)

        head = QHBoxLayout()
        head.setContentsMargins(0, 0, 0, 0)
        head.addWidget(self._toggle)
        head.addStretch(1)

        root = QVBoxLayout()
        root.setContentsMargins(0, 0, 0, 0)
        root.addLayout(head)
        root.addWidget(line)
        root.addWidget(self._content)

        self.setLayout(root)
        self._content.setVisible(not collapsed)

    def _on_toggled(self, checked: bool):
        self._toggle.setArrowType(Qt.DownArrow if checked else Qt.RightArrow)
        self._content.setVisible(checked)



def _parse_highlights_text(text: str) -> list[dict]:
    """Parse highlight specs from user text.

    Supported formats (comma/space separated):
    - chr:pos (vline)
    - chr:start-end (vrect)
    Examples:
      1:12345, 2:10000-20000, chr3:5e6-7e6
    """
    if not text:
        return []
    specs = []
    parts = re.split(r"[\s,;]+", str(text).strip())
    for p in parts:
        if not p:
            continue
        if ":" not in p:
            continue
        c, rng = p.split(":", 1)
        c = c.strip()
        rng = rng.strip()
        if not c or not rng:
            continue
        # allow '..' as range separator
        rng = rng.replace("..", "-")
        # numbers may be scientific notation
        def _to_num(x):
            try:
                return float(x)
            except Exception:
                return None
        if "-" in rng:
            a, b = rng.split("-", 1)
            a = a.strip(); b = b.strip()
            na = _to_num(a); nb = _to_num(b)
            if na is None or nb is None:
                continue
            start = min(na, nb); end = max(na, nb)
            specs.append({"chr": c, "start": start, "end": end})
        else:
            na = _to_num(rng)
            if na is None:
                continue
            specs.append({"chr": c, "start": na, "end": na})
    return specs

def _try_import_plotly():
    """Lazy import Plotly; returns (go, pio, qualitative_palettes) or (None, None, None)."""
    try:
        import plotly.graph_objects as go  # type: ignore
        import plotly.io as pio  # type: ignore
        from plotly.colors import qualitative  # type: ignore
        return go, pio, qualitative
    except Exception:
        return None, None, None

def _infer_pos_decimals(pos, pos_unit: str = "cM") -> int:
    """Infer a reasonable number of decimals for position display.

    - cM: choose 0/1/2/3 based on smallest non-zero step
    - bp: 0
    - Mb: 1-3 depending on scale
    """
    try:
        import numpy as _np
        import pandas as _pd
        arr = _pd.to_numeric(pos, errors="coerce").to_numpy(dtype=float) if hasattr(pos, "to_numpy") else _np.asarray(pos, dtype=float)
        arr = arr[_np.isfinite(arr)]
        if arr.size == 0:
            return 0

        u = str(pos_unit or "").strip().lower()
        if u in {"bp", "base", "bases", "basepair", "basepairs"} or "bp" == u:
            return 0

        # Fractional ratio
        fr = _np.abs(arr - _np.round(arr))
        frac_ratio = float(_np.nanmean(fr > 1e-6)) if fr.size else 0.0

        if u in {"mb", "megabase", "megabases"} or "mb" in u:
            mx = float(_np.nanmax(arr))
            if mx < 50:
                return 3 if frac_ratio > 0.05 else 2
            if mx < 500:
                return 2 if frac_ratio > 0.05 else 1
            return 1 if frac_ratio > 0.05 else 0

        if "cm" in u:
            # estimate smallest positive step
            uu = _np.unique(_np.round(arr, 6))
            if uu.size <= 1:
                return 0 if frac_ratio < 0.05 else 1
            diffs = _np.diff(_np.sort(uu))
            diffs = diffs[diffs > 1e-6]
            if diffs.size == 0:
                return 0 if frac_ratio < 0.05 else 1
            dmin = float(_np.nanmin(diffs))
            if dmin >= 1.0:
                return 0
            if dmin >= 0.1:
                return 1
            if dmin >= 0.01:
                return 2
            return 3

        # default
        return 0 if frac_ratio < 0.05 else 2
    except Exception:
        return 0



def _bh_qvalues(pvals: np.ndarray) -> np.ndarray:
    """Benjamini-Hochberg FDR q-values (vectorized)."""
    p = np.asarray(pvals, dtype=float)
    n = p.size
    q = np.full(n, np.nan, dtype=float)
    ok = np.isfinite(p)
    if ok.sum() == 0:
        return q
    p_ok = p[ok]
    order = np.argsort(p_ok)
    ranked = p_ok[order]
    m = ranked.size
    q_ranked = ranked * m / (np.arange(1, m + 1))
    q_ranked = np.minimum.accumulate(q_ranked[::-1])[::-1]  # enforce monotonicity
    q_ranked = np.clip(q_ranked, 0.0, 1.0)
    q_tmp = np.empty(m, dtype=float)
    q_tmp[order] = q_ranked
    q[ok] = q_tmp
    return q


def _standardize_gwas_df(df: pd.DataFrame) -> pd.DataFrame:
    """Return a copy with columns: marker, chr, pos, pvalue (+ qvalue)."""
    d = df.copy()
    def pick(keys):
        for k in keys:
            if k in d.columns:
                return k
        low = {c.lower(): c for c in d.columns}
        for k in keys:
            if k.lower() in low:
                return low[k.lower()]
        return None

    c_marker = pick(['marker','snp','SNP','Marker','rsid','id'])
    c_chr    = pick(['chr','Chromosome','chrom','CHR'])
    c_pos    = pick(['pos','Position','bp','BP','POS'])
    c_p      = pick(['pvalue','pval','P.value','P','p'])
    c_q      = pick(['qvalue','qval','FDR','q'])

    if c_marker is None: c_marker = d.columns[0]
    if c_chr is None: c_chr = d.columns[1] if len(d.columns) > 1 else d.columns[0]
    if c_pos is None: c_pos = d.columns[2] if len(d.columns) > 2 else d.columns[0]
    if c_p is None:
        num_cols = [c for c in d.columns if pd.api.types.is_numeric_dtype(d[c])]
        c_p = num_cols[-1] if num_cols else d.columns[-1]

    d = d.rename(columns={c_marker:'marker', c_chr:'chr', c_pos:'pos', c_p:'pvalue'})
    if c_q is not None and c_q in d.columns:
        d = d.rename(columns={c_q:'qvalue'})

    d['marker'] = d['marker'].astype(str)
    d['chr'] = d['chr'].astype(str)
    d['pos'] = pd.to_numeric(d['pos'], errors='coerce')
    d['pvalue'] = pd.to_numeric(d['pvalue'], errors='coerce')

    if 'qvalue' not in d.columns:
        d['qvalue'] = _bh_qvalues(d['pvalue'].to_numpy())
    else:
        d['qvalue'] = pd.to_numeric(d['qvalue'], errors='coerce')

    return d


def _default_manhattan_settings() -> dict:
    return dict(
        # colors
        color_scheme="palette",      # palette | alternating | single
        palette_name="Plotly",       # qualitative palette name
        color_a="#1f77b4",           # used for alternating/single
        color_b="#ff7f0e",           # used for alternating
        # points
        point_size=4,
        point_opacity=0.8,
        # labels
        label_mode="topn",           # none | topn | perchr
        label_top_n=10,
        # thresholds
        show_bonf=True,
        bonf_alpha=0.05,
        show_fdr=True,
        fdr_q=0.05,
        custom_pvals=[],             # list[float]
        # highlights
        show_highlights=True,
        highlights_text="",          # comma-separated: chr:pos or chr:start-end
        # layout / texts
        plot_title=None,             # if None, use provided title
        x_label="Genomic position",
        y_label="-log10(p)",
        font_family="Arial",
        font_size=12,
        font_color="#000000",
        margin_l=60,
        margin_r=25,
        margin_t=70,
        margin_b=60,
        plot_bgcolor="white",
        paper_bgcolor="white",
        # view / coordinates
        focus_chr=None,              # e.g. "1" or "Chr1"; None = genome-wide
        coord_mode="0max",           # 0max | minmax  (per-chr length basis)
        pos_min=None,                # optional int (after focus/filter)
        pos_max=None,                # optional int (after focus/filter)
        # UI on figure
        show_updatemenus=True,
        # export defaults
        export_width=1400,
        export_height=800,
        export_clean=True,           # hide figure dropdowns for exports
    )

def build_manhattan_figure(df: pd.DataFrame, title: str = "Manhattan plot", settings: dict | None = None):
    """Build a Plotly Manhattan plot Figure (no file I/O).

    Notes
    -----
    - Genome-wide view uses cumulative coordinates across chromosomes.
    - When coord_mode == 'minmax', each chromosome is shifted by its own min(pos),
      which can improve readability when markers do not start near 0.
    - When focus_chr is provided, only that chromosome is shown, and x-axis is marker position.
    """
    go, pio, qualitative = _try_import_plotly()
    if go is None:
        return None

    s = _default_manhattan_settings()
    if settings:
        s.update({k: v for k, v in settings.items() if v is not None})

    d = _standardize_gwas_df(df)
    d = d.dropna(subset=["pos", "pvalue"])
    if len(d) == 0:
        return None

    # ----- optional focus / range filter -----
    focus_chr = s.get("focus_chr", None)
    if isinstance(focus_chr, str) and focus_chr.strip() and focus_chr.strip().lower() != "all":
        d = d[d["chr"].astype(str) == str(focus_chr).strip()]
        if len(d) == 0:
            return None

    # position range (after focus)
    def _to_int_or_none(x):
        try:
            if x is None:
                return None
            if isinstance(x, str) and x.strip() == "":
                return None
            return int(float(x))
        except Exception:
            return None

    pos_min = _to_int_or_none(s.get("pos_min", None))
    pos_max = _to_int_or_none(s.get("pos_max", None))
    if pos_min is not None:
        d = d[d["pos"] >= pos_min]
    if pos_max is not None:
        d = d[d["pos"] <= pos_max]
    if len(d) == 0:
        return None

    # chromosome order: numeric first, then strings
    def chr_key(c: str):
        m = re.search(r"\d+", str(c))
        return (0, int(m.group(0))) if m else (1, str(c))

    chrs = sorted(d["chr"].astype(str).unique().tolist(), key=chr_key)

    # ----- coordinate construction -----
    coord_mode = str(s.get("coord_mode", "0max")).lower()
    use_minmax = coord_mode == "minmax"

    gap = 1e6
    offsets: dict[str, float] = {}
    chr_min: dict[str, float] = {}
    chr_len: dict[str, float] = {}
    tickvals, ticktext = [], []

    cur = 0.0
    for c in chrs:
        sub = d[d["chr"].astype(str) == c]
        if len(sub) == 0:
            continue
        mn = float(np.nanmin(sub["pos"].to_numpy()))
        mx = float(np.nanmax(sub["pos"].to_numpy()))
        chr_min[c] = mn if use_minmax else 0.0
        ln = (mx - mn) if use_minmax else mx
        ln = float(ln) if np.isfinite(ln) else 0.0
        chr_len[c] = max(ln, 0.0)
        offsets[c] = cur
        tickvals.append(cur + chr_len[c] / 2.0)
        ticktext.append(str(c))
        cur += chr_len[c] + gap

    traces = []
    for c in chrs:
        sub = d[d["chr"].astype(str) == c]
        if len(sub) == 0:
            continue
        # adjusted position for within-chr readability
        adj = sub["pos"].to_numpy(dtype=float) - chr_min.get(c, 0.0)
        if focus_chr is not None and str(focus_chr).strip().lower() != "all":
            xx = sub["pos"].to_numpy(dtype=float)  # real pos when focusing
        else:
            xx = adj + offsets.get(c, 0.0)
        yy = -np.log10(sub["pvalue"].to_numpy(dtype=float))
        cd = np.stack([
            sub["marker"].astype(str).to_numpy(),
            sub["chr"].astype(str).to_numpy(),
            sub["pos"].to_numpy(dtype=float),
            sub["pvalue"].to_numpy(dtype=float),
            sub["qvalue"].to_numpy(dtype=float),
        ], axis=1)
        traces.append((c, xx, yy, cd))

    if not traces:
        return None

    x_max = float(np.nanmax([np.nanmax(t[1]) for t in traces]))

    hover = (
        "marker=%{customdata[0]}<br>chr=%{customdata[1]}<br>pos=%{customdata[2]:.0f}"
        "<br>p=%{customdata[3]:.3g}<br>q=%{customdata[4]:.3g}<extra></extra>"
    )

    # ----- colors -----
    def get_palette(name: str):
        if qualitative is None:
            return None
        if hasattr(qualitative, name):
            return getattr(qualitative, name)
        return getattr(qualitative, "Plotly")

    palette = list(get_palette(str(s.get("palette_name", "Plotly"))))

    trace_colors = []
    if s["color_scheme"] == "alternating":
        a, b = str(s["color_a"]), str(s["color_b"])
        for i in range(len(traces)):
            trace_colors.append(a if i % 2 == 0 else b)
    elif s["color_scheme"] == "single":
        a = str(s["color_a"])
        trace_colors = [a] * len(traces)
    else:
        for i in range(len(traces)):
            trace_colors.append(palette[i % len(palette)])

    fig = go.Figure()
    for i, (c, xx, yy, cd) in enumerate(traces):
        # Use SVG-based Scatter (no WebGL dependency). This improves stability
        # on QtWebEngine/Chromium where WebGL contexts may be lost (Skia OOM).
        fig.add_trace(go.Scatter(
            x=xx, y=yy, mode="markers", name=str(c),
            marker=dict(size=int(s["point_size"]), opacity=float(s["point_opacity"]), color=trace_colors[i]),
            customdata=cd, hovertemplate=hover,
        ))


    # ----- highlights (vlines / vrects) -----
    hl_shapes: list[dict] = []
    hl_ann: list[dict] = []
    if bool(s.get("show_highlights", True)):
        specs = _parse_highlights_text(str(s.get("highlights_text", "")))
        for sp in specs:
            c = str(sp.get("chr", "")).strip()
            if c == "":
                continue
            start = float(sp.get("start", np.nan))
            end = float(sp.get("end", np.nan))
            if not (np.isfinite(start) and np.isfinite(end)):
                continue

            # skip chr mismatch when focusing
            if focus_chr is not None and str(focus_chr).strip().lower() != "all":
                if str(c) != str(focus_chr).strip():
                    continue

            if focus_chr is None or str(focus_chr).strip().lower() == "all":
                if c not in offsets:
                    continue
                x0 = (start - chr_min.get(c, 0.0)) + offsets.get(c, 0.0)
                x1 = (end - chr_min.get(c, 0.0)) + offsets.get(c, 0.0)
            else:
                x0, x1 = start, end

            # styling
            line_color = "rgba(220, 20, 60, 0.85)"  # crimson-ish
            fill_color = "rgba(220, 20, 60, 0.12)"

            if abs(x1 - x0) < 1e-9:
                hl_shapes.append(dict(
                    type="line",
                    x0=float(x0), x1=float(x0),
                    y0=0, y1=1,
                    xref="x", yref="paper",
                    line=dict(color=line_color, width=1, dash="dot"),
                ))
                hl_ann.append(dict(
                    x=float(x0), y=1,
                    xref="x", yref="paper",
                    text=f"{c}:{start:g}",
                    showarrow=False,
                    yanchor="bottom",
                    font=dict(size=int(s["font_size"])),
                ))
            else:
                a, b = (min(float(x0), float(x1)), max(float(x0), float(x1)))
                hl_shapes.append(dict(
                    type="rect",
                    x0=a, x1=b,
                    y0=0, y1=1,
                    xref="x", yref="paper",
                    fillcolor=fill_color,
                    line=dict(width=0),
                ))
                hl_ann.append(dict(
                    x=(a + b) / 2.0, y=1,
                    xref="x", yref="paper",
                    text=f"{c}:{min(start,end):g}-{max(start,end):g}",
                    showarrow=False,
                    yanchor="bottom",
                    font=dict(size=int(s["font_size"])),
                ))

    # ----- thresholds (shapes + annotations) -----
    def _line(y):
        return dict(type="line", x0=0, x1=x_max, y0=y, y1=y, xref="x", yref="y")

    def _line_annot(y, label):
        return dict(
            x=x_max, y=y,
            xref="x", yref="y",
            text=label,
            showarrow=False,
            xanchor="right",
            yanchor="bottom",
            font=dict(size=int(s["font_size"])),
        )

    shapes_none: list[dict] = list(hl_shapes)
    ann_none: list[dict] = list(hl_ann)

    shapes_custom: list[dict] = []
    ann_custom: list[dict] = []

    # custom p-value lines
    custom = s.get("custom_pvals", []) or []
    for p0 in custom:
        try:
            p0 = float(p0)
        except Exception:
            continue
        if p0 > 0:
            y0 = -np.log10(p0)
            if np.isfinite(y0):
                shapes_custom.append(_line(y0))
                ann_custom.append(_line_annot(y0, f"p={p0:g}"))

    # Bonferroni line
    shapes_bonf: list[dict] = []
    ann_bonf: list[dict] = []
    if bool(s.get("show_bonf", True)):
        ntests = int(d["pvalue"].notna().sum())
        bonf = float(s.get("bonf_alpha", 0.05)) / max(ntests, 1)
        y_bonf = -np.log10(bonf) if bonf > 0 else None
        if y_bonf is not None and np.isfinite(y_bonf):
            shapes_bonf.append(_line(y_bonf))
            ann_bonf.append(_line_annot(y_bonf, f"Bonferroni (α={float(s.get('bonf_alpha',0.05))})"))

    # FDR line (q threshold on computed qvalues)
    shapes_fdr: list[dict] = []
    ann_fdr: list[dict] = []
    if bool(s.get("show_fdr", True)):
        q_thr = float(s.get("fdr_q", 0.05))
        qv = d["qvalue"].to_numpy(dtype=float)
        pv = d["pvalue"].to_numpy(dtype=float)
        p_fdr = np.nan
        if np.isfinite(qv).any():
            mask = (qv <= q_thr) & np.isfinite(pv)
            if mask.any():
                p_fdr = np.nanmax(pv[mask])
        if np.isfinite(p_fdr) and p_fdr > 0:
            y_fdr = -np.log10(p_fdr)
            shapes_fdr.append(_line(y_fdr))
            ann_fdr.append(_line_annot(y_fdr, f"FDR (q≤{q_thr})"))

    # default threshold set (includes custom lines)
    shapes_default = hl_shapes + shapes_custom + shapes_bonf + shapes_fdr
    ann_default = hl_ann + ann_custom + ann_bonf + ann_fdr

    # ----- peak labels (annotations) -----
    def _pick_peaks(mode: str, top_n: int):
        if top_n <= 0:
            return d.iloc[0:0]
        if mode == "perchr":
            peaks = []
            for c in chrs:
                sub = d[d["chr"].astype(str) == c].sort_values("pvalue")
                if len(sub) > 0:
                    peaks.append(sub.iloc[0])
            if not peaks:
                return d.iloc[0:0]
            dd = pd.DataFrame(peaks).sort_values("pvalue")
            return dd.head(top_n)
        return d.sort_values("pvalue").head(top_n)

    def _peak_annotations(mode: str):
        if mode == "none":
            return []
        top_n = int(s.get("label_top_n", 10))
        sel = _pick_peaks(mode, top_n)
        if len(sel) == 0:
            return []
        ann = []
        for _, row in sel.iterrows():
            c = str(row["chr"])
            if focus_chr is not None and str(focus_chr).strip().lower() != "all":
                x0 = float(row["pos"])
            else:
                x0 = (float(row["pos"]) - chr_min.get(c, 0.0)) + offsets.get(c, 0.0)
            y0 = -np.log10(float(row["pvalue"])) if float(row["pvalue"]) > 0 else 0.0
            ann.append(dict(
                x=x0, y=y0,
                xref="x", yref="y",
                text=str(row["marker"]),
                showarrow=True,
                arrowhead=2,
                arrowsize=1,
                arrowwidth=1,
                ax=0,
                ay=-30,
                font=dict(size=int(s["font_size"])),
            ))
        return ann

    anns_peaks_topn = _peak_annotations("topn")
    anns_peaks_perchr = _peak_annotations("perchr")

    label_mode = str(s.get("label_mode", "topn"))
    if label_mode == "perchr":
        peak_anns = anns_peaks_perchr
    elif label_mode == "none":
        peak_anns = []
    else:
        peak_anns = anns_peaks_topn

    # ----- in-plot dropdowns (optional) -----
    updatemenus = []
    if bool(s.get("show_updatemenus", True)) and (focus_chr is None or str(focus_chr).strip().lower() == "all"):
        # Threshold menu
        thr_buttons = [
            dict(label="Threshold: none", method="relayout", args=[{"shapes": hl_shapes + shapes_custom, "annotations": peak_anns + hl_ann + ann_custom}]),
            dict(label="Threshold: Bonferroni", method="relayout", args=[{"shapes": hl_shapes + shapes_custom + shapes_bonf, "annotations": peak_anns + hl_ann + ann_custom + ann_bonf}]),
            dict(label="Threshold: FDR", method="relayout", args=[{"shapes": hl_shapes + shapes_custom + shapes_fdr, "annotations": peak_anns + hl_ann + ann_custom + ann_fdr}]),
            dict(label="Threshold: both", method="relayout", args=[{"shapes": hl_shapes + shapes_custom + shapes_bonf + shapes_fdr, "annotations": peak_anns + hl_ann + ann_custom + ann_bonf + ann_fdr}]),
        ]
        # Label menu
        lbl_buttons = [
            dict(label="Labels: none", method="relayout", args=[{"annotations": ann_default}]),
            dict(label=f"Labels: top {int(s.get('label_top_n',10))}", method="relayout", args=[{"annotations": anns_peaks_topn + ann_default}]),
            dict(label="Labels: per chr", method="relayout", args=[{"annotations": anns_peaks_perchr + ann_default}]),
        ]
        # Color menu
        a, b = str(s["color_a"]), str(s["color_b"])
        colors_alt = [a if i % 2 == 0 else b for i in range(len(traces))]
        colors_single = [a] * len(traces)
        colors_palette = [palette[i % len(palette)] for i in range(len(traces))]
        col_buttons = [
            dict(label="Colors: palette", method="restyle", args=[{"marker.color": colors_palette}]),
            dict(label="Colors: alternating", method="restyle", args=[{"marker.color": colors_alt}]),
            dict(label="Colors: single", method="restyle", args=[{"marker.color": colors_single}]),
        ]
        updatemenus = [
            dict(type="dropdown", x=0.01, y=1.03, yanchor="bottom", buttons=thr_buttons, showactive=True),
            dict(type="dropdown", x=0.34, y=1.03, yanchor="bottom", buttons=lbl_buttons, showactive=True),
            dict(type="dropdown", x=0.63, y=1.03, yanchor="bottom", buttons=col_buttons, showactive=True),
        ]

    # ----- layout -----
    plot_title = s.get("plot_title", None) or title
    xlab = str(s.get("x_label", "Genomic position"))
    ylab = str(s.get("y_label", "-log10(p)"))

    xaxis_kwargs = dict(title=xlab)
    if focus_chr is None or str(focus_chr).strip().lower() == "all":
        xaxis_kwargs.update(dict(tickmode="array", tickvals=tickvals, ticktext=ticktext))

    fig.update_layout(
        title=str(plot_title),
        xaxis=xaxis_kwargs,
        yaxis=dict(title=ylab),
        font=dict(family=str(s["font_family"]), size=int(s["font_size"]), color=str(s.get("font_color", "#000000"))),
        margin=dict(l=int(s["margin_l"]), r=int(s["margin_r"]), t=int(s["margin_t"]), b=int(s["margin_b"])),
        hovermode="closest",
        shapes=shapes_default,
        annotations=(peak_anns + ann_default),
        updatemenus=updatemenus,
        plot_bgcolor=str(s.get("plot_bgcolor", "white")),
        paper_bgcolor=str(s.get("paper_bgcolor", "white")),
    )

    return fig



_PLOTLY_DIV_ID = "gwas_manhattan"

def build_manhattan_compare_figure(
    items: list[tuple[str, pd.DataFrame]],
    *,
    title: str = "Manhattan compare",
    mode: str = "overlay",   # overlay | stacked
    top_n: int = 30000,
):
    """Build a multi-GWAS Manhattan comparison figure.

    - Coordinates are made comparable by using a shared cumulative genome axis
      derived from the union of chromosomes across all inputs.
    - For speed/stability, each dataset is downsampled to the smallest P top_n rows.
    """
    go, _pio, _qual = _try_import_plotly()
    if go is None:
        return None

    # Standardize and reduce
    std_items: list[tuple[str, pd.DataFrame]] = []
    for label, df in items:
        try:
            d = _standardize_gwas_df(df)
            d = d.dropna(subset=["pos", "pvalue"])
            if len(d) == 0:
                continue
            if top_n and len(d) > int(top_n):
                d = d.nsmallest(int(top_n), "pvalue")
            std_items.append((label, d))
        except Exception:
            continue
    if not std_items:
        return None

    # chromosome order: numeric first, then strings
    def chr_key(c: str):
        m = re.search(r"\d+", str(c))
        return (0, int(m.group(0))) if m else (1, str(c))

    all_chrs = sorted(
        {str(c) for _lab, d in std_items for c in d["chr"].astype(str).unique().tolist()},
        key=chr_key,
    )

    # shared chr length based on max(pos) across all datasets
    gap = 1e6
    offsets: dict[str, float] = {}
    chr_len: dict[str, float] = {}
    tickvals, ticktext = [], []

    cur = 0.0
    for c in all_chrs:
        mx = 0.0
        for _lab, d in std_items:
            sub = d[d["chr"].astype(str) == c]
            if len(sub) == 0:
                continue
            v = float(np.nanmax(sub["pos"].to_numpy(dtype=float)))
            if np.isfinite(v):
                mx = max(mx, v)
        chr_len[c] = max(mx, 0.0)
        offsets[c] = cur
        tickvals.append(cur + chr_len[c] / 2.0)
        ticktext.append(str(c))
        cur += chr_len[c] + gap

    def _build_trace(label: str, d: pd.DataFrame):
        xs = []
        ys = []
        cd = []
        for c in all_chrs:
            sub = d[d["chr"].astype(str) == c]
            if len(sub) == 0:
                continue
            x = sub["pos"].to_numpy(dtype=float) + offsets.get(str(c), 0.0)
            y = -np.log10(sub["pvalue"].to_numpy(dtype=float))
            xs.append(x)
            ys.append(y)
            cd.append(np.stack([
                np.full(len(sub), label, dtype=object),
                sub["marker"].astype(str).to_numpy(),
                sub["chr"].astype(str).to_numpy(),
                sub["pos"].to_numpy(dtype=float),
                sub["pvalue"].to_numpy(dtype=float),
            ], axis=1))
        if not xs:
            return None
        xall = np.concatenate(xs)
        yall = np.concatenate(ys)
        cdall = np.concatenate(cd, axis=0)
        return go.Scatter(
            x=xall,
            y=yall,
            mode="markers",
            name=label,
            marker=dict(size=3, opacity=0.75),
            customdata=cdall,
            hovertemplate=(
                "dataset=%{customdata[0]}<br>"
                "marker=%{customdata[1]}<br>"
                "chr=%{customdata[2]}<br>"
                "pos=%{customdata[3]:,.0f}<br>"
                "p=%{customdata[4]:.3e}"
                "<extra></extra>"
            ),
        )

    mode_l = str(mode).lower().strip()
    if mode_l == "stacked":
        try:
            from plotly.subplots import make_subplots  # type: ignore
        except Exception:
            mode_l = "overlay"

    if mode_l == "stacked":
        from plotly.subplots import make_subplots  # type: ignore
        fig = make_subplots(
            rows=len(std_items),
            cols=1,
            shared_xaxes=True,
            vertical_spacing=0.02,
            subplot_titles=[lab for lab, _d in std_items],
        )
        for i, (lab, d) in enumerate(std_items, start=1):
            tr = _build_trace(lab, d)
            if tr is not None:
                tr.showlegend = False
                fig.add_trace(tr, row=i, col=1)
            fig.update_yaxes(row=i, col=1, title_text="-log10(p)")
        fig.update_xaxes(
            row=len(std_items),
            col=1,
            tickmode="array",
            tickvals=tickvals,
            ticktext=ticktext,
            title_text="Genomic position (cumulative)",
        )
        fig.update_layout(
            title=title,
            height=max(650, 260 * len(std_items)),
            margin=dict(l=60, r=25, t=80, b=60),
            hovermode="closest",
        )
        return fig

    # overlay
    fig = go.Figure()
    for lab, d in std_items:
        tr = _build_trace(lab, d)
        if tr is not None:
            fig.add_trace(tr)

    fig.update_layout(
        title=title,
        hovermode="closest",
        margin=dict(l=60, r=25, t=80, b=60),
        height=720,
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="left", x=0.0),
    )
    fig.update_xaxes(tickmode="array", tickvals=tickvals, ticktext=ticktext, title_text="Genomic position (cumulative)")
    fig.update_yaxes(title_text="-log10(p)")
    return fig



def _standardize_gwas_records(columns: list[str], rows: list[list[str]]) -> list[dict]:
    """Standardize a GWAS results table into a list of records.

    Output record keys: marker, chr, pos, pvalue, qvalue (qvalue may be None).
    This function does NOT rely on pandas.
    """
    if not columns:
        return []

    cols_l = [str(c).strip() for c in columns]
    cols_map = {c.lower(): i for i, c in enumerate(cols_l)}

    def pick(cands: list[str]) -> int | None:
        for cand in cands:
            cand_l = cand.lower()
            if cand_l in cols_map:
                return cols_map[cand_l]
        # fuzzy
        for name_l, i in cols_map.items():
            for cand in cands:
                cand_l = cand.lower()
                if name_l.endswith(cand_l) or cand_l in name_l:
                    return i
        return None

    i_chr = pick(["chr", "chrom", "chromosome", "seqid"])
    i_pos = pick(["pos", "bp", "position", "physical_pos"])
    i_p   = pick(["p", "pvalue", "p_value", "p.val", "pval"])
    i_q   = pick(["q", "qvalue", "q_value", "fdr", "padj", "adj_p"])
    i_m   = pick(["marker", "snp", "id", "rsid", "locus", "variant", "markerid"])

    recs: list[dict] = []
    for r in rows:
        try:
            if i_chr is None or i_pos is None or i_p is None:
                continue
            chr_v = str(r[i_chr]).strip()
            pos_v = float(str(r[i_pos]).replace(",", ""))
            p_v = float(str(r[i_p]))
            if not (p_v > 0.0):
                continue
            q_v = None
            if i_q is not None and i_q < len(r):
                try:
                    q_v = float(str(r[i_q]))
                except Exception:
                    q_v = None
            m_v = None
            if i_m is not None and i_m < len(r):
                m_v = str(r[i_m]).strip()
            recs.append({
                "marker": m_v,
                "chr": chr_v,
                "pos": pos_v,
                "pvalue": p_v,
                "qvalue": q_v,
            })
        except Exception:
            continue
    return recs


def build_manhattan_compare_figure_records(
    items: list[tuple[str, list[dict]]],
    *,
    title: str = "Manhattan compare",
    mode: str = "overlay",   # overlay | stacked
    top_n: int = 30000,
):
    """Build multi-GWAS Manhattan comparison figure from record lists (no pandas)."""
    go, _pio, _qual = _try_import_plotly()
    if go is None:
        return None

    # Downsample each dataset to top_n smallest p-values
    std_items: list[tuple[str, list[dict]]] = []
    for lab, recs in items:
        rr = [x for x in recs if x.get("chr") is not None and x.get("pos") is not None and x.get("pvalue") is not None]
        if not rr:
            continue
        if top_n and len(rr) > int(top_n):
            rr = heapq.nsmallest(int(top_n), rr, key=lambda d: float(d.get("pvalue", 1.0)))
        std_items.append((lab, rr))
    if not std_items:
        return None

    def chr_key(c: str):
        m = re.search(r"\d+", str(c))
        return (0, int(m.group(0))) if m else (1, str(c))

    all_chrs = sorted({str(r["chr"]) for _lab, rr in std_items for r in rr}, key=chr_key)

    # shared chr length based on max(pos)
    gap = 1e6
    offsets: dict[str, float] = {}
    chr_len: dict[str, float] = {}
    tickvals, ticktext = [], []

    cur = 0.0
    for c in all_chrs:
        mx = 0.0
        for _lab, rr in std_items:
            for r in rr:
                if str(r["chr"]) != c:
                    continue
                try:
                    mx = max(mx, float(r["pos"]))
                except Exception:
                    pass
        chr_len[c] = max(mx, 0.0)
        offsets[c] = cur
        tickvals.append(cur + chr_len[c] / 2.0)
        ticktext.append(str(c))
        cur += chr_len[c] + gap

    def _trace(label: str, rr: list[dict]):
        xs, ys, cd = [], [], []
        for r in rr:
            c = str(r["chr"])
            try:
                x = float(r["pos"]) + float(offsets.get(c, 0.0))
                p = float(r["pvalue"])
                y = -math.log10(p) if p > 0 else 0.0
            except Exception:
                continue
            xs.append(x); ys.append(y)
            cd.append([label, str(r.get("marker") or ""), c, float(r["pos"]), float(r["pvalue"])])
        if not xs:
            return None
        return go.Scatter(
            x=xs,
            y=ys,
            mode="markers",
            name=label,
            marker=dict(size=3, opacity=0.75),
            customdata=cd,
            hovertemplate=(
                "dataset=%{customdata[0]}<br>"
                "marker=%{customdata[1]}<br>"
                "chr=%{customdata[2]}<br>"
                "pos=%{customdata[3]:,.0f}<br>"
                "p=%{customdata[4]:.3e}"
                "<extra></extra>"
            ),
        )

    mode_l = str(mode).lower().strip()
    if mode_l == "stacked":
        try:
            from plotly.subplots import make_subplots  # type: ignore
        except Exception:
            mode_l = "overlay"

    if mode_l == "stacked":
        from plotly.subplots import make_subplots  # type: ignore
        fig = make_subplots(
            rows=len(std_items),
            cols=1,
            shared_xaxes=True,
            vertical_spacing=0.02,
            subplot_titles=[lab for lab, _rr in std_items],
        )
        for i, (lab, rr) in enumerate(std_items, start=1):
            tr = _trace(lab, rr)
            if tr is not None:
                tr.showlegend = False
                fig.add_trace(tr, row=i, col=1)
            fig.update_yaxes(row=i, col=1, title_text="-log10(p)")
        fig.update_xaxes(
            row=len(std_items),
            col=1,
            tickmode="array",
            tickvals=tickvals,
            ticktext=ticktext,
            title_text="Genomic position (cumulative)",
        )
        fig.update_layout(
            title=title,
            height=max(650, 260 * len(std_items)),
            margin=dict(l=60, r=25, t=80, b=60),
            hovermode="closest",
        )
        return fig

    fig = go.Figure()
    for lab, rr in std_items:
        tr = _trace(lab, rr)
        if tr is not None:
            fig.add_trace(tr)

    fig.update_layout(
        title=title,
        hovermode="closest",
        margin=dict(l=60, r=25, t=80, b=60),
        height=720,
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="left", x=0.0),
    )
    fig.update_xaxes(tickmode="array", tickvals=tickvals, ticktext=ticktext, title_text="Genomic position (cumulative)")
    fig.update_yaxes(title_text="-log10(p)")
    return fig




def _plotly_html(fig, pio, *, div_id: str = _PLOTLY_DIV_ID, include_plotlyjs: str = "inline", add_selection_js: bool = True) -> str:
    """Render Plotly figure to HTML, embedding plotly.js and (optionally) selection hooks."""
    config = {
        "displaylogo": False,
        "responsive": True,
    }
    html = pio.to_html(
        fig,
        full_html=True,
        include_plotlyjs=include_plotlyjs,
        div_id=div_id,
        config=config,
    )

    if not add_selection_js:
        return html

    # Capture Plotly selections so Qt can read them via runJavaScript().
    # Stores: window.__gwas_selection = {chr, pos_min, pos_max, n}
    js = f"""\n<script>
(function() {{
  try {{
    var gd = document.getElementById("{_PLOTLY_DIV_ID}");
    if (!gd || !gd.on) return;
    window.__gwas_selection = null;
    gd.on('plotly_selected', function(e) {{
      try {{
        if (!e || !e.points || e.points.length === 0) {{
          window.__gwas_selection = null;
          return;
        }}
        var chrs = [];
        var poss = [];
        e.points.forEach(function(p) {{
          if (p.customdata && p.customdata.length >= 3) {{
            chrs.push(String(p.customdata[1]));
            poss.push(Number(p.customdata[2]));
          }}
        }});
        if (poss.length === 0) {{
          window.__gwas_selection = null;
          return;
        }}
        var chrSet = Array.from(new Set(chrs));
        var chr = (chrSet.length === 1) ? chrSet[0] : "All";
        var minPos = Math.min.apply(null, poss);
        var maxPos = Math.max.apply(null, poss);
        window.__gwas_selection = {{chr: chr, pos_min: minPos, pos_max: maxPos, n: poss.length}};
      }} catch(err) {{
        window.__gwas_selection = null;
      }}
    }});
    gd.on('plotly_deselect', function() {{
      window.__gwas_selection = null;
    }});
  }} catch(errOuter) {{}}
}})();
</script>\n"""

    if "</body>" in html:
        html = html.replace("</body>", js + "</body>")
    else:
        html = html + js
    return html

def make_manhattan_plotly(df: pd.DataFrame, out_html: Path, title: str = "Manhattan plot", settings: dict | None = None) -> bool:
    """Create an interactive Manhattan plot (Plotly) and write to out_html."""
    go, pio, qualitative = _try_import_plotly()
    if go is None:
        return False

    fig = build_manhattan_figure(df, title=title, settings=settings)
    if fig is None:
        return False

    out_html.parent.mkdir(parents=True, exist_ok=True)
    html = _plotly_html(fig, pio, add_selection_js=True)
    out_html.write_text(html, encoding='utf-8')
    return True


def _default_qq_settings() -> dict:
    return dict(
        plot_title=None,
        x_label="Expected -log10(p)",
        y_label="Observed -log10(p)",
        point_size=4,
        point_opacity=0.8,
        color_a="#1f77b4",
        show_ci=True,
        ci_level=0.95,
        ci_points=2000,
        show_lambda=True,
        lambda_df=1,
        font_family="Arial",
        font_size=12,
        font_color="#000000",
        margin_l=60,
        margin_r=25,
        margin_t=70,
        margin_b=60,
        plot_bgcolor="#ffffff",
        paper_bgcolor="#ffffff",
        max_points=200000,
        tail_keep=5000,
        height=720,
    )


def build_qq_figure(df: pd.DataFrame, title: str = "QQ plot", settings: dict | None = None):
    """Build a GWAS QQ plot (Plotly).

    Notes
    -----
    - Uses p-values (column variants are standardized via _standardize_gwas_df).
    - For large datasets, down-samples for interactive responsiveness while keeping the tail.
    - Optionally adds a confidence envelope and genomic inflation factor (λGC).
    """
    go, pio, qualitative = _try_import_plotly()
    if go is None:
        return None

    s = _default_qq_settings()
    if settings:
        s.update(settings)

    d = _standardize_gwas_df(df)
    # filter valid p-values
    try:
        pvals = pd.to_numeric(d["pvalue"], errors="coerce")
    except Exception:
        pvals = d["pvalue"]
    d = d.copy()
    d["pvalue"] = pvals
    d = d.dropna(subset=["pvalue"])
    d = d[(d["pvalue"] > 0.0) & (d["pvalue"] <= 1.0)]
    if d.empty:
        return None

    # sort by p ascending (smallest first), then reverse for ascending -log10 axis
    d = d.sort_values("pvalue", ascending=True)
    n = int(len(d))

    obs_desc = (-np.log10(d["pvalue"].astype(float).values))  # high -> low
    exp_desc = (-np.log10((np.arange(1, n + 1, dtype=float)) / float(n + 1)))

    obs = obs_desc[::-1]
    exp = exp_desc[::-1]
    d_plot = d.iloc[::-1].reset_index(drop=True)

    # subsample points for interactivity
    max_points = int(s.get("max_points", 200000) or 200000)
    tail_keep = int(s.get("tail_keep", 5000) or 0)
    if max_points < 1000:
        max_points = 1000
    if tail_keep < 0:
        tail_keep = 0
    if tail_keep > max_points:
        tail_keep = max_points

    if n > max_points:
        n_uniform = max_points - tail_keep
        if n_uniform < 1:
            n_uniform = 1
        idx_uniform = np.unique(np.linspace(0, n - 1, n_uniform, dtype=int))
        idx_tail = np.arange(max(0, n - tail_keep), n, dtype=int) if tail_keep else np.array([], dtype=int)
        idx = np.unique(np.concatenate([idx_uniform, idx_tail]))
        exp_pts = exp[idx]
        obs_pts = obs[idx]
        d_pts = d_plot.iloc[idx].reset_index(drop=True)
    else:
        exp_pts = exp
        obs_pts = obs
        d_pts = d_plot

    # compute CI envelope (on a grid)
    env_x = env_lo = env_hi = None
    if bool(s.get("show_ci", True)):
        try:
            from scipy.stats import beta as _beta
            ci_level = float(s.get("ci_level", 0.95) or 0.95)
            ci_level = min(max(ci_level, 0.5), 0.999999)
            alpha = 1.0 - ci_level
            ci_points = int(s.get("ci_points", 2000) or 2000)
            ci_points = max(100, min(ci_points, n))

            idx_ci = np.unique(np.linspace(0, n - 1, ci_points, dtype=int))
            # map ascending-x index j -> rank i (in sorted-ascending-p order)
            i_rank = (n - idx_ci).astype(int)
            a = i_rank
            b = (n - i_rank + 1).astype(int)
            p_low = _beta.ppf(alpha / 2.0, a, b)
            p_high = _beta.ppf(1.0 - alpha / 2.0, a, b)
            # convert to -log10 scale; lower p -> higher -log10
            y_lo = -np.log10(np.clip(p_high, 1e-300, 1.0))
            y_hi = -np.log10(np.clip(p_low, 1e-300, 1.0))
            env_x = exp[idx_ci]
            env_lo = y_lo
            env_hi = y_hi
        except Exception:
            env_x = env_lo = env_hi = None

    # lambda GC
    lam = None
    if bool(s.get("show_lambda", True)):
        try:
            from scipy.stats import chi2 as _chi2
            pv = d["pvalue"].astype(float).values
            pv = pv[np.isfinite(pv) & (pv > 0.0) & (pv <= 1.0)]
            if pv.size > 0:
                df1 = int(s.get("lambda_df", 1) or 1)
                chi = _chi2.isf(pv, df=df1)
                med = float(np.nanmedian(chi))
                denom = float(_chi2.ppf(0.5, df=df1))
                if denom > 0:
                    lam = med / denom
        except Exception:
            lam = None

    # build figure
    fig = go.Figure()

    if env_x is not None and env_lo is not None and env_hi is not None:
        fig.add_trace(go.Scatter(
            x=env_x,
            y=env_lo,
            mode="lines",
            line=dict(width=0),
            name=f"{int(round(float(s.get('ci_level', 0.95))*100))}% CI",
            showlegend=False,
            hoverinfo="skip",
        ))
        fig.add_trace(go.Scatter(
            x=env_x,
            y=env_hi,
            mode="lines",
            line=dict(width=0),
            fill="tonexty",
            fillcolor="rgba(0,0,0,0.10)",
            showlegend=False,
            hoverinfo="skip",
        ))

    # diagonal
    mx = float(np.nanmax([np.nanmax(exp_pts), np.nanmax(obs_pts)])) if len(exp_pts) else 1.0
    mx = max(mx, 1.0)
    fig.add_trace(go.Scatter(
        x=[0.0, mx],
        y=[0.0, mx],
        mode="lines",
        line=dict(dash="dash"),
        name="y=x",
        hoverinfo="skip",
        showlegend=False,
    ))

    # points
    # customdata: marker, chr, pos, p, q
    try:
        cd = np.stack([
            d_pts.get("marker", pd.Series([None] * len(d_pts))).astype(str).fillna("").values,
            d_pts.get("chr", pd.Series([None] * len(d_pts))).astype(str).fillna("").values,
            pd.to_numeric(d_pts.get("pos", pd.Series([np.nan] * len(d_pts))), errors="coerce").values,
            pd.to_numeric(d_pts.get("pvalue", pd.Series([np.nan] * len(d_pts))), errors="coerce").values,
            pd.to_numeric(d_pts.get("qvalue", pd.Series([np.nan] * len(d_pts))), errors="coerce").values,
        ], axis=1)
    except Exception:
        cd = None

    fig.add_trace(go.Scatter(
        x=exp_pts,
        y=obs_pts,
        mode="markers",
        name="SNPs",
        marker=dict(
            size=int(s.get("point_size", 4)),
            opacity=float(s.get("point_opacity", 0.8)),
            color=str(s.get("color_a", "#1f77b4")),
        ),
        customdata=cd,
        hovertemplate=(
            "marker=%{customdata[0]}<br>chr=%{customdata[1]} pos=%{customdata[2]:.0f}<br>"
            "p=%{customdata[3]:.3g}<br>q=%{customdata[4]:.3g}<extra></extra>"
            if cd is not None else None
        ),
    ))

    tt = (s.get("plot_title") or title) if title else (s.get("plot_title") or "QQ plot")
    x_label = s.get("x_label") or "Expected -log10(p)"
    y_label = s.get("y_label") or "Observed -log10(p)"

    ann = []
    if lam is not None and np.isfinite(lam):
        ann.append(dict(
            x=0.02,
            y=0.98,
            xref="paper",
            yref="paper",
            text=f"λGC={lam:.3f}",
            showarrow=False,
            xanchor="left",
            yanchor="top",
            font=dict(color=str(s.get("font_color", "#000000")), size=max(10, int(s.get("font_size", 12))))
        ))

    fig.update_layout(
        title=dict(text=tt, x=0.02, xanchor="left"),
        height=int(s.get("height", 720)),
        margin=dict(l=int(s.get("margin_l", 60)), r=int(s.get("margin_r", 25)), t=int(s.get("margin_t", 70)), b=int(s.get("margin_b", 60))),
        font=dict(
            family=str(s.get("font_family", "Arial")),
            size=int(s.get("font_size", 12)),
            color=str(s.get("font_color", "#000000")),
        ),
        plot_bgcolor=str(s.get("plot_bgcolor", "#ffffff")),
        paper_bgcolor=str(s.get("paper_bgcolor", "#ffffff")),
        annotations=ann,
        showlegend=False,
    )

    fig.update_xaxes(title_text=x_label, range=[0.0, mx * 1.02], zeroline=False)
    fig.update_yaxes(title_text=y_label, range=[0.0, mx * 1.02], zeroline=False, scaleanchor="x", scaleratio=1)

    return fig


def make_qq_plotly(df: pd.DataFrame, out_html: Path, title: str = "QQ plot", settings: dict | None = None) -> bool:
    go, pio, qualitative = _try_import_plotly()
    if go is None:
        return False
    fig = build_qq_figure(df, title=title, settings=settings)
    if fig is None:
        return False
    out_html.parent.mkdir(parents=True, exist_ok=True)
    html = _plotly_html(fig, pio, add_selection_js=False)
    out_html.write_text(html, encoding="utf-8")
    return True



# ----------------------------
# Preprocess / Imputation QC plots (Plotly)
# ----------------------------

def make_genotype_imputation_qc_plotly(marker_summary_tsv: Path, sample_summary_tsv: Path | None, out_html: Path,
                                       title: str = "Genotype imputation QC") -> bool:
    """Create a compact QC dashboard for genotype imputation.

    Design intent (simple but informative):
      - Missingness *before* imputation (marker & sample)
      - MAF change (before vs after) and ΔMAF distribution

    Expects marker_summary.tsv / sample_summary.tsv produced by plugins/impute_genotypes.
    """
    go, pio, qualitative = _try_import_plotly()
    if go is None:
        return False
    try:
        from plotly.subplots import make_subplots  # type: ignore
    except Exception:
        return False

    try:
        mdf = pd.read_csv(marker_summary_tsv, sep="	")
    except Exception:
        return False

    sdf = None
    if sample_summary_tsv and sample_summary_tsv.exists():
        try:
            sdf = pd.read_csv(sample_summary_tsv, sep="	")
        except Exception:
            sdf = None

    def _num(s):
        return pd.to_numeric(s, errors="coerce") if s is not None else None

    # marker-level
    m_before = _num(mdf.get("missing_before"))
    marker_name = mdf.get("marker")

    maf_before = _num(mdf.get("maf_before"))
    maf_after = _num(mdf.get("maf_after"))
    if maf_after is None:
        # backward compatibility
        maf_after = _num(mdf.get("maf"))

    # sample-level
    s_before = _num(sdf.get("missing_before")) if sdf is not None else None

    # Optional: quick accuracy check summary (if available)
    acc_text = None
    try:
        acc_path = marker_summary_tsv.parent / "accuracy_summary.tsv"
        if acc_path.exists():
            adf = pd.read_csv(acc_path, sep="\t")
            if len(adf) > 0:
                row = adf.iloc[0].to_dict()
                if "status" in row and str(row.get("status")) not in ("ok", "OK"):
                    acc_text = f"QuickAcc: {row.get('status')} ({row.get('reason', '')})"
                elif "acc_overall" in row:
                    try:
                        acc = float(row.get("acc_overall"))
                        n_mask = int(float(row.get("n_mask", 0)))
                        mr = float(row.get("mask_rate", 0.0))
                        rmse = float(row.get("rmse", float('nan')))
                        acc_text = f"QuickAcc (mask): acc={acc:.3f}  rmse={rmse:.3f}  n={n_mask}  rate={mr:.3f}"
                    except Exception:
                        pass
    except Exception:
        pass

    fig = make_subplots(
        rows=2, cols=2,
        subplot_titles=[
            "Marker missingness (before)",
            "Sample missingness (before)",
            "MAF (before vs after)",
            "ΔMAF (after - before)",
        ],
        specs=[[{"type": "histogram"}, {"type": "histogram"}],
               [{"type": "scatter"}, {"type": "histogram"}]],
        horizontal_spacing=0.12, vertical_spacing=0.15,
    )

    # (1) Marker missingness BEFORE
    try:
        if m_before is not None and m_before.notna().any():
            fig.add_trace(go.Histogram(x=m_before, name="marker before", nbinsx=50, showlegend=False), row=1, col=1)
            fig.update_xaxes(title_text="missing rate", row=1, col=1)
            fig.update_yaxes(title_text="# markers", row=1, col=1)
    except Exception:
        pass

    # (2) Sample missingness BEFORE
    try:
        if s_before is not None and s_before.notna().any():
            fig.add_trace(go.Histogram(x=s_before, name="sample before", nbinsx=50, showlegend=False), row=1, col=2)
            fig.update_xaxes(title_text="missing rate", row=1, col=2)
            fig.update_yaxes(title_text="# samples", row=1, col=2)
    except Exception:
        pass

    # (3) MAF before vs after
    maf_scatter_ok = False
    try:
        if (maf_before is not None and maf_after is not None and maf_before.notna().any() and maf_after.notna().any()):
            x = maf_before
            y = maf_after
            mx = float(np.nanmax([np.nanmax(x.values), np.nanmax(y.values), 0.0]))
            fig.add_trace(go.Scatter(x=[0, mx], y=[0, mx], mode="lines", name="y=x", line=dict(dash="dash"), showlegend=False), row=2, col=1)

            mk = dict(size=4, opacity=0.75)
            # color by missingness before (useful to see where MAF shifts are driven by sparse markers)
            if m_before is not None and m_before.notna().any():
                mk["color"] = m_before
                mk["colorscale"] = "Viridis"
                mk["showscale"] = True
                mk["colorbar"] = dict(title="missing_before")

            hover = None
            if marker_name is not None:
                try:
                    hover = [str(v) for v in marker_name]
                except Exception:
                    hover = None

            fig.add_trace(
                go.Scatter(
                    x=x,
                    y=y,
                    mode="markers",
                    marker=mk,
                    text=hover,
                    hovertemplate=(
                        "marker=%{text}<br>MAF(before)=%{x:.3f}<br>MAF(after)=%{y:.3f}<extra></extra>" if hover else None
                    ),
                    showlegend=False,
                ),
                row=2,
                col=1,
            )
            fig.update_xaxes(title_text="MAF (before)", row=2, col=1)
            fig.update_yaxes(title_text="MAF (after)", row=2, col=1)
            maf_scatter_ok = True
    except Exception:
        maf_scatter_ok = False

    # fallback: if maf_before not available, show maf_after histogram
    if not maf_scatter_ok:
        try:
            if maf_after is not None and maf_after.notna().any():
                fig.add_trace(go.Histogram(x=maf_after, name="maf after", nbinsx=50, showlegend=False), row=2, col=1)
                fig.update_xaxes(title_text="MAF (after)", row=2, col=1)
                fig.update_yaxes(title_text="# markers", row=2, col=1)
        except Exception:
            pass

    # (4) ΔMAF histogram
    try:
        if (maf_before is not None and maf_after is not None and maf_before.notna().any() and maf_after.notna().any()):
            d = (maf_after - maf_before)
            d = d.replace([np.inf, -np.inf], np.nan).dropna()
            if len(d) > 0:
                fig.add_trace(go.Histogram(x=d, nbinsx=60, showlegend=False), row=2, col=2)
                fig.update_xaxes(title_text="ΔMAF", row=2, col=2)
                fig.update_yaxes(title_text="# markers", row=2, col=2)
                # vertical line at 0
                fig.add_vline(x=0.0, line_dash="dash", row=2, col=2)
    except Exception:
        pass

    fig.update_layout(
        template="plotly_white",
        title=title,
        height=850,
        margin=dict(l=60, r=30, t=80, b=60),
        font=dict(family="Arial", size=12),
    )

    if acc_text:
        try:
            fig.add_annotation(
                x=0.01,
                y=0.99,
                xref="paper",
                yref="paper",
                text=acc_text,
                showarrow=False,
                xanchor="left",
                yanchor="top",
                font=dict(size=12),
            )
        except Exception:
            pass

    out_html.parent.mkdir(parents=True, exist_ok=True)
    out_html.write_text(_plotly_html(fig, pio, add_selection_js=False), encoding="utf-8")
    return True


def make_phenotype_imputation_qc_plotly(trait_summary_tsv: Path, sample_summary_tsv: Path | None, out_html: Path,
                                        title: str = "Phenotype imputation QC") -> bool:
    """QC dashboard for phenotype imputation outputs."""
    go, pio, qualitative = _try_import_plotly()
    if go is None:
        return False
    try:
        from plotly.subplots import make_subplots  # type: ignore
    except Exception:
        return False

    try:
        tdf = pd.read_csv(trait_summary_tsv, sep="\t")
    except Exception:
        return False

    sdf = None
    if sample_summary_tsv and sample_summary_tsv.exists():
        try:
            sdf = pd.read_csv(sample_summary_tsv, sep="\t")
        except Exception:
            sdf = None

    # numeric conversions
    for c in ["missing_before", "missing_after", "mean_before", "mean_after", "sd_before", "sd_after"]:
        if c in tdf.columns:
            tdf[c] = pd.to_numeric(tdf[c], errors="coerce")

    if sdf is not None:
        for c in ["missing_before", "missing_after"]:
            if c in sdf.columns:
                sdf[c] = pd.to_numeric(sdf[c], errors="coerce")

    # keep plot manageable: show all traits up to 80, otherwise top 80 by missing_before
    if "trait" in tdf.columns and len(tdf) > 80:
        tdf = tdf.sort_values("missing_before", ascending=False).head(80)

    fig = make_subplots(
        rows=2, cols=2,
        subplot_titles=[
            "Trait missingness (before vs after)",
            "Sample missingness (before vs after)",
            "Trait mean (before vs after)",
            "Trait SD / h2 (method-specific)"
        ],
        horizontal_spacing=0.12, vertical_spacing=0.15
    )

    if "trait" in tdf.columns and "missing_before" in tdf.columns:
        fig.add_trace(go.Bar(
            y=tdf["trait"], x=tdf["missing_before"], orientation="h",
            name="trait before", opacity=0.7
        ), row=1, col=1)
    if "trait" in tdf.columns and "missing_after" in tdf.columns:
        fig.add_trace(go.Bar(
            y=tdf["trait"], x=tdf["missing_after"], orientation="h",
            name="trait after", opacity=0.7
        ), row=1, col=1)

    if sdf is not None:
        if "missing_before" in sdf.columns:
            fig.add_trace(go.Histogram(x=sdf["missing_before"], name="sample before", opacity=0.6, nbinsx=50), row=1, col=2)
        if "missing_after" in sdf.columns:
            fig.add_trace(go.Histogram(x=sdf["missing_after"], name="sample after", opacity=0.6, nbinsx=50), row=1, col=2)

    # mean scatter
    if "mean_before" in tdf.columns and "mean_after" in tdf.columns:
        x = tdf["mean_before"]
        y = tdf["mean_after"]
        mx = float(np.nanmax([np.nanmax(x.values), np.nanmax(y.values), 0.0]))
        mn = float(np.nanmin([np.nanmin(x.values), np.nanmin(y.values), 0.0]))
        fig.add_trace(go.Scatter(x=[mn, mx], y=[mn, mx], mode="lines", name="y=x", line=dict(dash="dash")), row=2, col=1)
        fig.add_trace(go.Scatter(
            x=x, y=y, mode="markers", name="traits",
            text=tdf["trait"] if "trait" in tdf.columns else None,
            marker=dict(size=7, opacity=0.85),
            hovertemplate="trait=%{text}<br>before=%{x:.3g}<br>after=%{y:.3g}<extra></extra>" if "trait" in tdf.columns else None
        ), row=2, col=1)

    # SD scatter OR h2 bar if phenix outputs available (handled by caller by replacing trait_summary_tsv parent lookup)
    if "sd_before" in tdf.columns and "sd_after" in tdf.columns:
        x = tdf["sd_before"]
        y = tdf["sd_after"]
        mx = float(np.nanmax([np.nanmax(x.values), np.nanmax(y.values), 0.0]))
        mn = float(np.nanmin([np.nanmin(x.values), np.nanmin(y.values), 0.0]))
        fig.add_trace(go.Scatter(x=[mn, mx], y=[mn, mx], mode="lines", name="y=x (sd)", line=dict(dash="dash")), row=2, col=2)
        fig.add_trace(go.Scatter(
            x=x, y=y, mode="markers", name="sd traits",
            text=tdf["trait"] if "trait" in tdf.columns else None,
            marker=dict(size=7, opacity=0.85),
            hovertemplate="trait=%{text}<br>sd_before=%{x:.3g}<br>sd_after=%{y:.3g}<extra></extra>" if "trait" in tdf.columns else None
        ), row=2, col=2)

    fig.update_layout(
        template="plotly_white",
        title=title,
        height=850,
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="left", x=0.0),
        margin=dict(l=70, r=30, t=80, b=60),
        font=dict(family="Arial", size=12),
    )
    fig.update_xaxes(title_text="missing rate", row=1, col=1)
    fig.update_yaxes(title_text="trait", row=1, col=1)
    fig.update_xaxes(title_text="missing rate", row=1, col=2)
    fig.update_yaxes(title_text="count", row=1, col=2)
    fig.update_xaxes(title_text="mean_before", row=2, col=1)
    fig.update_yaxes(title_text="mean_after", row=2, col=1)
    fig.update_xaxes(title_text="sd_before", row=2, col=2)
    fig.update_yaxes(title_text="sd_after", row=2, col=2)

    out_html.parent.mkdir(parents=True, exist_ok=True)
    out_html.write_text(_plotly_html(fig, pio, add_selection_js=False), encoding="utf-8")
    return True


def summarize_genotype_matrix_tsv(path: Path,
                                 max_cols_full: int = 2000,
                                 max_markers_plot: int = 50000,
                                 max_samples_plot: int = 5000,
                                 chunksize: int = 200) -> dict[str, Any]:
    """Summarize a (potentially large) genotype matrix TSV for quick QC plots.

    Supports two common orientations:
    - sample x marker: first column looks like 'id'
    - marker x sample: first column looks like 'marker' (GBScleanR export)

    Returns dict with arrays for plotting and simple genotype counts.
    """
    na_values = ["NA", "", ".", "-", "nan", "NaN", "NAN"]
    if not path.exists():
        return {}

    # determine orientation by header
    with path.open("r", encoding="utf-8", errors="ignore") as f:
        header = f.readline().rstrip("\n")
    cols = header.split("\t")
    if len(cols) < 2:
        return {}
    first = cols[0].strip().lower()
    orient = "sample_rows"
    if first in ("marker", "snp", "locus", "rsid"):
        orient = "marker_rows"
    elif first in ("id", "sample", "taxa", "name"):
        orient = "sample_rows"
    else:
        # heuristic: if many columns, likely marker x sample (first col marker, many samples)
        orient = "marker_rows" if (len(cols) - 1) > 200 else "sample_rows"

    # decide subset of data columns for full parsing
    data_cols = cols[1:]
    usecols = None
    selected_data_cols = data_cols
    if len(data_cols) > max_cols_full:
        idx = np.unique(np.linspace(0, len(data_cols) - 1, max_cols_full, dtype=int))
        selected_data_cols = [data_cols[i] for i in idx]
        usecols = [cols[0]] + selected_data_cols

    # streaming aggregates
    marker_missing = []
    marker_maf = []
    marker_names = []

    sample_missing_counts = None
    sample_total_counts = None
    sample_ids = selected_data_cols if orient == "marker_rows" else None

    sample_missing_list: list[float] = []

    geno_counts = {"0": 0, "1": 0, "2": 0, "NA": 0}
    n_rows = 0

    try:
        reader = pd.read_csv(path, sep="\t", usecols=usecols, chunksize=chunksize, low_memory=False, na_values=na_values)
    except Exception:
        # try engine python for odd TSVs
        reader = pd.read_csv(path, sep="\t", usecols=usecols, chunksize=chunksize, low_memory=False, na_values=na_values, engine="python")

    for chunk in reader:
        if chunk.empty:
            continue
        n_rows += len(chunk)

        if orient == "marker_rows":
            # first col = marker id
            mnames = chunk.iloc[:, 0].astype(str).tolist()
            X = chunk.iloc[:, 1:]
            # numeric conversion (best-effort)
            Xn = X.apply(pd.to_numeric, errors="coerce").to_numpy(dtype=float)
            miss = np.mean(np.isnan(Xn), axis=1)
            mu = np.nanmean(Xn, axis=1) / 2.0
            mu = np.clip(mu, 0.0, 1.0)
            maf = np.minimum(mu, 1.0 - mu)
            marker_names.extend(mnames)
            marker_missing.extend(miss.tolist())
            marker_maf.extend(maf.tolist())

            # sample missingness
            if sample_missing_counts is None:
                sample_missing_counts = np.zeros(Xn.shape[1], dtype=np.float64)
                sample_total_counts = np.zeros(Xn.shape[1], dtype=np.float64)
            sample_missing_counts += np.sum(np.isnan(Xn), axis=0)
            sample_total_counts += Xn.shape[0]

            # genotype counts (rounded)
            finite = np.isfinite(Xn)
            geno_counts["NA"] += int(np.sum(~finite))
            vals = np.round(Xn[finite]).astype(int)
            geno_counts["0"] += int(np.sum(vals == 0))
            geno_counts["1"] += int(np.sum(vals == 1))
            geno_counts["2"] += int(np.sum(vals == 2))

        else:
            # sample_rows: first col = sample id; columns = markers
            sids = chunk.iloc[:, 0].astype(str).tolist()
            X = chunk.iloc[:, 1:]
            Xn = X.apply(pd.to_numeric, errors="coerce").to_numpy(dtype=float)

            # sample missingness directly
            s_miss = np.mean(np.isnan(Xn), axis=1)
            if sample_ids is None:
                sample_ids = []
            sample_ids.extend(sids)
            # store as marker_missing arrays for samples, for plotting
            # we will keep separate list below
            # (use marker_missing list to store sample missing temporarily)
            # But better: keep dedicated list
            sample_missing_list.extend(s_miss.tolist())

            # marker-level summaries may be huge; compute only if markers not too many (<= max_cols_full)
            # Here we compute maf/missing per marker on the selected columns only (if usecols limited)
            miss_m = np.mean(np.isnan(Xn), axis=0)
            mu = np.nanmean(Xn, axis=0) / 2.0
            mu = np.clip(mu, 0.0, 1.0)
            maf = np.minimum(mu, 1.0 - mu)
            marker_names.extend(list(X.columns))
            marker_missing.extend(miss_m.tolist())
            marker_maf.extend(maf.tolist())

            finite = np.isfinite(Xn)
            geno_counts["NA"] += int(np.sum(~finite))
            vals = np.round(Xn[finite]).astype(int)
            geno_counts["0"] += int(np.sum(vals == 0))
            geno_counts["1"] += int(np.sum(vals == 1))
            geno_counts["2"] += int(np.sum(vals == 2))

    # finalize
    if orient == "marker_rows":
        sample_missing = None
        if sample_missing_counts is not None and sample_total_counts is not None and sample_total_counts.size:
            sample_missing = (sample_missing_counts / np.maximum(sample_total_counts, 1.0)).tolist()
        # cap plot sizes
        if len(marker_missing) > max_markers_plot:
            idx = np.unique(np.linspace(0, len(marker_missing) - 1, max_markers_plot, dtype=int))
            marker_missing = [marker_missing[i] for i in idx]
            marker_maf = [marker_maf[i] for i in idx]
            marker_names = [marker_names[i] for i in idx]
        if sample_missing and len(sample_missing) > max_samples_plot:
            idx = np.unique(np.linspace(0, len(sample_missing) - 1, max_samples_plot, dtype=int))
            sample_missing = [sample_missing[i] for i in idx]
            sample_ids = [sample_ids[i] for i in idx] if sample_ids else None
        return dict(
            orientation=orient,
            marker_names=marker_names,
            marker_missing=marker_missing,
            marker_maf=marker_maf,
            sample_ids=sample_ids,
            sample_missing=sample_missing,
            genotype_counts=geno_counts,
            n_rows=n_rows,
            n_cols=len(data_cols),
            used_cols=len(selected_data_cols),
        )
    else:
        # sample_rows
        sample_missing = sample_missing_list
        if len(marker_missing) > max_markers_plot:
            idx = np.unique(np.linspace(0, len(marker_missing) - 1, max_markers_plot, dtype=int))
            marker_missing = [marker_missing[i] for i in idx]
            marker_maf = [marker_maf[i] for i in idx]
            marker_names = [marker_names[i] for i in idx]
        if sample_missing and len(sample_missing) > max_samples_plot:
            idx = np.unique(np.linspace(0, len(sample_missing) - 1, max_samples_plot, dtype=int))
            sample_missing = [sample_missing[i] for i in idx]
            sample_ids = [sample_ids[i] for i in idx] if sample_ids else None
        return dict(
            orientation=orient,
            marker_names=marker_names,
            marker_missing=marker_missing,
            marker_maf=marker_maf,
            sample_ids=sample_ids,
            sample_missing=sample_missing,
            genotype_counts=geno_counts,
            n_rows=n_rows,
            n_cols=len(data_cols),
            used_cols=len(selected_data_cols),
        )


def make_cross_imputation_qc_plotly(imputed_tsv: Path, out_html: Path, title: str = "Cross-population imputation QC") -> bool:
    go, pio, qualitative = _try_import_plotly()
    if go is None:
        return False
    try:
        from plotly.subplots import make_subplots  # type: ignore
    except Exception:
        return False

    summ = summarize_genotype_matrix_tsv(imputed_tsv)
    if not summ:
        return False

    mm = summ.get("marker_missing") or []
    sm = summ.get("sample_missing") or []
    maf = summ.get("marker_maf") or []
    gc = summ.get("genotype_counts") or {"0": 0, "1": 0, "2": 0, "NA": 0}

    fig = make_subplots(
        rows=2, cols=2,
        subplot_titles=[
            "Marker missingness (after)",
            "Sample missingness (after)",
            "MAF (after)",
            "Genotype counts (after)"
        ],
        horizontal_spacing=0.12, vertical_spacing=0.15
    )

    if mm:
        fig.add_trace(go.Histogram(x=mm, name="marker missing", nbinsx=50), row=1, col=1)
    if sm:
        fig.add_trace(go.Histogram(x=sm, name="sample missing", nbinsx=50), row=1, col=2)
    if maf:
        fig.add_trace(go.Histogram(x=maf, name="maf", nbinsx=50), row=2, col=1)

    fig.add_trace(go.Bar(x=list(gc.keys()), y=[gc[k] for k in gc.keys()], name="counts"), row=2, col=2)

    fig.update_layout(
        template="plotly_white",
        title=f"{title} (orientation={summ.get('orientation')}, used_cols={summ.get('used_cols')}/{summ.get('n_cols')})",
        height=850,
        margin=dict(l=60, r=30, t=80, b=60),
        font=dict(family="Arial", size=12),
        showlegend=False
    )
    fig.update_xaxes(title_text="missing rate", row=1, col=1)
    fig.update_yaxes(title_text="count", row=1, col=1)
    fig.update_xaxes(title_text="missing rate", row=1, col=2)
    fig.update_yaxes(title_text="count", row=1, col=2)
    fig.update_xaxes(title_text="MAF", row=2, col=1)
    fig.update_yaxes(title_text="count", row=2, col=1)
    fig.update_xaxes(title_text="genotype", row=2, col=2)
    fig.update_yaxes(title_text="count", row=2, col=2)

    out_html.parent.mkdir(parents=True, exist_ok=True)
    out_html.write_text(_plotly_html(fig, pio, add_selection_js=False), encoding="utf-8")
    return True



def _standardize_qtl_lod_df(df: pd.DataFrame) -> pd.DataFrame:
    """Standardize QTL LOD profile into columns: chr, pos, lod.

    The app currently supports multiple QTL backends (r/qtl, qtl2). Their
    output tables differ slightly, so we normalize to a minimal common schema.
    """
    d = df.copy()
    # normalize column names
    cols = {c: str(c).strip() for c in d.columns}
    d.rename(columns=cols, inplace=True)

    # common variants
    if "LOD" in d.columns and "lod" not in d.columns:
        d.rename(columns={"LOD": "lod"}, inplace=True)

    # r/qtl scanone typically returns columns: chr, pos, lod
    # qtl2 code joins map_df and scan_df, often yielding: marker, chr, pos, lod
    # Some tables use 'cM' or 'position' variants
    if "pos" not in d.columns:
        for cand in ["cM", "cm", "position", "Position", "pos_cM", "pos_cm"]:
            if cand in d.columns:
                d.rename(columns={cand: "pos"}, inplace=True)
                break
    if "chr" not in d.columns:
        for cand in ["chrom", "chromosome", "Chr", "CHR"]:
            if cand in d.columns:
                d.rename(columns={cand: "chr"}, inplace=True)
                break
    if "lod" not in d.columns:
        # try first numeric column other than marker/chr/pos
        for c in d.columns:
            if c.lower() in ("marker", "chr", "pos"):
                continue
            if pd.api.types.is_numeric_dtype(d[c]):
                d.rename(columns={c: "lod"}, inplace=True)
                break

    need = {"chr", "pos", "lod"}
    if not need.issubset(set(d.columns)):
        raise ValueError(f"LOD profile missing required columns {need}. Found: {list(d.columns)}")

    d = d[["chr", "pos", "lod"]].copy()
    d["chr"] = d["chr"].astype(str)
    d["pos"] = pd.to_numeric(d["pos"], errors="coerce")
    d["lod"] = pd.to_numeric(d["lod"], errors="coerce")
    d = d.dropna(subset=["pos", "lod"])
    return d


def _sort_chr_labels(chrs: list[str]) -> list[str]:
    def _key(c: str):
        m = re.search(r"\d+", c)
        if m:
            return (0, int(m.group(0)), c)
        return (1, 10**9, c)
    return sorted([str(x) for x in chrs], key=_key)


def _genome_offsets(lod_df: pd.DataFrame) -> tuple[pd.DataFrame, dict[str, float], list[str]]:
    """Create genome-wide x coordinate by concatenating chromosomes."""
    d = lod_df.copy()
    chrs = _sort_chr_labels(d["chr"].dropna().astype(str).unique().tolist())
    offsets: dict[str, float] = {}
    cur = 0.0
    gap = 5.0  # small visual gap between chromosomes (in the same unit as 'pos')
    for c in chrs:
        sub = d[d["chr"].astype(str) == c]
        if sub.empty:
            offsets[c] = cur
            continue
        mn = float(np.nanmin(sub["pos"].values))
        mx = float(np.nanmax(sub["pos"].values))
        offsets[c] = cur - mn
        cur += (mx - mn) + gap
    d["x"] = d.apply(lambda r: float(r["pos"]) + offsets.get(str(r["chr"]), 0.0), axis=1)
    return d, offsets, chrs


def _infer_ci(peaks_df: pd.DataFrame) -> tuple[str | None, str | None]:
    """Infer CI column names (left/right) from peaks table."""
    cols = [c for c in peaks_df.columns]
    # common in r/qtl summary: ci.lo / ci.hi
    for l, r in [("ci.lo", "ci.hi"), ("ci_lo", "ci_hi"), ("ci_l", "ci_r"), ("ci_left", "ci_right"), ("l", "r")]:
        if l in cols and r in cols:
            return l, r
    # qtl2 sometimes uses 'ci_lower'/'ci_upper'
    for l in cols:
        if re.search(r"ci.*(lo|left|lower)", l, flags=re.I):
            for r in cols:
                if re.search(r"ci.*(hi|right|upper)", r, flags=re.I):
                    return l, r
    return None, None




# ---- RNA-seq Plotly (publication-oriented) ---------------------------------

def _read_table_auto_pd(path: Path) -> pd.DataFrame:
    """Best-effort TSV/CSV reader (delimiter auto-detect)."""
    try:
        return pd.read_csv(path, sep=None, engine="python")
    except Exception:
        # fallback: assume TSV
        return pd.read_csv(path, sep="\t")

def _rnaseq_guess_pcol(df: pd.DataFrame) -> str | None:
    for c in ["padj", "FDR", "adj.P.Val", "qvalue", "q_value", "qval"]:
        if c in df.columns:
            return c
    for c in ["pvalue", "PValue", "P.Value", "p_val", "pval", "p"]:
        if c in df.columns:
            return c
    return None

def _rnaseq_guess_lfc_col(df: pd.DataFrame) -> str | None:
    for c in ["log2FoldChange", "logFC", "log2FC", "LFC", "log_fold_change"]:
        if c in df.columns:
            return c
    return None

def _rnaseq_guess_mean_col(df: pd.DataFrame) -> str | None:
    for c in ["baseMean", "mean", "AveExpr", "logCPM", "log2_mean", "avgExpr", "log2Mean"]:
        if c in df.columns:
            return c
    return None

def _rnaseq_guess_gene_col(df: pd.DataFrame) -> str:
    for c in ["gene", "gene_id", "Gene", "id", "ID"]:
        if c in df.columns:
            return c
    return df.columns[0]

def _pca2_svd(X: np.ndarray) -> tuple[np.ndarray, np.ndarray]:
    """Return (scores[n,2], explained_ratio[2]) using SVD PCA."""
    # center
    X = X.astype(float)
    X = X - np.nanmean(X, axis=0, keepdims=True)
    X[np.isnan(X)] = 0.0
    # scale to unit variance (avoid divide-by-zero)
    s = np.nanstd(X, axis=0, keepdims=True)
    s[s == 0] = 1.0
    X = X / s
    # SVD
    U, S, Vt = np.linalg.svd(X, full_matrices=False)
    scores = U[:, :2] * S[:2]
    # explained variance ratio
    n = X.shape[0]
    ev = (S**2) / max(n - 1, 1)
    evr = ev / ev.sum() if ev.sum() > 0 else np.array([0.0] * len(ev))
    return scores, evr[:2]



def _standardize_map_markers_df(df: pd.DataFrame) -> pd.DataFrame:
    """Return a copy with columns: lg, marker, pos.

    Accepts common column variants produced by mapping backends.
    """
    d = df.copy()

    def pick(keys):
        for k in keys:
            if k in d.columns:
                return k
        low = {c.lower(): c for c in d.columns}
        for k in keys:
            if k.lower() in low:
                return low[k.lower()]
        return None

    c_lg = pick(["lg", "chr", "chrom", "chromosome", "group", "linkage_group", "CHR", "Chromosome"])
    c_marker = pick(["marker", "Marker", "snp", "SNP", "id", "name", "rsid"])
    c_pos = pick(["pos_cM", "pos_cm", "cM", "cm", "pos", "position", "bp", "BP", "POS"])

    if c_lg is None:
        d["lg"] = "NA"
    else:
        d["lg"] = d[c_lg].astype(str)

    if c_marker is None:
        # generate marker ids if absent
        d["marker"] = [f"m{i+1}" for i in range(len(d))]
    else:
        d["marker"] = d[c_marker].astype(str)

    if c_pos is None:
        d["pos"] = pd.to_numeric(d.iloc[:, 0], errors="coerce")
    else:
        d["pos"] = pd.to_numeric(d[c_pos], errors="coerce")

    # drop missing positions
    d = d.dropna(subset=["pos"]).copy()

    return d


def build_rnaseq_volcano_figure(
    deg_df: pd.DataFrame,
    *,
    title: str = "Volcano plot",
    fdr: float = 0.05,
    lfc: float = 1.0,
    topn_labels: int = 20,
    label_col: str | None = None,
) -> "go.Figure" | None:
    go, pio, qualitative = _try_import_plotly()
    if go is None:
        return None

    df = deg_df.copy()
    gene_col = _rnaseq_guess_gene_col(df)
    pcol = _rnaseq_guess_pcol(df)
    lfc_col = _rnaseq_guess_lfc_col(df)
    if pcol is None or lfc_col is None:
        raise ValueError("DEG table must contain pvalue/padj and logFC/log2FoldChange columns.")

    df[pcol] = pd.to_numeric(df[pcol], errors="coerce")
    df[lfc_col] = pd.to_numeric(df[lfc_col], errors="coerce")

    df = df.dropna(subset=[pcol, lfc_col]).copy()
    # avoid log(0)
    df["_mlog10p"] = -np.log10(np.clip(df[pcol].values, 1e-300, 1.0))
    df["_sig"] = (df[pcol] <= fdr) & (np.abs(df[lfc_col]) >= lfc)

    # label column default
    if label_col and (label_col in df.columns):
        lab = df[label_col].astype(str)
    else:
        lab = df[gene_col].astype(str)

    # main scatter (SVG-based; no WebGL dependency)
    fig = go.Figure()
    fig.add_trace(
        go.Scatter(
            x=df[lfc_col],
            y=df["_mlog10p"],
            mode="markers",
            marker=dict(
                size=5,
                opacity=0.75,
                color=np.where(df["_sig"].values, "#d62728", "#1f77b4"),
            ),
            text=lab,
            hovertemplate="<b>%{text}</b><br>log2FC=%{x:.3g}<br>-log10(p)=%{y:.3g}<extra></extra>",
            name="genes",
            showlegend=False,
        )
    )

    # threshold lines
    fig.add_hline(y=-np.log10(max(fdr, 1e-300)), line_width=1, line_dash="dot")
    fig.add_vline(x=lfc, line_width=1, line_dash="dot")
    fig.add_vline(x=-lfc, line_width=1, line_dash="dot")

    # top labels (robust: prioritize by p then |lfc|)
    if topn_labels and topn_labels > 0:
        df2 = df.copy()
        df2["_rank"] = df2[pcol].rank(method="average") + (1.0 / (np.abs(df2[lfc_col]) + 1e-9))
        df2 = df2.sort_values(by=[pcol, lfc_col], ascending=[True, False]).head(topn_labels)
        fig.add_trace(
            go.Scatter(
                x=df2[lfc_col],
                y=df2["_mlog10p"],
                mode="markers+text",
                text=(df2[label_col].astype(str) if (label_col and label_col in df2.columns) else df2[gene_col].astype(str)),
                textposition="top center",
                marker=dict(size=6, opacity=0.95, color="#d62728"),
                hoverinfo="skip",
                showlegend=False,
            )
        )

    fig.update_layout(
        title=title,
        xaxis_title="log2 fold change",
        yaxis_title="-log10(p)",
        margin=dict(l=70, r=20, t=70, b=60),
        template="plotly_white",
        font=dict(size=12, family="Arial"),
    )
    fig.update_xaxes(showline=True, linewidth=1, linecolor="black", mirror=True, zeroline=False)
    fig.update_yaxes(showline=True, linewidth=1, linecolor="black", mirror=True, zeroline=False)

    return fig

def build_rnaseq_ma_figure(
    deg_df: pd.DataFrame,
    *,
    title: str = "MA plot",
    lfc: float = 1.0,
    topn_labels: int = 20,
    label_col: str | None = None,
) -> "go.Figure" | None:
    go, pio, qualitative = _try_import_plotly()
    if go is None:
        return None

    df = deg_df.copy()
    gene_col = _rnaseq_guess_gene_col(df)
    lfc_col = _rnaseq_guess_lfc_col(df)
    mean_col = _rnaseq_guess_mean_col(df)
    if lfc_col is None or mean_col is None:
        raise ValueError("DEG table must contain logFC/log2FoldChange and baseMean/logCPM/AveExpr columns for MA plot.")

    df[lfc_col] = pd.to_numeric(df[lfc_col], errors="coerce")
    df[mean_col] = pd.to_numeric(df[mean_col], errors="coerce")
    df = df.dropna(subset=[lfc_col, mean_col]).copy()

    # Use log-scale on mean-like axis if it is raw baseMean
    x = df[mean_col].values
    if np.nanmax(x) > 1000:  # heuristic
        x_plot = np.log10(np.clip(x, 1e-9, None))
        xlab = "log10(mean expression)"
    else:
        x_plot = x
        xlab = str(mean_col)

    if label_col and (label_col in df.columns):
        lab = df[label_col].astype(str)
    else:
        lab = df[gene_col].astype(str)

    fig = go.Figure()
    fig.add_trace(
        go.Scatter(
            x=x_plot,
            y=df[lfc_col],
            mode="markers",
            marker=dict(size=5, opacity=0.75, color="#1f77b4"),
            text=lab,
            hovertemplate="<b>%{text}</b><br>x=%{x:.3g}<br>log2FC=%{y:.3g}<extra></extra>",
            showlegend=False,
        )
    )
    fig.add_hline(y=lfc, line_width=1, line_dash="dot")
    fig.add_hline(y=-lfc, line_width=1, line_dash="dot")
    fig.add_hline(y=0.0, line_width=1, line_dash="solid")

    if topn_labels and topn_labels > 0:
        df2 = df.copy()
        df2["_abs"] = np.abs(df2[lfc_col])
        df2 = df2.sort_values(by="_abs", ascending=False).head(topn_labels)
        x2 = df2[mean_col].values
        x2_plot = np.log10(np.clip(x2, 1e-9, None)) if (np.nanmax(x) > 1000) else x2
        fig.add_trace(
            go.Scatter(
                x=x2_plot,
                y=df2[lfc_col],
                mode="markers+text",
                text=(df2[label_col].astype(str) if (label_col and label_col in df2.columns) else df2[gene_col].astype(str)),
                textposition="top center",
                marker=dict(size=6, opacity=0.95, color="#d62728"),
                hoverinfo="skip",
                showlegend=False,
            )
        )

    fig.update_layout(
        title=title,
        xaxis_title=xlab,
        yaxis_title="log2 fold change",
        margin=dict(l=70, r=20, t=70, b=60),
        template="plotly_white",
        font=dict(size=12, family="Arial"),
    )
    fig.update_xaxes(showline=True, linewidth=1, linecolor="black", mirror=True, zeroline=False)
    fig.update_yaxes(showline=True, linewidth=1, linecolor="black", mirror=True, zeroline=False)
    return fig


def _apply_rnaseq_deg_style(fig, settings: dict) -> None:
    """Apply common RNA-seq DEG style options to a Plotly figure.

    The UI collects options (marker size/opacity, font). This helper applies them
    to figures produced by build_rnaseq_*_figure.
    """
    if fig is None:
        return

    # Marker size / opacity for scatter traces
    try:
        pt_size = float(settings.get("point_size", 5) or 5)
        opacity = float(settings.get("opacity", 0.8) or 0.8)
        for tr in getattr(fig, "data", []) or []:
            try:
                if str(getattr(tr, "type", "")) != "scatter":
                    continue
                mk = getattr(tr, "marker", None)
                if mk is None:
                    continue
                try:
                    mk.size = pt_size
                except Exception:
                    pass
                try:
                    mk.opacity = opacity
                except Exception:
                    pass
            except Exception:
                pass
    except Exception:
        pass

    # Font
    try:
        fam = (settings.get("font_family") or "Arial").strip()
        fsz = int(settings.get("font_size") or 12)
        fig.update_layout(font=dict(family=fam, size=fsz))
    except Exception:
        pass


def build_rnaseq_volcano(deg_df: pd.DataFrame, settings: dict):
    """Wrapper used by ResultsPane RNA-seq Plotly regeneration."""
    title = (settings.get("title") or "").strip() or "Volcano plot"
    fig = build_rnaseq_volcano_figure(
        deg_df,
        title=title,
        fdr=float(settings.get("fdr") or 0.05),
        lfc=float(settings.get("lfc") or 1.0),
        topn_labels=int(settings.get("top_n") or 20),
    )
    if fig is None:
        return None
    _apply_rnaseq_deg_style(fig, settings)
    if not bool(settings.get("show_thresholds", True)):
        try:
            ResultsPane._strip_rnaseq_threshold_annotations(fig)
        except Exception:
            pass
    return fig


def build_rnaseq_ma(deg_df: pd.DataFrame, settings: dict):
    """Wrapper used by ResultsPane RNA-seq Plotly regeneration."""
    title = (settings.get("title") or "").strip() or "MA plot"
    fig = build_rnaseq_ma_figure(
        deg_df,
        title=title,
        lfc=float(settings.get("lfc") or 1.0),
        topn_labels=int(settings.get("top_n") or 20),
    )
    if fig is None:
        return None
    _apply_rnaseq_deg_style(fig, settings)
    if not bool(settings.get("show_thresholds", True)):
        try:
            ResultsPane._strip_rnaseq_threshold_annotations(fig)
        except Exception:
            pass
    return fig

def build_rnaseq_pca_figure(
    normalized_counts_tsv: Path,
    design_table: Path,
    *,
    sample_col: str = "sample",
    color_col: str = "condition",
    title: str = "PCA (samples)",
) -> "go.Figure" | None:
    go, pio, qualitative = _try_import_plotly()
    if go is None:
        return None

    expr = _read_table_auto_pd(normalized_counts_tsv)
    if expr.shape[1] < 3:
        raise ValueError("normalized counts must be (gene + >=2 samples).")
    gene_col = _rnaseq_guess_gene_col(expr)
    expr = expr.rename(columns={gene_col: "gene"})
    expr = expr.set_index("gene")
    # numeric matrix genes x samples
    Xg = expr.apply(pd.to_numeric, errors="coerce").fillna(0.0).to_numpy(dtype=float)
    # transform: log2(x+1)
    Xg = np.log2(Xg + 1.0)
    X = Xg.T  # samples x genes

    scores, evr = _pca2_svd(X)

    meta = _read_table_auto_pd(design_table)
    if sample_col not in meta.columns:
        raise ValueError(f"design table missing sample_col={sample_col}")
    meta[sample_col] = meta[sample_col].astype(str)

    samples = list(expr.columns.astype(str))
    md = meta.set_index(sample_col, drop=False).reindex(samples)
    grp = md[color_col].astype(str) if (color_col in md.columns) else pd.Series(["sample"] * len(samples))

    fig = go.Figure()
    for g in pd.unique(grp):
        idx = np.where(grp.values == g)[0]
        fig.add_trace(
            go.Scatter(
                x=scores[idx, 0],
                y=scores[idx, 1],
                mode="markers+text",
                text=[samples[i] for i in idx],
                textposition="top center",
                marker=dict(size=10, opacity=0.9),
                name=str(g),
                hovertemplate="<b>%{text}</b><br>PC1=%{x:.3g}<br>PC2=%{y:.3g}<extra></extra>",
            )
        )

    fig.update_layout(
        title=title,
        xaxis_title=f"PC1 ({evr[0]*100:.1f}%)",
        yaxis_title=f"PC2 ({evr[1]*100:.1f}%)",
        margin=dict(l=70, r=20, t=70, b=60),
        template="plotly_white",
        font=dict(size=12, family="Arial"),
        legend_title=color_col,
    )
    fig.update_xaxes(showline=True, linewidth=1, linecolor="black", mirror=True, zeroline=False)
    fig.update_yaxes(showline=True, linewidth=1, linecolor="black", mirror=True, zeroline=False)
    return fig

def build_rnaseq_heatmap_figure(
    normalized_counts_tsv: Path,
    design_table: Path,
    *,
    sample_col: str = "sample",
    order_col: str = "condition",
    topn: int = 200,
    mode: str = "variance",
    zscore: bool = True,
    title: str = "Expression heatmap (Top genes)",
) -> "go.Figure" | None:
    go, pio, qualitative = _try_import_plotly()
    if go is None:
        return None

    expr = _read_table_auto_pd(normalized_counts_tsv)
    if expr.shape[1] < 3:
        raise ValueError("normalized counts must be (gene + >=2 samples).")
    gene_col = _rnaseq_guess_gene_col(expr)
    expr = expr.rename(columns={gene_col: "gene"})
    expr = expr.set_index("gene")
    mat = expr.apply(pd.to_numeric, errors="coerce").fillna(0.0).to_numpy(dtype=float)
    mat = np.log2(mat + 1.0)

    # rank genes
    if mode == "variance":
        score = np.var(mat, axis=1)
    else:
        score = np.mean(mat, axis=1)
    idx = np.argsort(score)[::-1][: max(2, int(topn))]
    mat2 = mat[idx, :]
    genes = expr.index.values[idx]

    # z-score per gene
    if zscore:
        mu = mat2.mean(axis=1, keepdims=True)
        sd = mat2.std(axis=1, keepdims=True)
        sd[sd == 0] = 1.0
        mat2 = (mat2 - mu) / sd

    samples = list(expr.columns.astype(str))
    meta = _read_table_auto_pd(design_table)
    if sample_col not in meta.columns:
        raise ValueError(f"design table missing sample_col={sample_col}")
    meta[sample_col] = meta[sample_col].astype(str)
    md = meta.set_index(sample_col, drop=False).reindex(samples)

    # order samples by order_col if available
    if order_col in md.columns:
        ord_vals = md[order_col].astype(str).fillna("")
        order = np.argsort(ord_vals.values, kind="stable")
        mat2 = mat2[:, order]
        samples = [samples[i] for i in order]

    fig = go.Figure(
        data=go.Heatmap(
            z=mat2,
            x=samples,
            y=genes.astype(str),
            colorbar=dict(title=("z-score" if zscore else "log2(x+1)")),
        )
    )
    fig.update_layout(
        title=title,
        margin=dict(l=90, r=20, t=70, b=90),
        template="plotly_white",
        font=dict(size=11, family="Arial"),
    )
    return fig

