def build_qtl_scan_figure(
    lod_profile_tsv: Path,
    peaks_tsv: Path | None,
    perm_thresholds_tsv: Path | None,
    *,
    title: str = "QTL LOD profile",
    pos_unit: str = "cM",
    zoom_window: float = 20.0,
    style: dict | None = None,
):
    """Build a publication-style QTL scan Plotly figure (genome-wide + peak zoom).

    This returns a Plotly figure and does not write files. Use `make_qtl_scan_plotly` to save HTML.

    Parameters
    ----------
    lod_profile_tsv
        TSV with chr/pos/lod (r/qtl) or marker/chr/pos/lod (qtl2).
    peaks_tsv
        TSV with peak rows (chr/pos/lod and optional CI columns).
    perm_thresholds_tsv
        TSV with columns alpha/threshold (optional).
    style
        Optional dict controlling layout and layer toggles.
        Supported keys (subset):
            font_family, font_size, font_color,
            margin_l, margin_r, margin_t, margin_b,
            height,
            lod_line_width,
            peak_marker_size,
            show_chr_shading (bool), chr_shading_alpha,
            show_thresholds (bool),
            show_ci (bool),
            show_peak_label (bool)
    """
    go, pio, _qual = _try_import_plotly()
    if go is None or pio is None:
        return None

    style = style or {}
    font_family = str(style.get("font_family", "Arial"))
    font_size = int(style.get("font_size", 12))
    font_color = str(style.get("font_color", "#000000"))
    margin = dict(
        l=int(style.get("margin_l", 60)),
        r=int(style.get("margin_r", 25)),
        t=int(style.get("margin_t", 70)),
        b=int(style.get("margin_b", 60)),
    )
    height = int(style.get("height", 900))
    lod_line_width = float(style.get("lod_line_width", 2.0))
    peak_marker_size = float(style.get("peak_marker_size", 8.0))
    show_chr_shading = bool(style.get("show_chr_shading", True))
    chr_shading_alpha = float(style.get("chr_shading_alpha", 0.03))
    show_thresholds = bool(style.get("show_thresholds", True))
    show_ci = bool(style.get("show_ci", True))
    show_peak_label = bool(style.get("show_peak_label", True))

    # backgrounds
    plot_bgcolor = str(style.get("plot_bgcolor", "#ffffff"))
    paper_bgcolor = str(style.get("paper_bgcolor", "#ffffff"))

    # threshold line style
    threshold_line_width = float(style.get("threshold_line_width", 2.0))
    threshold_label_position = str(style.get("threshold_label_position", "top left"))

    lod_raw = pd.read_csv(lod_profile_tsv, sep="\t")
    lod_df = _standardize_qtl_lod_df(lod_raw)

    # ---- pos unit auto-detect & scaling (for qtl2 outputs in bp, etc.) ----
    def _infer_scale_unit(pos: pd.Series, hint: str) -> tuple[float, str, int]:
        """Infer a display unit and scale factor.

        Returns (factor, unit_label, decimals) where displayed_pos = pos / factor.
        """
        h = (hint or "").strip().lower()
        mx = float(np.nanmax(pos.values)) if len(pos) else float("nan")
        # explicit hints
        if any(k in h for k in ["cm", "centimorgan"]):
            return 1.0, "cM", 3
        if any(k in h for k in ["mb", "megabase"]):
            return 1e6, "Mb", 3
        if any(k in h for k in ["kb", "kilobase"]):
            return 1e3, "kb", 1
        if any(k in h for k in ["bp", "base"]):
            # choose kb or Mb by magnitude
            if np.isfinite(mx) and mx >= 1e6:
                return 1e6, "Mb", 3
            return 1e3, "kb", 1
        # auto
        if h in ("", "auto", "infer"):
            if np.isfinite(mx) and mx >= 1e6:
                return 1e6, "Mb", 3
            if np.isfinite(mx) and mx >= 1e4:
                return 1e3, "kb", 1
            return 1.0, "cM", 3
        # fallback: use as-is
        return 1.0, hint, 3

    scale_factor, pos_unit_disp, pos_decimals = _infer_scale_unit(lod_df["pos"], pos_unit)
    if scale_factor != 1.0:
        lod_df = lod_df.copy()
        lod_df["pos"] = lod_df["pos"] / scale_factor
    pos_unit = pos_unit_disp

    d, offsets, chrs = _genome_offsets(lod_df)

    # peaks
    peaks_df = None
    top_peak = None
    ci_l = ci_r = None
    if peaks_tsv is not None and Path(peaks_tsv).exists():
        try:
            peaks_df = pd.read_csv(peaks_tsv, sep="\t")
            # normalize columns
            if "chr" not in peaks_df.columns:
                for cand in ["Chr", "chrom", "chromosome", "CHR"]:
                    if cand in peaks_df.columns:
                        peaks_df.rename(columns={cand: "chr"}, inplace=True)
                        break
            if "pos" not in peaks_df.columns:
                for cand in ["cM", "cm", "position", "pos_cM", "pos_cm", "pos"]:
                    if cand in peaks_df.columns:
                        peaks_df.rename(columns={cand: "pos"}, inplace=True)
                        break
            if "lod" not in peaks_df.columns:
                for cand in ["LOD", "lod"]:
                    if cand in peaks_df.columns:
                        peaks_df.rename(columns={cand: "lod"}, inplace=True)
                        break
            peaks_df["pos"] = pd.to_numeric(peaks_df.get("pos"), errors="coerce")
            peaks_df["lod"] = pd.to_numeric(peaks_df.get("lod"), errors="coerce")
            peaks_df["chr"] = peaks_df.get("chr").astype(str)
            peaks_df = peaks_df.dropna(subset=["chr", "pos", "lod"])
            if scale_factor != 1.0 and not peaks_df.empty:
                peaks_df["pos"] = peaks_df["pos"] / scale_factor
                # also scale CI columns if present
                ci_l0, ci_r0 = _infer_ci(peaks_df)
                if ci_l0 and ci_l0 in peaks_df.columns:
                    peaks_df[ci_l0] = pd.to_numeric(peaks_df[ci_l0], errors="coerce") / scale_factor
                if ci_r0 and ci_r0 in peaks_df.columns:
                    peaks_df[ci_r0] = pd.to_numeric(peaks_df[ci_r0], errors="coerce") / scale_factor
            if not peaks_df.empty:
                top_peak = peaks_df.sort_values("lod", ascending=False).iloc[0]
                ci_l, ci_r = _infer_ci(peaks_df)
        except Exception:
            peaks_df = None

    # threshold(s)
    thr_lines: list[tuple[float, str]] = []
    if show_thresholds and perm_thresholds_tsv is not None and Path(perm_thresholds_tsv).exists():
        try:
            thr_df = pd.read_csv(perm_thresholds_tsv, sep="\t")
            if "threshold" in thr_df.columns:
                for _, row in thr_df.iterrows():
                    try:
                        a = float(row.get("alpha", np.nan))
                        t = float(row.get("threshold"))
                        lab = f"thr (alpha={a:g})" if np.isfinite(a) else "threshold"
                        if np.isfinite(t):
                            thr_lines.append((t, lab))
                    except Exception:
                        continue
        except Exception:
            pass

    try:
        from plotly.subplots import make_subplots  # type: ignore
    except Exception:
        make_subplots = None
    if make_subplots is None:
        return None

    fig = make_subplots(
        rows=2,
        cols=1,
        shared_xaxes=False,
        vertical_spacing=0.12,
        row_heights=[0.62, 0.38],
        subplot_titles=("Genome-wide scan", "Peak region"),
    )

    # genome-wide line
    # Plotly uses d3-format strings (e.g. ".3f"); keep the same string for python f-string formatting.
    pos_fmt = f".{pos_decimals}f"
    fig.add_trace(
        go.Scatter(
            x=d["x"],
            y=d["lod"],
            mode="lines",
            name="LOD",
            line=dict(width=lod_line_width),
            hovertemplate="chr=%{customdata[0]}<br>pos=%{customdata[1]:" + pos_fmt + "} " + pos_unit + "<br>LOD=%{y:.3f}<extra></extra>",
            customdata=np.stack([d["chr"].values, d["pos"].values], axis=1),
        ),
        row=1,
        col=1,
    )

    # chr boundaries + alternating backgrounds
    for i, c in enumerate(chrs):
        sub = d[d["chr"].astype(str) == c]
        if sub.empty:
            continue
        xmin = float(np.nanmin(sub["x"].values))
        xmax = float(np.nanmax(sub["x"].values))

        if show_chr_shading and (i % 2 == 0):
            a = max(0.0, min(0.25, chr_shading_alpha))
            fig.add_vrect(
                x0=xmin,
                x1=xmax,
                fillcolor=f"rgba(0,0,0,{a:g})",
                line_width=0,
                row=1,
                col=1,
            )
        fig.add_vline(x=xmax, line_width=1, line_dash="dot", line_color="rgba(0,0,0,0.25)", row=1, col=1)

    # chr tick labels at midpoints
    tick_x = []
    tick_t = []
    for c in chrs:
        sub = d[d["chr"].astype(str) == c]
        if sub.empty:
            continue
        xmin = float(np.nanmin(sub["x"].values))
        xmax = float(np.nanmax(sub["x"].values))
        tick_x.append((xmin + xmax) / 2.0)
        tick_t.append(str(c))

    fig.update_xaxes(
        row=1,
        col=1,
        tickmode="array",
        tickvals=tick_x,
        ticktext=tick_t,
        title_text="Chromosome",
    )
    fig.update_yaxes(row=1, col=1, title_text="LOD")

    # peaks markers (genome-wide)
    if peaks_df is not None and not peaks_df.empty:
        xpk = []
        ypk = []
        hcd = []
        for _, r in peaks_df.iterrows():
            c = str(r["chr"])
            pos = float(r["pos"])
            lodv = float(r["lod"])
            xpk.append(pos + offsets.get(c, 0.0))
            ypk.append(lodv)
            hcd.append([c, pos])
        fig.add_trace(
            go.Scatter(
                x=xpk,
                y=ypk,
                mode="markers",
                name="Peaks",
                marker=dict(size=peak_marker_size),
                hovertemplate="PEAK<br>chr=%{customdata[0]}<br>pos=%{customdata[1]:" + pos_fmt + "} " + pos_unit + "<br>LOD=%{y:.3f}<extra></extra>",
                customdata=np.array(hcd),
            ),
            row=1,
            col=1,
        )

    # threshold lines
    if show_thresholds:
        for t, lab in thr_lines:
            fig.add_hline(
                y=t,
                line_dash="dash",
                line_width=threshold_line_width,
                annotation_text=lab,
                annotation_position=threshold_label_position,
                row=1,
                col=1,
            )
            fig.add_hline(y=t, line_dash="dash", line_width=threshold_line_width, row=2, col=1)

    # zoom panel: around top peak
    if top_peak is not None:
        c0 = str(top_peak["chr"])
        p0 = float(top_peak["pos"])

        # CI if available
        if show_ci and ci_l and ci_r and peaks_df is not None and (ci_l in peaks_df.columns) and (ci_r in peaks_df.columns):
            try:
                l0 = float(top_peak[ci_l])
                r0 = float(top_peak[ci_r])
                if np.isfinite(l0) and np.isfinite(r0):
                    zmin, zmax = min(l0, r0), max(l0, r0)
                else:
                    raise ValueError("non-finite")
            except Exception:
                zmin, zmax = (p0 - zoom_window / 2.0), (p0 + zoom_window / 2.0)
        else:
            zmin, zmax = (p0 - zoom_window / 2.0), (p0 + zoom_window / 2.0)

        sub = lod_df[(lod_df["chr"].astype(str) == c0) & (lod_df["pos"] >= zmin) & (lod_df["pos"] <= zmax)].copy()
        if sub.empty:
            sub = lod_df[lod_df["chr"].astype(str) == c0].copy()

        fig.add_trace(
            go.Scatter(
                x=sub["pos"],
                y=sub["lod"],
                mode="lines",
                line=dict(width=lod_line_width),
                name=f"LOD (chr {c0})",
                showlegend=False,
                hovertemplate="chr=%{customdata[0]}<br>pos=%{x:" + pos_fmt + "} " + pos_unit + "<br>LOD=%{y:.3f}<extra></extra>",
                customdata=np.stack([sub["chr"].values], axis=1),
            ),
            row=2,
            col=1,
        )

        # CI highlight (only if CI is being shown, otherwise a lighter zoom window highlight)
        if show_ci:
            fig.add_vrect(x0=zmin, x1=zmax, fillcolor="rgba(0,0,0,0.05)", line_width=0, row=2, col=1)

        # peak marker (+ optional label)
        mode = "markers+text" if show_peak_label else "markers"
        text = [f"Peak: chr{c0}:{p0:{pos_fmt}} {pos_unit}"] if show_peak_label else None
        fig.add_trace(
            go.Scatter(
                x=[p0],
                y=[float(top_peak["lod"])],
                mode=mode,
                text=text,
                textposition="top center",
                marker=dict(size=max(peak_marker_size, 10)),
                showlegend=False,
                hovertemplate="PEAK<br>chr=%{customdata[0]}<br>pos=%{x:" + pos_fmt + "} " + pos_unit + "<br>LOD=%{y:.3f}<extra></extra>",
                customdata=np.array([[c0]]),
            ),
            row=2,
            col=1,
        )
        fig.update_xaxes(row=2, col=1, title_text=f"Position ({pos_unit})")
        fig.update_yaxes(row=2, col=1, title_text="LOD")
    else:
        fig.update_xaxes(row=2, col=1, title_text=f"Position ({pos_unit})")
        fig.update_yaxes(row=2, col=1, title_text="LOD")

    fig.update_layout(
        title=title,
        hovermode="closest",
        margin=margin,
        height=height,
        font=dict(family=font_family, size=font_size, color=font_color),
        plot_bgcolor=plot_bgcolor,
        paper_bgcolor=paper_bgcolor,
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="left", x=0.0),
    )
    return fig


def make_qtl_scan_plotly(
    lod_profile_tsv: Path,
    peaks_tsv: Path | None,
    perm_thresholds_tsv: Path | None,
    out_html: Path,
    *,
    title: str = "QTL LOD profile",
    pos_unit: str = "cM",
    zoom_window: float = 20.0,
    style: dict | None = None,
) -> bool:
    """Create a publication-style QTL scan plot (genome-wide + peak zoom) in Plotly and save as HTML."""
    go, pio, _qual = _try_import_plotly()
    if go is None or pio is None:
        return False

    fig = build_qtl_scan_figure(
        lod_profile_tsv=lod_profile_tsv,
        peaks_tsv=peaks_tsv,
        perm_thresholds_tsv=perm_thresholds_tsv,
        title=title,
        pos_unit=pos_unit,
        zoom_window=zoom_window,
        style=style,
    )
    if fig is None:
        return False

    out_html.parent.mkdir(parents=True, exist_ok=True)
    html = _plotly_html(fig, pio, add_selection_js=False)
    out_html.write_text(html, encoding="utf-8")
    return True

def read_tsv_header_cols(path: str) -> list[str]:
    cols = pd.read_csv(path, sep="\t", nrows=0).columns.tolist()
    return [str(c) for c in cols]





def build_linkage_map_figure(
    map_markers_tsv: Path,
    map_lengths_tsv: Path | None = None,
    *,
    title: str = "Linkage map",
    pos_unit: str = "cM",
    style: dict | None = None,
) -> "go.Figure" | None:
    """Create a publication-quality linkage map stick plot (Plotly).

    Expected inputs
      - map_markers_tsv: marker table (TSV). Columns may vary; we try to standardize to:
          lg, marker, pos
      - map_lengths_tsv (optional): LG length table (TSV) with columns like lg,length

    Style keys (Phase2)
      - lg_spacing (float)
      - axis_pad (float fraction)
      - show_grid (bool)
      - color_by (bool), color_col (str "(auto)" or column name), show_legend (bool)
      - show_density (bool), density_bin/width/alpha/side, density_color
      - highlight_markers_enabled (bool), highlight_markers (text)
      - highlight_regions_enabled (bool), highlight_regions (text LG:start-end)
      - highlight_color, highlight_marker_size, highlight_band_width, highlight_alpha
      - label_highlights (bool)

    Existing style keys (Phase1)
      - orientation, lg_order, bin_size, label_mode, label_gap, label_list
      - marker_size, line_width, font_family, font_size, font_color
      - plot_bgcolor, paper_bgcolor, margin, height
    """
    go, pio, qualitative = _try_import_plotly()
    if go is None or pio is None:
        return None

    import re

    style = style or {}

    # Orientation can be either the full UI label (e.g. "Vertical (LG on X)")
    # or a short keyword ("vertical"/"horizontal"). Be robust/case-insensitive.
    orientation_raw = str(style.get("orientation", "Vertical (LG on X)") or "").strip().lower()
    if ("horiz" in orientation_raw) or ("lg on y" in orientation_raw) or (orientation_raw in {"h", "horizontal"}):
        orientation = "horizontal"
    elif ("vert" in orientation_raw) or ("lg on x" in orientation_raw) or (orientation_raw in {"v", "vertical"}):
        orientation = "vertical"
    else:
        orientation = "vertical"

    lg_order = str(style.get("lg_order", "Input"))
    bin_size = float(style.get("bin_size", 0.0) or 0.0)

    label_mode = str(style.get("label_mode", "spaced"))
    label_gap = float(style.get("label_gap", 5.0) or 5.0)
    label_list_text = str(style.get("label_list", ""))

    marker_size = float(style.get("marker_size", 3.5) or 3.5)
    line_width = float(style.get("line_width", 2.0) or 2.0)

    font_family = str(style.get("font_family", "Arial"))
    font_size = int(style.get("font_size", 12) or 12)
    font_color = str(style.get("font_color", "#222222"))

    plot_bgcolor = str(style.get("plot_bgcolor", "#ffffff"))
    paper_bgcolor = str(style.get("paper_bgcolor", "#ffffff"))

    # Margin keys are aligned with other plots (margin_l/r/t/b), but accept legacy m_* too.
    margin = dict(
        l=int(style.get("margin_l", style.get("m_l", 60)) or 60),
        r=int(style.get("margin_r", style.get("m_r", 40)) or 40),
        t=int(style.get("margin_t", style.get("m_t", 60)) or 60),
        b=int(style.get("margin_b", style.get("m_b", 60)) or 60),
    )
    height = int(style.get("height", 900) or 900)
    export_width = int(style.get("export_width", 1400) or 1400)

    # Phase2
    lg_spacing = float(style.get("lg_spacing", 1.0) or 1.0)
    axis_pad = float(style.get("axis_pad", 0.05) or 0.05)
    show_grid = bool(style.get("show_grid", True))

    color_by = bool(style.get("color_by", False))
    color_col = str(style.get("color_col", "(auto)") or "(auto)")
    show_legend = bool(style.get("show_legend", True))

    show_density = bool(style.get("show_density", False))
    density_bin = float(style.get("density_bin", 2.0) or 2.0)
    density_width = float(style.get("density_width", 0.22) or 0.22)
    density_alpha = float(style.get("density_alpha", 0.35) or 0.35)
    density_side = str(style.get("density_side", "left") or "left")
    density_color = str(style.get("density_color", font_color) or font_color)
    density_style_raw = str(style.get("density_style", "heat band") or "heat band")
    density_colorbar = bool(style.get("density_colorbar", False))

    hl_markers_enabled = bool(style.get("highlight_markers_enabled", False))
    hl_markers_text = str(style.get("highlight_markers", "") or "")
    hl_regions_enabled = bool(style.get("highlight_regions_enabled", False))
    hl_regions_text = str(style.get("highlight_regions", "") or "")
    hl_color = str(style.get("highlight_color", "#d62728") or "#d62728")
    hl_marker_size = float(style.get("highlight_marker_size", max(6.0, marker_size * 1.8)) or max(6.0, marker_size * 1.8))
    hl_band_width = float(style.get("highlight_band_width", 0.35) or 0.35)
    hl_alpha = float(style.get("highlight_alpha", 0.15) or 0.15)
    label_highlights = bool(style.get("label_highlights", True))

    # Phase3
    smart_labels = bool(style.get("smart_labels", True))
    label_min_px = int(style.get("label_min_px", max(10, int(font_size * 1.0))) or max(10, int(font_size * 1.0)))
    label_leaders = bool(style.get("label_leaders", True))
    jitter_markers = bool(style.get("jitter_markers", True))
    jitter_strength = float(style.get("jitter_strength", 0.18) or 0.18)
    lg_title_mode_raw = str(style.get("lg_title_mode", "axis ticks") or "axis ticks")
    lg_title_offset = int(style.get("lg_title_offset", 16) or 16)

    def _split_tokens(s: str) -> list[str]:
        toks = re.split(r"[\s,;]+", (s or "").strip())
        return [t for t in toks if t]

    def _parse_regions(s: str) -> list[tuple[str, float, float]]:
        regs: list[tuple[str, float, float]] = []
        # split by newline / semicolon into region specs
        for raw in re.split(r"[\n;]+", (s or "").strip()):
            raw = raw.strip()
            if not raw:
                continue
            for part in re.split(r"[,]+", raw):
                part = part.strip()
                if not part or ":" not in part:
                    continue
                lg, rr = part.split(":", 1)
                lg = lg.strip()
                rr = rr.strip().replace("..", "-")
                if not lg or not rr:
                    continue
                if "-" in rr:
                    a, b = rr.split("-", 1)
                    try:
                        x0 = float(a)
                        x1 = float(b)
                    except Exception:
                        continue
                else:
                    try:
                        x0 = float(rr)
                        x1 = float(rr)
                    except Exception:
                        continue
                if x1 < x0:
                    x0, x1 = x1, x0
                regs.append((lg, x0, x1))
        return regs

    def _hex_to_rgb(hex_color: str) -> tuple[int, int, int]:
        hc = (hex_color or "").strip()
        if not hc:
            hc = "#000000"
        if hc.startswith("rgba"):
            m = re.search(r"rgba\((\d+),(\d+),(\d+)", hc)
            if m:
                return int(m.group(1)), int(m.group(2)), int(m.group(3))
            return (0, 0, 0)
        if hc.startswith("rgb"):
            m = re.search(r"rgb\((\d+),(\d+),(\d+)", hc)
            if m:
                return int(m.group(1)), int(m.group(2)), int(m.group(3))
            return (0, 0, 0)
        hc = hc.lstrip("#")
        if len(hc) == 3:
            hc = "".join([c + c for c in hc])
        if len(hc) != 6:
            return (0, 0, 0)
        return int(hc[0:2], 16), int(hc[2:4], 16), int(hc[4:6], 16)

    def _rgba(hex_color: str, alpha: float) -> str:
        r, g, b = _hex_to_rgb(hex_color)
        a = max(0.0, min(1.0, float(alpha)))
        return f"rgba({r},{g},{b},{a})"

    # ---- read and standardize marker table ----
    df_raw = pd.read_csv(map_markers_tsv, sep="	")
    df0 = _standardize_map_markers_df(df_raw)
    if df0 is None or df0.empty:
        return None

    # Infer scaling (bp -> Mb if needed)
    try:
        med = float(np.nanmedian(df0["pos"].astype(float).values))
    except Exception:
        med = 0.0
    scale_factor = 1.0
    if pos_unit.lower() in {"mb", "megabase", "megabases"}:
        if med > 1e6:
            scale_factor = 1e-6
        elif med > 1e4:
            scale_factor = 1e-3

    df = df0.copy()
    df["pos"] = pd.to_numeric(df["pos"], errors="coerce")
    df = df.dropna(subset=["pos"]).copy()
    if scale_factor != 1.0:
        df["pos"] = df["pos"].astype(float) * scale_factor

    df["lg"] = df["lg"].astype(str)
    df["marker"] = df["marker"].astype(str)

    # ---- determine LG lengths ----
    lengths: dict[str, float] = {}
    if map_lengths_tsv is not None and Path(map_lengths_tsv).exists():
        try:
            ldf = pd.read_csv(map_lengths_tsv, sep="	")
            lstd = _standardize_map_lengths_df(ldf)
            if lstd is not None and not lstd.empty:
                for _, rr in lstd.iterrows():
                    lengths[str(rr["lg"])] = float(rr["length"]) * scale_factor
        except Exception:
            lengths = {}

    if not lengths:
        for lg, g in df.groupby("lg"):
            lengths[str(lg)] = float(np.nanmax(g["pos"].astype(float).values)) if len(g) else 0.0

    # ---- LG order ----
    lg_list = list(pd.unique(df["lg"]))
    if lg_order == "Natural":
        try:
            def _key(x: str):
                m = re.search(r"(\d+)", str(x))
                return (int(m.group(1)) if m else 10**12, str(x))
            lg_list = sorted(lg_list, key=_key)
        except Exception:
            pass
    elif lg_order == "Length desc":
        lg_list = sorted(lg_list, key=lambda x: -float(lengths.get(str(x), 0.0)))

    lg_to_axis = {str(lg): float(i) * lg_spacing for i, lg in enumerate(lg_list)}

    # axis range in map units
    max_len = max([float(lengths.get(str(lg), 0.0) or 0.0) for lg in lg_list] or [0.0])
    pos_range = [0.0, max_len * (1.0 + axis_pad) if max_len > 0 else 1.0]

    # ---- decimate markers for display (bin by position) ----
    df_plot = df
    if bin_size and bin_size > 0:
        try:
            grp = (df[["lg", "marker", "pos"]]
                   .assign(_bin=(df["pos"] / bin_size).round().astype(int))
                   .sort_values(["lg", "pos"]))
            df_plot = grp.groupby(["lg", "_bin"], as_index=False).first()
        except Exception:
            df_plot = df

    # ---- label selection ----
    label_df = None
    if label_mode == "spaced":
        if label_gap <= 0:
            label_gap = 5.0
        try:
            rows = []
            for lg in lg_list:
                g = df_plot[df_plot["lg"] == lg].sort_values("pos")
                last = None
                for _, rr in g.iterrows():
                    if last is None or float(rr["pos"]) - float(last) >= label_gap:
                        rows.append(rr)
                        last = float(rr["pos"])
            label_df = pd.DataFrame(rows) if rows else None
        except Exception:
            label_df = None
    elif label_mode == "list":
        wanted = set(_split_tokens(label_list_text))
        if wanted:
            label_df = df[df["marker"].astype(str).isin(wanted)].copy()

    # ---- coloring by group column ----
    group_col_resolved: str | None = None
    if color_by:
        if color_col and color_col != "(auto)":
            if color_col in df_plot.columns:
                group_col_resolved = color_col
            else:
                low = {c.lower(): c for c in df_plot.columns}
                if color_col.lower() in low:
                    group_col_resolved = low[color_col.lower()]
        if group_col_resolved is None:
            cands = ["set", "parent", "sex", "phase", "source", "type", "population", "pop", "origin", "subset", "component", "map"]
            low = {c.lower(): c for c in df_plot.columns}
            for c in cands:
                if c in low:
                    group_col_resolved = low[c]
                    break

    if group_col_resolved is not None and group_col_resolved in df_plot.columns:
        df_plot = df_plot.copy()
        df_plot["__grp"] = df_plot[group_col_resolved].astype(str).fillna("NA")
        df_full = df.copy()
        if group_col_resolved in df_full.columns:
            df_full["__grp"] = df_full[group_col_resolved].astype(str).fillna("NA")
        else:
            df_full["__grp"] = "NA"
    else:
        df_full = df.copy()

    # ---- Phase3: canonicalize option labels ----
    density_style = "heat" if "heat" in str(density_style_raw).lower() else "alpha"
    lg_title_mode = "axis"
    lgt = str(lg_title_mode_raw).lower()
    if "top" in lgt or "right" in lgt:
        lg_title_mode = "far"
    elif "bottom" in lgt or "left" in lgt:
        lg_title_mode = "near"

    # ---- Phase3: jitter markers at the same position ----
    if jitter_markers and jitter_strength > 0:
        try:
            span = float(jitter_strength) * float(lg_spacing)
            def _add_jitter(dfin: pd.DataFrame) -> pd.DataFrame:
                if dfin is None or dfin.empty:
                    return dfin
                dfj = dfin.copy()
                dfj["__pos_round"] = dfj["pos"].astype(float).round(6)
                m: dict = {}
                for (_, _), sub in dfj.groupby(["lg", "__pos_round"], sort=False):
                    if len(sub) <= 1:
                        continue
                    sub2 = sub.sort_values("marker")
                    offs = np.linspace(-span / 2.0, span / 2.0, len(sub2))
                    for off, idx in zip(offs, list(sub2.index)):
                        m[idx] = float(off)
                dfj["__jit"] = [float(m.get(idx, 0.0)) for idx in dfj.index]
                return dfj
            df_plot = _add_jitter(df_plot)
            df_full = _add_jitter(df_full)
        except Exception:
            try:
                df_plot = df_plot.copy(); df_plot["__jit"] = 0.0
                df_full = df_full.copy(); df_full["__jit"] = 0.0
            except Exception:
                pass
    else:
        try:
            df_plot = df_plot.copy(); df_plot["__jit"] = 0.0
            df_full = df_full.copy(); df_full["__jit"] = 0.0
        except Exception:
            pass

    # ---- build figure ----
    fig = go.Figure()
    shapes: list[dict] = []

    # highlight regions (below)
    if hl_regions_enabled and hl_regions_text.strip():
        for lg, a, b in _parse_regions(hl_regions_text):
            lg_key = None
            if lg in lg_to_axis:
                lg_key = lg
            else:
                s = str(lg)
                for cand in lg_to_axis.keys():
                    if str(cand) == s or str(cand).lower() == s.lower():
                        lg_key = cand
                        break
            if lg_key is None:
                continue
            i = float(lg_to_axis.get(lg_key, 0.0))
            if orientation == "vertical":
                x0, x1 = i - hl_band_width / 2.0, i + hl_band_width / 2.0
                y0, y1 = a, b
            else:
                x0, x1 = a, b
                y0, y1 = i - hl_band_width / 2.0, i + hl_band_width / 2.0
            shapes.append(dict(type="rect", x0=x0, x1=x1, y0=y0, y1=y1, xref="x", yref="y",
                               fillcolor=_rgba(hl_color, hl_alpha), line=dict(width=0), layer="below"))

    # density track (below)
    if show_density and density_bin > 0:
        max_cnt = 0
        per_lg_bins: dict[str, dict[int, int]] = {}
        for lg in lg_list:
            g = df_full[df_full["lg"] == lg]
            if g.empty:
                continue
            idx = (g["pos"] // density_bin).astype(int)
            cnts = idx.value_counts().to_dict()
            per_lg_bins[lg] = {int(k): int(v) for k, v in cnts.items()}
            if cnts:
                max_cnt = max(max_cnt, int(max(cnts.values())))
        max_cnt = max(1, max_cnt)

        if density_style == "heat":
            hx: list[float] = []
            hy: list[float] = []
            hc: list[float] = []
            for lg in lg_list:
                bins = per_lg_bins.get(lg)
                if not bins:
                    continue
                i = float(lg_to_axis.get(lg, 0.0))
                L = float(lengths.get(lg, 0.0) or 0.0)
                for bi, cnt in bins.items():
                    p0 = float(bi) * density_bin
                    p1 = min(L, p0 + density_bin)
                    if p1 <= p0:
                        continue
                    cen = 0.5 * (p0 + p1)
                    if orientation == "vertical":
                        xx = i - 0.5 * density_width if density_side == "left" else i + 0.5 * density_width
                        hx.append(float(xx))
                        hy.append(float(cen))
                    else:
                        yy = i - 0.5 * density_width if density_side == "left" else i + 0.5 * density_width
                        hx.append(float(cen))
                        hy.append(float(yy))
                    hc.append(float(cnt))
            if hx:
                ms = int(max(6, min(40, 70 * float(density_width))))
                cb = dict(title="density", thickness=12, len=0.55) if density_colorbar else None
                fig.add_trace(go.Scatter(
                    x=hx, y=hy, mode="markers",
                    marker=dict(
                        symbol="square",
                        size=ms,
                        color=hc,
                        colorscale="Viridis",
                        cmin=0,
                        cmax=float(max_cnt),
                        showscale=bool(density_colorbar),
                        colorbar=cb,
                        line=dict(width=0),
                    ),
                    opacity=min(1.0, max(0.1, 0.65 + 0.35 * float(density_alpha))),
                    showlegend=False,
                    hoverinfo="skip",
                ))
        else:
            for lg in lg_list:
                bins = per_lg_bins.get(lg)
                if not bins:
                    continue
                i = float(lg_to_axis.get(lg, 0.0))
                L = float(lengths.get(lg, 0.0) or 0.0)
                for bi, cnt in bins.items():
                    p0 = float(bi) * density_bin
                    p1 = min(L, p0 + density_bin)
                    if p1 <= p0:
                        continue
                    a = density_alpha * (float(cnt) / float(max_cnt))
                    if a <= 0:
                        continue
                    if orientation == "vertical":
                        if density_side == "left":
                            x0, x1 = i - density_width, i
                        else:
                            x0, x1 = i, i + density_width
                        shapes.append(dict(type="rect", x0=x0, x1=x1, y0=p0, y1=p1, xref="x", yref="y",
                                           fillcolor=_rgba(density_color, a), line=dict(width=0), layer="below"))
                    else:
                        if density_side == "left":
                            yy0, yy1 = i - density_width, i
                        else:
                            yy0, yy1 = i, i + density_width
                        shapes.append(dict(type="rect", x0=p0, x1=p1, y0=yy0, y1=yy1, xref="x", yref="y",
                                           fillcolor=_rgba(density_color, a), line=dict(width=0), layer="below"))

    # backbone lines (above)
    for lg in lg_list:
        i = float(lg_to_axis.get(lg, 0.0))
        L = float(lengths.get(lg, 0.0) or 0.0)
        if orientation == "vertical":
            shapes.append(dict(type="line", x0=i, x1=i, y0=0, y1=L, xref="x", yref="y",
                               line=dict(color=font_color, width=line_width), layer="above"))
        else:
            shapes.append(dict(type="line", x0=0, x1=L, y0=i, y1=i, xref="x", yref="y",
                               line=dict(color=font_color, width=line_width), layer="above"))

    fig.update_layout(shapes=shapes)

    def _coords(dfi: pd.DataFrame) -> tuple[list[float], list[float]]:
        xs: list[float] = []
        ys: list[float] = []
        if orientation == "vertical":
            for _, rr in dfi.iterrows():
                xs.append(float(lg_to_axis.get(str(rr["lg"]), 0.0)) + float(rr.get("__jit", 0.0) or 0.0))
                ys.append(float(rr["pos"]))
        else:
            for _, rr in dfi.iterrows():
                xs.append(float(rr["pos"]))
                ys.append(float(lg_to_axis.get(str(rr["lg"]), 0.0)) + float(rr.get("__jit", 0.0) or 0.0))
        return xs, ys

    # marker points
    if group_col_resolved is not None and "__grp" in df_plot.columns:
        pal = []
        try:
            pal = list(getattr(qualitative, "Plotly", []))
        except Exception:
            pal = []
        if not pal:
            pal = ["#1f77b4", "#ff7f0e", "#2ca02c", "#d62728", "#9467bd", "#8c564b", "#e377c2", "#7f7f7f", "#bcbd22", "#17becf"]

        groups = list(pd.unique(df_plot["__grp"]))
        for gi, gname in enumerate(groups):
            gdf = df_plot[df_plot["__grp"] == gname]
            x, y = _coords(gdf)
            custom = np.column_stack([
                gdf["marker"].astype(str).values,
                gdf["lg"].astype(str).values,
                gdf["pos"].astype(float).values,
                gdf["__grp"].astype(str).values,
            ])
            col = pal[gi % len(pal)]
            fig.add_trace(go.Scatter(
                x=x, y=y, mode="markers",
                marker=dict(size=marker_size, color=col, opacity=0.95),
                name=str(gname), showlegend=show_legend,
                customdata=custom,
                hovertemplate=(
                    "LG: %{customdata[1]}<br>Marker: %{customdata[0]}<br>Pos: %{customdata[2]:." + str(_infer_pos_decimals(df_plot["pos"], pos_unit)) + "f} " + pos_unit +
                    "<br>" + str(group_col_resolved) + ": %{customdata[3]}<extra></extra>"
                ),
            ))
    else:
        x, y = _coords(df_plot)
        custom = np.column_stack([
            df_plot["marker"].astype(str).values,
            df_plot["lg"].astype(str).values,
            df_plot["pos"].astype(float).values,
        ])
        fig.add_trace(go.Scatter(
            x=x, y=y, mode="markers",
            marker=dict(size=marker_size, color=font_color, opacity=0.95),
            showlegend=False,
            customdata=custom,
            hovertemplate=(
                "LG: %{customdata[1]}<br>Marker: %{customdata[0]}<br>Pos: %{customdata[2]:." + str(_infer_pos_decimals(df_plot["pos"], pos_unit)) + "f} " + pos_unit +
                "<extra></extra>"
            ),
        ))

    # highlighted markers overlay
    if hl_markers_enabled and hl_markers_text.strip():
        wanted = set(_split_tokens(hl_markers_text))
        if wanted:
            hdf = df_full[df_full["marker"].astype(str).isin(wanted)].copy()
            if not hdf.empty:
                xh, yh = _coords(hdf)
                mode = "markers"
                text_labels = None
                if label_highlights and len(hdf) <= 120:
                    mode = "markers+text"
                    text_labels = hdf["marker"].astype(str).tolist()
                custom_h = np.column_stack([
                    hdf["marker"].astype(str).values,
                    hdf["lg"].astype(str).values,
                    hdf["pos"].astype(float).values,
                ])
                fig.add_trace(go.Scatter(
                    x=xh, y=yh, mode=mode,
                    marker=dict(size=hl_marker_size, color=hl_color, symbol="diamond", opacity=0.98),
                    text=text_labels,
                    textfont=dict(family=font_family, size=max(8, int(font_size * 0.85)), color=hl_color),
                    textposition="middle right" if orientation == "vertical" else "top center",
                    showlegend=False,
                    customdata=custom_h,
                    hovertemplate=(
                        "LG: %{customdata[1]}<br>Marker: %{customdata[0]}<br>Pos: %{customdata[2]:." + str(_infer_pos_decimals(df_plot["pos"], pos_unit)) + "f} " + pos_unit +
                        "<extra></extra>"
                    ),
                ))

    # labels (text)
    if label_df is not None and not label_df.empty:
        label_offset = 0.12 * lg_spacing
        if show_density and density_side == "right":
            label_offset += density_width
        if show_density and density_side == "left":
            label_offset += 0.02

        # minimum separation in map units from pixel requirement
        try:
            plot_h_px = max(200, int(height) - int(margin.get("t", 0)) - int(margin.get("b", 0)))
            plot_w_px = max(300, int(export_width) - int(margin.get("l", 0)) - int(margin.get("r", 0)))
        except Exception:
            plot_h_px, plot_w_px = 800, 1200

        span_units = float(pos_range[1]) - float(pos_range[0])
        if span_units <= 0:
            span_units = 1.0
        units_per_px = span_units / float(plot_h_px if orientation == "vertical" else plot_w_px)
        min_sep = max(float(label_gap), float(units_per_px) * float(max(6, int(label_min_px))))

        def _spread_1d(vals: list[float], *, min_sep: float, low: float, high: float) -> list[float]:
            if not vals:
                return []
            v = [float(x) for x in vals]
            out: list[float] = []
            for x in v:
                if not out:
                    out.append(max(low, x))
                else:
                    out.append(max(x, out[-1] + min_sep))
            # fit to high by shifting down if needed
            if out and out[-1] > high:
                shift = out[-1] - high
                out = [y - shift for y in out]
                # backward pass to enforce min_sep and clamp low
                for k in range(len(out) - 2, -1, -1):
                    out[k] = min(out[k], out[k + 1] - min_sep)
                if out[0] < low:
                    up = low - out[0]
                    out = [y + up for y in out]
            # final clamp
            out = [min(max(low, y), high) for y in out]
            return out

        xl: list[float] = []
        yl: list[float] = []
        tl: list[str] = []
        lx: list[float] = []
        ly: list[float] = []

        # per-LG smart spreading along the position axis
        for lg in lg_list:
            g = label_df[label_df["lg"].astype(str) == str(lg)].sort_values("pos")
            if g.empty:
                continue
            i = float(lg_to_axis.get(str(lg), 0.0))
            L = float(lengths.get(str(lg), 0.0) or 0.0)
            if L <= 0:
                L = float(pos_range[1])
            targets = [float(x) for x in g["pos"].astype(float).tolist()]
            adj = targets
            if smart_labels and len(targets) >= 2:
                adj = _spread_1d(targets, min_sep=min_sep, low=0.0, high=float(L))
            for (idx, rr), a in zip(g.iterrows(), adj):
                pos0 = float(rr["pos"])
                txt = str(rr["marker"])
                if orientation == "vertical":
                    xl.append(i + label_offset)
                    yl.append(float(a))
                    if label_leaders and smart_labels and abs(float(a) - pos0) > 1e-9:
                        lx += [i, i + label_offset * 0.88, None]
                        ly += [pos0, float(a), None]
                else:
                    xl.append(float(a))
                    yl.append(i + label_offset)
                    if label_leaders and smart_labels and abs(float(a) - pos0) > 1e-9:
                        lx += [pos0, float(a), None]
                        ly += [i, i + label_offset * 0.88, None]
                tl.append(txt)

        if label_leaders and smart_labels and lx:
            fig.add_trace(go.Scatter(
                x=lx, y=ly, mode="lines",
                line=dict(color=font_color, width=max(1, int(round(line_width * 0.6)))),
                showlegend=False,
                hoverinfo="skip",
            ))

        if xl:
            fig.add_trace(go.Scatter(
                x=xl, y=yl, mode="text", text=tl,
                textfont=dict(family=font_family, size=max(8, int(font_size * 0.85)), color=font_color),
                textposition="middle right" if orientation == "vertical" else "top center",
                showlegend=False,
                hoverinfo="skip",
            ))

    # axes
    tickvals = [float(lg_to_axis.get(lg, 0.0)) for lg in lg_list]
    ticktext = [str(lg) for lg in lg_list]

    lg_min = min(tickvals) if tickvals else 0.0
    lg_max = max(tickvals) if tickvals else 0.0
    extra = 0.6 * lg_spacing
    if show_density and density_side == "right":
        extra += density_width

    if orientation == "vertical":
        fig.update_xaxes(tickmode="array", tickvals=tickvals, ticktext=ticktext, title_text="Linkage group",
                         showgrid=False, zeroline=False,
                         range=[lg_min - 0.7 * lg_spacing, lg_max + extra + 0.3 * lg_spacing])
        fig.update_yaxes(title_text=f"Position ({pos_unit})", showgrid=show_grid, zeroline=False, range=pos_range)
    else:
        fig.update_yaxes(tickmode="array", tickvals=tickvals, ticktext=ticktext, title_text="Linkage group",
                         showgrid=False, zeroline=False,
                         range=[lg_min - 0.7 * lg_spacing, lg_max + extra + 0.3 * lg_spacing])
        fig.update_xaxes(title_text=f"Position ({pos_unit})", showgrid=show_grid, zeroline=False, range=pos_range)

    # Phase3: LG title placement via annotations
    annotations: list[dict] = []
    if lg_title_mode in {"far", "near"}:
        if orientation == "vertical":
            fig.update_xaxes(showticklabels=False)
            yy = float(pos_range[1]) if lg_title_mode == "far" else float(pos_range[0])
            yshift = int(lg_title_offset) if lg_title_mode == "far" else -int(lg_title_offset)
            for lg, xv in zip(lg_list, tickvals):
                annotations.append(dict(
                    x=float(xv), y=yy,
                    xref="x", yref="y",
                    text=str(lg),
                    showarrow=False,
                    yshift=yshift,
                    font=dict(family=font_family, size=max(8, int(font_size * 0.9)), color=font_color),
                ))
        else:
            fig.update_yaxes(showticklabels=False)
            xx = float(pos_range[1]) if lg_title_mode == "far" else float(pos_range[0])
            xshift = int(lg_title_offset) if lg_title_mode == "far" else -int(lg_title_offset)
            for lg, yv in zip(lg_list, tickvals):
                annotations.append(dict(
                    x=xx, y=float(yv),
                    xref="x", yref="y",
                    text=str(lg),
                    showarrow=False,
                    xshift=xshift,
                    font=dict(family=font_family, size=max(8, int(font_size * 0.9)), color=font_color),
                ))

    fig.update_layout(
        title=dict(text=title, x=0.02, xanchor="left"),
        height=height,
        margin=margin,
        annotations=annotations,
        font=dict(family=font_family, size=font_size, color=font_color),
        plot_bgcolor=plot_bgcolor,
        paper_bgcolor=paper_bgcolor,
        legend=dict(title=str(group_col_resolved) if group_col_resolved else None),
    )

    return fig



class ResultsPane(QWidget):
    """Right side: table + plot (static PNG or interactive HTML) + interactive controls."""
    def __init__(self):
        super().__init__()
        self.table = QTableWidget()
        # Enable interactive sorting (we will also provide explicit sort/reset controls)
        try:
            self.table.setSortingEnabled(True)
            self.table.horizontalHeader().setSortIndicatorShown(True)
        except Exception:
            pass

        # Keep original/current ordering for reset
        self._table_df_original: pd.DataFrame | None = None
        self._table_df_current: pd.DataFrame | None = None

        # Table sort controls
        self.cmb_table_sort_col = QComboBox()
        self.cmb_table_sort_order = QComboBox()
        self.cmb_table_sort_order.addItems(["ascending", "descending"])
        self.btn_table_sort = QPushButton("Sort")
        self.btn_table_reset = QPushButton("Reset order")
        self.btn_table_sort.clicked.connect(lambda *args, **kwargs: self._apply_table_sort())
        self.btn_table_reset.clicked.connect(lambda *args, **kwargs: self._reset_table_sort())

        # ---- plot views ----
        self.plot_label = QLabel("plot will appear here")
        self.plot_label.setAlignment(Qt.AlignCenter)
        self.plot_label.setMinimumHeight(320)

        self.cb_interactive = QCheckBox("Interactive (Plotly)")
        self.cb_interactive.setChecked(True)

        self.btn_open_browser = QPushButton("Open plot in browser")
        self.btn_open_browser.clicked.connect(lambda *args, **kwargs: self._open_plot_in_browser())

        self.plot_stack = QStackedWidget()
        self.plot_stack.addWidget(self.plot_label)

        self._html_path: Path | None = None
        self._png_path: Path | None = None

        if _HAS_WEBENGINE and QWebEngineView is not None:
            self.web_view = QWebEngineView()
            # Reduce GPU/WebGL usage to avoid crashes (Skia OOM / context lost)
            try:
                if 'QWebEngineSettings' in globals() and QWebEngineSettings is not None:  # type: ignore
                    s = self.web_view.settings()
                    s.setAttribute(QWebEngineSettings.WebAttribute.WebGLEnabled, False)  # type: ignore
                    s.setAttribute(QWebEngineSettings.WebAttribute.Accelerated2dCanvasEnabled, False)  # type: ignore
                    s.setAttribute(QWebEngineSettings.WebAttribute.ScrollAnimatorEnabled, False)  # type: ignore
            except Exception:
                pass
            self.plot_stack.addWidget(self.web_view)
        else:
            self.web_view = None
            self.html_fallback = QPlainTextEdit()
            self.html_fallback.setReadOnly(True)
            self.html_fallback.setPlainText(
                "Interactive plot requires QtWebEngine.\n"
                "If you installed it, restart the app.\n"
                "Otherwise you can open the HTML in an external browser."
            )
            self.plot_stack.addWidget(self.html_fallback)

        self.cb_interactive.stateChanged.connect(lambda *args, **kwargs: self._update_plot_view(*args, **kwargs))

        # ---- interactive plot controls ----
        self._plot_df: pd.DataFrame | None = None
        self._plot_title: str = "Manhattan plot"
        self._plot_out_dir: Path | None = None
        self._plot_fig = None  # plotly figure, if available
        self._webengine_embed_primed = False

        self.gb_style = QGroupBox("Interactive plot controls")
        self.gb_style.setCheckable(True)
        self.gb_style.setChecked(True)

        # colors
        self.cmb_color_scheme = QComboBox()
        self.cmb_color_scheme.addItems(["palette", "alternating", "single"])
        self.cmb_palette = QComboBox()
        self.cmb_palette.addItems(["Plotly", "D3", "G10", "T10", "Alphabet", "Dark24", "Light24", "Set1", "Set2", "Pastel1", "Pastel2", "Safe", "Vivid"])
        self.btn_color_a = QPushButton("Color A")
        self.btn_color_b = QPushButton("Color B")
        self._color_a = QColor("#1f77b4")
        self._color_b = QColor("#ff7f0e")
        self._refresh_color_buttons()

        self.btn_color_a.clicked.connect(lambda: self._pick_color("a"))
        self.btn_color_b.clicked.connect(lambda: self._pick_color("b"))

        # points
        self.sp_point_size = QSpinBox(); self.sp_point_size.setRange(1, 30); self.sp_point_size.setValue(4)
        self.sp_opacity = QDoubleSpinBox(); self.sp_opacity.setRange(0.05, 1.0); self.sp_opacity.setSingleStep(0.05); self.sp_opacity.setValue(0.8)

        # labels
        self.cb_labels = QCheckBox("Annotate peak SNPs")
        self.cb_labels.setChecked(True)
        self.cmb_label_mode = QComboBox(); self.cmb_label_mode.addItems(["topn", "perchr"])
        self.sp_topn = QSpinBox(); self.sp_topn.setRange(0, 200); self.sp_topn.setValue(10)

        # thresholds
        self.cb_bonf = QCheckBox("Bonferroni")
        self.cb_bonf.setChecked(True)
        self.ds_bonf_alpha = QDoubleSpinBox(); self.ds_bonf_alpha.setDecimals(6); self.ds_bonf_alpha.setRange(1e-12, 1.0); self.ds_bonf_alpha.setSingleStep(0.01); self.ds_bonf_alpha.setValue(0.05)

        self.cb_fdr = QCheckBox("FDR")
        self.cb_fdr.setChecked(True)
        self.ds_fdr_q = QDoubleSpinBox(); self.ds_fdr_q.setDecimals(6); self.ds_fdr_q.setRange(1e-12, 1.0); self.ds_fdr_q.setSingleStep(0.01); self.ds_fdr_q.setValue(0.05)

        self.ed_custom_p = QLineEdit()
        self.ed_custom_p.setPlaceholderText("Custom p-value lines (comma/space separated), e.g. 1e-6,1e-8")

        # layout / export
        self.cmb_font = QComboBox(); self.cmb_font.addItems(["Arial", "Helvetica", "Times New Roman", "Courier New", "DejaVu Sans"])
        self.sp_font_size = QSpinBox(); self.sp_font_size.setRange(6, 48); self.sp_font_size.setValue(12)

        self.sp_m_l = QSpinBox(); self.sp_m_l.setRange(0, 300); self.sp_m_l.setValue(60)
        self.sp_m_r = QSpinBox(); self.sp_m_r.setRange(0, 300); self.sp_m_r.setValue(25)
        self.sp_m_t = QSpinBox(); self.sp_m_t.setRange(0, 300); self.sp_m_t.setValue(60)
        self.sp_m_b = QSpinBox(); self.sp_m_b.setRange(0, 300); self.sp_m_b.setValue(60)

        self.sp_export_w = QSpinBox(); self.sp_export_w.setRange(400, 6000); self.sp_export_w.setValue(1400)
        self.sp_export_h = QSpinBox(); self.sp_export_h.setRange(300, 6000); self.sp_export_h.setValue(800)

        self.btn_export_html = QPushButton("Export HTML")
        self.btn_export_png = QPushButton("Export PNG")
        self.btn_export_svg = QPushButton("Export SVG")
        self.btn_export_pdf = QPushButton("Export PDF")

        self.btn_export_html.clicked.connect(lambda *args, **kwargs: self._export_html())
        self.btn_export_png.clicked.connect(lambda: self._export_image("png"))
        self.btn_export_svg.clicked.connect(lambda: self._export_image("svg"))
        self.btn_export_pdf.clicked.connect(lambda: self._export_image("pdf"))

        # texts / backgrounds
        self.ed_plot_title = QLineEdit()
        self.ed_plot_title.setPlaceholderText("Plot title (optional)")
        self.ed_x_label = QLineEdit("Genomic position")
