        def _mk_metric_combo(default_key: str):
            cb = QComboBox()
            keys = ["gene_ratio", "count", "mlog10", "rich_factor", "set_size", "bg_ratio"]
            for k in keys:
                cb.addItem(k, k)
            idx = cb.findData(default_key)
            if idx >= 0:
                cb.setCurrentIndex(idx)
            return cb

        self.cmb_rnaseq_en_x_metric = _mk_metric_combo("gene_ratio")
        self.cmb_rnaseq_en_size_metric = _mk_metric_combo("count")
