    def _apply_map_style_preset(self, name: str):
        presets = {
            "Paper (journal)": dict(
                orientation="Vertical (LG on X)", lg_order="Input",
                bin_size=0.0, label_mode="spaced", label_gap=5.0,
                marker_size=3.5, line_width=2.0,
                font_family="Times New Roman", font_size=14, font_color="#000000",
                margin_l=80, margin_r=30, margin_t=90, margin_b=80,
                height=950,
                lg_spacing=1.0, axis_pad=0.05, show_grid=True,
                lg_title_mode="axis ticks", lg_title_offset=14,
                smart_labels=True, label_min_px=14, label_leaders=True,
                jitter_markers=True, jitter_strength=0.18,
                show_density=False, density_style="heat band", density_colorbar=False,
                plot_bgcolor="#ffffff", paper_bgcolor="#ffffff",
            ),
            "Paper (compact)": dict(
                orientation="Vertical (LG on X)", lg_order="Input",
                bin_size=0.0, label_mode="spaced", label_gap=7.0,
                marker_size=3.0, line_width=1.8,
                font_family="Times New Roman", font_size=12, font_color="#000000",
                margin_l=65, margin_r=25, margin_t=75, margin_b=65,
                height=850,
                lg_spacing=1.0, axis_pad=0.05, show_grid=True,
                lg_title_mode="axis ticks", lg_title_offset=12,
                smart_labels=True, label_min_px=12, label_leaders=True,
                jitter_markers=True, jitter_strength=0.18,
                show_density=False, density_style="heat band", density_colorbar=False,
                plot_bgcolor="#ffffff", paper_bgcolor="#ffffff",
            ),
            "Talk (large labels)": dict(
                orientation="Vertical (LG on X)", lg_order="Input",
                bin_size=0.0, label_mode="spaced", label_gap=12.0,
                marker_size=5.0, line_width=3.0,
                font_family="Arial", font_size=18, font_color="#000000",
                margin_l=80, margin_r=30, margin_t=90, margin_b=80,
                height=1100,
                lg_spacing=1.0, axis_pad=0.05, show_grid=True,
                lg_title_mode="top/right annotations", lg_title_offset=18,
                smart_labels=True, label_min_px=16, label_leaders=True,
                jitter_markers=True, jitter_strength=0.22,
                show_density=False, density_style="heat band", density_colorbar=False,
                plot_bgcolor="#ffffff", paper_bgcolor="#ffffff",
            ),
        }
        if name not in presets:
            return
        cfg = presets[name]

        widgets_to_block = [
            self.cmb_map_orientation, self.cmb_map_lg_order,
            self.ds_map_bin, self.cmb_map_label_mode, self.ds_map_label_gap,
            self.cb_map_smart_labels, self.sp_map_label_min_px, self.cb_map_label_leaders,
            self.ds_map_marker_size, self.ds_map_line_width,
            self.cb_map_jitter, self.ds_map_jitter_strength,
            self.cmb_map_font, self.sp_map_font_size,
            self.sp_map_m_l, self.sp_map_m_r, self.sp_map_m_t, self.sp_map_m_b,
            self.sp_map_height,
            self.ds_map_lg_spacing, self.ds_map_axis_pad, self.cb_map_show_grid,
            self.cmb_map_lg_title_mode, self.sp_map_lg_title_offset,
            self.cb_map_density, self.cmb_map_density_style, self.cb_map_density_colorbar,
        ]
        for w in widgets_to_block:
            try:
                w.blockSignals(True)
            except Exception:
                pass

        try:
            # geometry
            i = self.cmb_map_orientation.findText(str(cfg.get("orientation", "Vertical (LG on X)")))
            if i >= 0:
                self.cmb_map_orientation.setCurrentIndex(i)
            j = self.cmb_map_lg_order.findText(str(cfg.get("lg_order", "Input")))
            if j >= 0:
                self.cmb_map_lg_order.setCurrentIndex(j)

            self.ds_map_bin.setValue(float(cfg.get("bin_size", 0.0)))
            lm = str(cfg.get("label_mode", "spaced"))
            k = self.cmb_map_label_mode.findText(lm)
            if k >= 0:
                self.cmb_map_label_mode.setCurrentIndex(k)
            self.ds_map_label_gap.setValue(float(cfg.get("label_gap", 5.0)))

            # Phase3: label collision & jitter
            try:
                self.cb_map_smart_labels.setChecked(bool(cfg.get("smart_labels", True)))
            except Exception:
                pass
            try:
                self.sp_map_label_min_px.setValue(int(cfg.get("label_min_px", max(10, int(cfg.get("font_size", 12))))) )
            except Exception:
                pass
            try:
                self.cb_map_label_leaders.setChecked(bool(cfg.get("label_leaders", True)))
            except Exception:
                pass
            try:
                self.cb_map_jitter.setChecked(bool(cfg.get("jitter_markers", True)))
            except Exception:
                pass
            try:
                self.ds_map_jitter_strength.setValue(float(cfg.get("jitter_strength", 0.18)))
            except Exception:
                pass

            self.ds_map_marker_size.setValue(float(cfg.get("marker_size", 3.5)))
            self.ds_map_line_width.setValue(float(cfg.get("line_width", 2.0)))

            # spacing / axis
            self.ds_map_lg_spacing.setValue(float(cfg.get("lg_spacing", 1.0)))
            self.ds_map_axis_pad.setValue(float(cfg.get("axis_pad", 0.05)))
            try:
                self.cb_map_show_grid.setChecked(bool(cfg.get("show_grid", True)))
            except Exception:
                pass

            # Phase3: LG title placement
            try:
                tmode = str(cfg.get("lg_title_mode", "axis ticks"))
                ii = self.cmb_map_lg_title_mode.findText(tmode)
                if ii >= 0:
                    self.cmb_map_lg_title_mode.setCurrentIndex(ii)
            except Exception:
                pass
            try:
                self.sp_map_lg_title_offset.setValue(int(cfg.get("lg_title_offset", 14)))
            except Exception:
                pass

            # Phase3: density style presets
            try:
                self.cb_map_density.setChecked(bool(cfg.get("show_density", False)))
            except Exception:
                pass
            try:
                ds = str(cfg.get("density_style", "heat band"))
                di = self.cmb_map_density_style.findText(ds)
                if di >= 0:
                    self.cmb_map_density_style.setCurrentIndex(di)
            except Exception:
                pass
            try:
                self.cb_map_density_colorbar.setChecked(bool(cfg.get("density_colorbar", False)))
            except Exception:
                pass

            # fonts / colors
            fam = str(cfg.get("font_family", "Arial"))
            m = self.cmb_map_font.findText(fam)
            if m >= 0:
                self.cmb_map_font.setCurrentIndex(m)
            self.sp_map_font_size.setValue(int(cfg.get("font_size", 12)))
            self._map_font_color = QColor(str(cfg.get("font_color", "#000000")))
            self._map_bg_plot = QColor(str(cfg.get("plot_bgcolor", "#ffffff")))
            self._map_bg_paper = QColor(str(cfg.get("paper_bgcolor", "#ffffff")))
            self._refresh_map_style_buttons()

            # margins / height
            self.sp_map_m_l.setValue(int(cfg.get("margin_l", 70)))
            self.sp_map_m_r.setValue(int(cfg.get("margin_r", 25)))
            self.sp_map_m_t.setValue(int(cfg.get("margin_t", 60)))
            self.sp_map_m_b.setValue(int(cfg.get("margin_b", 70)))
            self.sp_map_height.setValue(int(cfg.get("height", 900)))
        finally:
            for w in widgets_to_block:
                try:
                    w.blockSignals(False)
                except Exception:
                    pass

        self._rebuild_map_plotly()

    def _collect_map_plot_settings(self) -> dict:
        orientation = "vertical" if "Vertical" in self.cmb_map_orientation.currentText() else "horizontal"
        lg_order = self.cmb_map_lg_order.currentText().strip()
        label_mode = self.cmb_map_label_mode.currentText().strip().lower()
        return dict(
            orientation=orientation,
            lg_order=lg_order,
            bin_size=float(self.ds_map_bin.value()),
            label_mode=label_mode,
            label_gap=float(self.ds_map_label_gap.value()),
            label_list=self.ed_map_label_list.toPlainText().strip(),
            smart_labels=bool(self.cb_map_smart_labels.isChecked()),
            label_min_px=int(self.sp_map_label_min_px.value()),
            label_leaders=bool(self.cb_map_label_leaders.isChecked()),
            marker_size=float(self.ds_map_marker_size.value()),
            line_width=float(self.ds_map_line_width.value()),
            jitter_markers=bool(self.cb_map_jitter.isChecked()),
            jitter_strength=float(self.ds_map_jitter_strength.value()),
            lg_spacing=float(self.ds_map_lg_spacing.value()),
            axis_pad=float(self.ds_map_axis_pad.value()),
            lg_title_mode=str(self.cmb_map_lg_title_mode.currentText()),
            lg_title_offset=int(self.sp_map_lg_title_offset.value()),
            show_grid=bool(self.cb_map_show_grid.isChecked()),
            color_by=bool(self.cb_map_color_by.isChecked()),
            color_col=str(self.cmb_map_color_col.currentText()),
            show_legend=bool(self.cb_map_color_legend.isChecked()),
            show_density=bool(self.cb_map_density.isChecked()),
            density_style=str(self.cmb_map_density_style.currentText()),
            density_colorbar=bool(self.cb_map_density_colorbar.isChecked()),
            density_bin=float(self.ds_map_density_bin.value()),
            density_width=float(self.ds_map_density_width.value()),
            density_alpha=float(self.ds_map_density_alpha.value()),
            density_side=str(self.cmb_map_density_side.currentText()),
            density_color=self._map_density_color.name(),
            highlight_markers_enabled=bool(self.cb_map_highlight_markers.isChecked()),
            highlight_markers=str(self.ed_map_highlight_markers.toPlainText()),
            highlight_regions_enabled=bool(self.cb_map_highlight_regions.isChecked()),
            highlight_regions=str(self.ed_map_highlight_regions.toPlainText()),
            highlight_color=self._map_highlight_color.name(),
            highlight_marker_size=float(self.ds_map_highlight_marker_size.value()),
            highlight_band_width=float(self.ds_map_highlight_band_width.value()),
            highlight_alpha=float(self.ds_map_highlight_alpha.value()),
            label_highlights=bool(self.cb_map_label_highlights.isChecked()),
            font_family=self.cmb_map_font.currentText(),
            font_size=int(self.sp_map_font_size.value()),
            font_color=self._map_font_color.name(),
            plot_bgcolor=self._map_bg_plot.name(),
            paper_bgcolor=self._map_bg_paper.name(),
            margin_l=int(self.sp_map_m_l.value()),
            margin_r=int(self.sp_map_m_r.value()),
            margin_t=int(self.sp_map_m_t.value()),
            margin_b=int(self.sp_map_m_b.value()),
            height=int(self.sp_map_height.value()),
            export_width=int(self.sp_map_export_w.value()),
            export_height=int(self.sp_map_export_h.value()),
        )

    def set_map_plotly_context(
        self,
        map_markers_tsv: Path,
        map_lengths_tsv: Path | None,
        out_dir: Path,
        *,
        title: str = "Linkage map",
        pos_unit: str = "cM",
    ):
        """Enable Map style controls and show interactive linkage map."""
        self._plot_mode = "map"
        self._map_markers_tsv = Path(map_markers_tsv)
        self._map_lengths_tsv = Path(map_lengths_tsv) if map_lengths_tsv is not None else None
        self._map_out_dir = Path(out_dir)

        self._map_title = str(title)
        self._map_pos_unit = str(pos_unit)

        # Populate available columns for 'Color by column'
        try:
            cols: list[str] = []
            with open(self._map_markers_tsv, "r", encoding="utf-8", errors="ignore") as f:
                header = f.readline().rstrip("\n")
            if "\t" in header:
                cols = [c.strip() for c in header.split("\t") if c.strip()]
            else:
                cols = [c.strip() for c in header.split() if c.strip()]

            # update combobox while preserving selection when possible
            cur = self.cmb_map_color_col.currentText() if hasattr(self, "cmb_map_color_col") else "(auto)"
            self.cmb_map_color_col.blockSignals(True)
            self.cmb_map_color_col.clear()
            self.cmb_map_color_col.addItem("(auto)")
            for c in cols:
                if c in ("lg", "marker", "pos"):
                    continue
                self.cmb_map_color_col.addItem(c)
            if cur and self.cmb_map_color_col.findText(cur) >= 0:
                self.cmb_map_color_col.setCurrentText(cur)
            else:
                self.cmb_map_color_col.setCurrentIndex(0)
            self.cmb_map_color_col.blockSignals(False)
        except Exception:
            try:
                self.cmb_map_color_col.blockSignals(False)
            except Exception:
                pass

        # enable map controls; disable others

        try:
            self.gb_style.setEnabled(False)
            self.gb_qtl_style.setEnabled(False)
            self.gb_map_style.setEnabled(True)
        except Exception:
            pass
        try:
            self.set_style_panel("map", rebuild=False)
        except Exception:
            pass

        self._rebuild_map_plotly()

    def _rebuild_map_plotly(self, *args, **kwargs):
        if not getattr(self, 'gb_map_style', None):
            return
        if not self.gb_map_style.isChecked():
            return
        if self._map_markers_tsv is None or self._map_out_dir is None:
            return

        go, pio, _qual = _try_import_plotly()
        if go is None or pio is None:
            return

        style = self._collect_map_plot_settings()
        try:
            fig = build_linkage_map_figure(
                self._map_markers_tsv,
                self._map_lengths_tsv,
                title=self._map_title,
                pos_unit=self._map_pos_unit,
                style=style,
            )
            self._map_fig = fig
            if fig is None:
                return

            out_html = self._map_out_dir / "plots" / "map_plotly.html"
            out_html.parent.mkdir(parents=True, exist_ok=True)
            html = _plotly_html(fig, pio, add_selection_js=False)
            out_html.write_text(html, encoding="utf-8")
            self.set_plot_html(out_html)
        except Exception:
            # keep previous figure if any
            return

    def _export_map_html(self):
        if self._map_markers_tsv is None or self._map_out_dir is None:
            QMessageBox.information(self, "Export", "No map results available (run Map first).")
            return

        default = str((self._map_out_dir / "plots" / "map_plotly.html").resolve())
        out, _ = QFileDialog.getSaveFileName(self, "Export map HTML", default, "HTML (*.html)")
        if not out:
            return

        try:
            self._rebuild_map_plotly()
            fig = self._map_fig
            if fig is None:
                fig = build_linkage_map_figure(
                    self._map_markers_tsv,
                    self._map_lengths_tsv,
                    title=self._map_title,
                    pos_unit=self._map_pos_unit,
                    style=self._collect_map_plot_settings(),
                )
            if fig is None:
                raise RuntimeError("Failed to build map figure")
            go, pio, _qual = _try_import_plotly()
            html = _plotly_html(fig, pio, add_selection_js=False)
            Path(out).write_text(html, encoding="utf-8")
            QMessageBox.information(self, "Export", f"Saved: {out}")
        except Exception as e:
            QMessageBox.warning(self, "Export failed", f"Failed to export map HTML.\n\n{e}")

    def _export_map_image(self, ext: str):
        if self._map_markers_tsv is None or self._map_out_dir is None:
            QMessageBox.information(self, "Export", "No map results available (run Map first).")
            return

        try:
            self._rebuild_map_plotly()
        except Exception:
            pass
        fig = self._map_fig
        if fig is None:
            QMessageBox.warning(self, "Export", "Failed to build map figure.")
            return

        settings = self._collect_map_plot_settings()
        w = int(settings.get("export_width", 1400))
        h = int(settings.get("export_height", 900))

        default = str((self._map_out_dir / "plots" / f"map_plotly.{ext}").resolve())
        filt = f"{ext.upper()} (*.{ext})"
        out, _ = QFileDialog.getSaveFileName(self, f"Export map {ext.upper()}", default, filt)
        if not out:
            return

        try:
            fig.write_image(out, width=w, height=h, scale=1)
            QMessageBox.information(self, "Export", f"Saved: {out}")
        except Exception as e:
            QMessageBox.warning(self, "Export failed", f"Failed to export {ext.upper()}.\n\nTip: install kaleido.\n\n{e}")


    # ---- RNA-seq (Phase1: DEG volcano/MA) ----


    # =====================
    # Preprocess QC (Imputation) Plotly
    # =====================

    def _refresh_preprocess_color_buttons(self):
        try:
            self.btn_preprocess_font_color.setStyleSheet(f"background-color: {self._preprocess_font_color.name()};")
            self.btn_preprocess_bg_plot.setStyleSheet(f"background-color: {self._preprocess_bg_plot.name()};")
            self.btn_preprocess_bg_paper.setStyleSheet(f"background-color: {self._preprocess_bg_paper.name()};")
        except Exception:
            pass

    def _pick_preprocess_color(self, which: str):
        if which == "font":
            init = self._preprocess_font_color
            col = QColorDialog.getColor(init, self, "Pick font color")
            if col.isValid():
                self._preprocess_font_color = col
        elif which == "plot":
            init = self._preprocess_bg_plot
            col = QColorDialog.getColor(init, self, "Pick plot background")
            if col.isValid():
                self._preprocess_bg_plot = col
        else:
            init = self._preprocess_bg_paper
            col = QColorDialog.getColor(init, self, "Pick figure background")
            if col.isValid():
                self._preprocess_bg_paper = col

        try:
            self._refresh_preprocess_color_buttons()
        except Exception:
            pass
        self._rebuild_preprocess_plotly()

    def _collect_preprocess_plot_settings(self) -> dict:
        return dict(
            template=str(self.cmb_preprocess_template.currentText()),
            font_family=str(self.cmb_preprocess_font.currentText()),
            font_size=int(self.sp_preprocess_font_size.value()),
            font_color=str(self._preprocess_font_color.name()),
            plot_bgcolor=str(self._preprocess_bg_plot.name()),
            paper_bgcolor=str(self._preprocess_bg_paper.name()),
            margin_l=int(self.sp_preprocess_m_l.value()),
            margin_r=int(self.sp_preprocess_m_r.value()),
            margin_t=int(self.sp_preprocess_m_t.value()),
            margin_b=int(self.sp_preprocess_m_b.value()),
            height=int(self.sp_preprocess_height.value()),
            export_clean=bool(self.cb_preprocess_export_clean.isChecked()),
            export_width=int(self.sp_preprocess_export_w.value()),
            export_height=int(self.sp_preprocess_export_h.value()),
        )

    def set_preprocess_plotly_context(self, out_dir: Path, *, kind: str, title: str | None = None):
        """Enable Preprocess style controls and (re)build QC Plotly from a Preprocess output folder.

        This supports multiple output conventions:
          - missing_before/after(+summary.tsv) style
          - marker_summary/trait_summary(+sample_summary) style
          - cross-population: imputed genotype matrix TSV
        """
        base = Path(out_dir)
        k = (kind or "").strip().lower()
        if k.startswith("geno"):
            k = "genotype"
        elif k.startswith("pheno"):
            k = "phenotype"
        elif k.startswith("cross"):
            k = "cross"

        self._plot_mode = "preprocess"
        self._preprocess_out_dir = base
        self._preprocess_kind = k

        # reset pointers (safe even if attributes are not pre-declared)
        self._preprocess_missing_before_tsv = None
        self._preprocess_missing_after_tsv = None
        self._preprocess_summary_tsv = None
        self._preprocess_marker_summary_tsv = None
        self._preprocess_trait_summary_tsv = None
        self._preprocess_sample_summary_tsv = None
        self._preprocess_imputed_tsv = None

        # Prefer missing_before/after style if present
        if k == "phenotype":
            mb = base / "pheno_missing_before.tsv"
            ma = base / "pheno_missing_after.tsv"
        elif k == "cross":
            mb = base / "missing_rates_before.tsv"
            ma = base / "missing_rates_after.tsv"
        else:
            mb = base / "missing_before.tsv"
            ma = base / "missing_after.tsv"
        sm = base / "summary.tsv"

        if mb.exists() and ma.exists():
            self._preprocess_missing_before_tsv = mb
            self._preprocess_missing_after_tsv = ma
        if sm.exists():
            self._preprocess_summary_tsv = sm

        # Alternative runner outputs
        if k == "genotype":
            ms = base / "marker_summary.tsv"
            ss = base / "sample_summary.tsv"
            if ms.exists():
                self._preprocess_marker_summary_tsv = ms
            if ss.exists():
                self._preprocess_sample_summary_tsv = ss
        elif k == "phenotype":
            ts = base / "trait_summary.tsv"
            ss = base / "sample_summary.tsv"
            if ts.exists():
                self._preprocess_trait_summary_tsv = ts
            if ss.exists():
                self._preprocess_sample_summary_tsv = ss
        elif k == "cross":
            # Try to find imputed TSV from artifacts.json (preferred)
            art = base / "artifacts.json"
            cand = None
            if art.exists():
                try:
                    meta = json.loads(art.read_text(encoding="utf-8", errors="ignore"))
                    for key in ["imputed_tsv", "imputed_genotype_tsv", "imputed_matrix_tsv", "imputed_genotypes_tsv"]:
                        v = meta.get(key)
                        if v:
                            p = Path(str(v))
                            if p.exists():
                                cand = p
                                break
                except Exception:
                    cand = None
            # Fallback: common filenames
            if cand is None:
                for p in [
                    base / "imputed.tsv",
                    base / "imputed_genotype.tsv",
                    base / "imputed_genotypes.tsv",
                    base / "imputed_matrix.tsv",
                    base / "imputed_genotype_matrix.tsv",
                ]:
                    if p.exists():
                        cand = p
                        break
            self._preprocess_imputed_tsv = cand

        # Update labels and default title
        try:
            pretty = {
                "genotype": "Genotype Imputation QC",
                "phenotype": "Phenotype Imputation QC",
                "cross": "Cross-population Imputation QC",
            }.get(k, k)
            self.lbl_preprocess_kind.setText(pretty)
            if title:
                self.ed_preprocess_title.setText(str(title))
            else:
                if not (self.ed_preprocess_title.text() or "").strip() or self.ed_preprocess_title.text().strip() == "Preprocess QC":
                    self.ed_preprocess_title.setText(pretty)
        except Exception:
            pass

        # Load a summary-ish table when available (best-effort)
        try:
            if getattr(self, "_preprocess_marker_summary_tsv", None) is not None and Path(self._preprocess_marker_summary_tsv).exists():
                self.load_table(Path(self._preprocess_marker_summary_tsv))
            elif getattr(self, "_preprocess_trait_summary_tsv", None) is not None and Path(self._preprocess_trait_summary_tsv).exists():
                self.load_table(Path(self._preprocess_trait_summary_tsv))
            elif getattr(self, "_preprocess_summary_tsv", None) is not None and Path(self._preprocess_summary_tsv).exists():
                self.load_table(Path(self._preprocess_summary_tsv))
        except Exception:
            pass

        # Enable preprocess controls; disable others
        try:
            self.gb_style.setEnabled(False)
            self.gb_qtl_style.setEnabled(False)
            self.gb_map_style.setEnabled(False)
            self.gb_preprocess_style.setEnabled(True)
            self.gb_rnaseq_style.setEnabled(False)
            self.gb_gp_style.setEnabled(False)
        except Exception:
            pass

        try:
            self.set_style_panel("preprocess", rebuild=False)
        except Exception:
            pass

        self._rebuild_preprocess_plotly()

    def _rebuild_preprocess_plotly(self, *args, **kwargs):
        if not getattr(self, "gb_preprocess_style", None):
            return
        if not self.gb_preprocess_style.isChecked():
            return
        if getattr(self, "_preprocess_out_dir", None) is None or getattr(self, "_preprocess_kind", None) is None:
            return

        go, pio, _qual = _try_import_plotly()
        if go is None or pio is None:
            return

        base = Path(self._preprocess_out_dir)
        k = str(self._preprocess_kind or "").strip().lower()

        # Title and style settings
        try:
            title = str(self.ed_preprocess_title.text()).strip()
        except Exception:
            title = ""
        if not title:
            title = {
                "genotype": "Genotype Imputation QC",
                "phenotype": "Phenotype Imputation QC",
                "cross": "Cross-population Imputation QC",
            }.get(k, "Preprocess QC")
        settings = {}
        try:
            settings = self._collect_preprocess_plot_settings()
        except Exception:
            settings = {}

        fig = None

        # 1) missing_before/after(+summary.tsv) style
        mb = getattr(self, "_preprocess_missing_before_tsv", None)
        ma = getattr(self, "_preprocess_missing_after_tsv", None)
        sm = getattr(self, "_preprocess_summary_tsv", None)
        if mb and ma and sm and Path(mb).exists() and Path(ma).exists() and Path(sm).exists():
            try:
                if k == "phenotype":
                    fig = build_phenotype_imputation_qc_figure(Path(mb), Path(ma), Path(sm), title=title, settings=settings)
                elif k == "cross":
                    fig = build_cross_population_imputation_qc_figure(Path(mb), Path(ma), Path(sm), title=title, settings=settings)
                else:
                    fig = build_genotype_imputation_qc_figure(Path(mb), Path(ma), Path(sm), title=title, settings=settings)
            except Exception:
                fig = None

        # 2) marker/trait summary style (current runners)
        if fig is None and k == "genotype":
            ms = getattr(self, "_preprocess_marker_summary_tsv", None) or (base / "marker_summary.tsv")
            ss = getattr(self, "_preprocess_sample_summary_tsv", None) or (base / "sample_summary.tsv")
            if ms and Path(ms).exists():
                fig = build_genotype_imputation_qc_figure_marker_summary(Path(ms), Path(ss) if ss and Path(ss).exists() else None, title=title, settings=settings)

        if fig is None and k == "phenotype":
            ts = getattr(self, "_preprocess_trait_summary_tsv", None) or (base / "trait_summary.tsv")
            ss = getattr(self, "_preprocess_sample_summary_tsv", None) or (base / "sample_summary.tsv")
            if ts and Path(ts).exists():
                fig = build_phenotype_imputation_qc_figure_trait_summary(Path(ts), Path(ss) if ss and Path(ss).exists() else None, title=title, settings=settings)

        # 3) cross-population: imputed genotype matrix TSV
        if fig is None and k == "cross":
            it = getattr(self, "_preprocess_imputed_tsv", None)
            if it is None:
                it = base / "imputed.tsv"
            if it and Path(it).exists():
                fig = build_cross_imputation_qc_figure_from_imputed(Path(it), title=title, settings=settings)

        # Fallback: show an existing QC html (no rebuild / export)
        if fig is None:
            for cand in [
                base / "plots" / "qc_genotype_imputation.html",
                base / "plots" / "qc_phenotype_imputation.html",
                base / "plots" / "qc_cross_imputation.html",
                base / "qc_genotype_imputation.html",
                base / "qc_phenotype_imputation.html",
                base / "qc_cross_imputation.html",
            ]:
                if cand.exists():
                    self.set_plot_html(cand, cache=True)
                    return
            return

        self._preprocess_fig = fig

        html_dir = base / "plots"
        html_dir.mkdir(parents=True, exist_ok=True)

        html_name = {
            "genotype": "qc_genotype_imputation.html",
            "phenotype": "qc_phenotype_imputation.html",
            "cross": "qc_cross_imputation.html",
        }.get(k, "qc_preprocess.html")

        html_path = html_dir / html_name

        try:
            html = _plotly_html(fig, pio)
            html_path.write_text(html, encoding="utf-8")
            # also mirror into out_dir root (keeps backward compatibility with earlier runs)
            try:
                (base / html_name).write_text(html, encoding="utf-8")
            except Exception:
                pass
        except Exception:
            return

        self.set_plot_html(html_path, cache=True)

    def _export_preprocess_html(self):
        if getattr(self, "_preprocess_out_dir", None) is None or getattr(self, "_preprocess_kind", None) is None:
            QMessageBox.information(self, "Export", "No Preprocess QC plot is available (run imputation or use Draw).")
            return

        base = Path(self._preprocess_out_dir)
        k = str(self._preprocess_kind)
        default_name = {
            "genotype": "qc_genotype_imputation.html",
            "phenotype": "qc_phenotype_imputation.html",
            "cross": "qc_cross_imputation.html",
        }.get(k, "qc_preprocess.html")

        default = str((base / "plots" / default_name).resolve())
        out, _ = QFileDialog.getSaveFileName(self, "Export HTML", default, "HTML (*.html)")
        if not out:
            return

        go, pio, _qual = _try_import_plotly()
        if pio is None:
            QMessageBox.warning(self, "Export", "Plotly is not available.")
            return

        try:
            self._rebuild_preprocess_plotly()
            fig = getattr(self, "_preprocess_fig", None)
            if fig is None:
                raise RuntimeError("Failed to build figure.")
            html = _plotly_html(fig, pio, add_selection_js=False)
            Path(out).write_text(html, encoding="utf-8")
            QMessageBox.information(self, "Export", f"Saved: {out}")
        except Exception as e:
            QMessageBox.warning(self, "Export failed", f"Failed to export HTML.\n\n{e}")

    def _export_preprocess_image(self, ext: str):
        if getattr(self, "_preprocess_out_dir", None) is None or getattr(self, "_preprocess_kind", None) is None:
            QMessageBox.information(self, "Export", "No Preprocess QC plot is available (run imputation or use Draw).")
            return

        base = Path(self._preprocess_out_dir)
        k = str(self._preprocess_kind)
        default_name = {
            "genotype": f"qc_genotype_imputation.{ext}",
            "phenotype": f"qc_phenotype_imputation.{ext}",
            "cross": f"qc_cross_population_imputation.{ext}",
        }.get(k, f"qc_preprocess.{ext}")

        out, _ = QFileDialog.getSaveFileName(self, f"Export {ext.upper()}", str((base / default_name).resolve()), f"*.{ext}")
        if not out:
            return

        go, pio, _qual = _try_import_plotly()
        if pio is None:
            QMessageBox.warning(self, "Export", "Plotly is not available.")
            return

        try:
            self._rebuild_preprocess_plotly()
            fig = getattr(self, "_preprocess_fig", None)
            if fig is None:
                raise RuntimeError("Failed to build figure.")

            w = int(self.sp_preprocess_export_w.value())
            h = int(self.sp_preprocess_export_h.value())
            pio.write_image(fig, out, width=w, height=h, scale=1)
            QMessageBox.information(self, "Export", f"Saved: {out}")
        except Exception as e:
            QMessageBox.warning(self, "Export failed", f"Failed to export {ext.upper()}.\n\nTip: install kaleido.\n\n{e}")

    def set_rnaseq_plotly_context(
        self,
        deg_tsv: Path,
        *,
        out_dir: Path,
        title: str = "DEG",
    ):
        """Enable RNA-seq style controls and show an interactive DEG plot.

        Notes
        -----
        Phase1 supports:
          - DEG volcano plot
          - DEG MA plot
        """
        self._plot_mode = "rnaseq"
        self._rnaseq_deg_tsv = Path(deg_tsv)
        self._rnaseq_out_dir = Path(out_dir)

        # load DEG table
        try:
            self._rnaseq_deg_df = pd.read_csv(self._rnaseq_deg_tsv, sep="\t", dtype=str)
        except Exception:
            try:
                self._rnaseq_deg_df = pd.read_csv(self._rnaseq_deg_tsv, sep="\s+", engine="python", dtype=str)
            except Exception:
                self._rnaseq_deg_df = pd.DataFrame()

        try:
            self.load_table(self._rnaseq_deg_tsv)
        except Exception:
            pass

        # defaults: module=DEG, plot=Volcano
        try:
            self.cmb_rnaseq_module.blockSignals(True)
            self.cmb_rnaseq_module.setCurrentText("DEG")
            self.cmb_rnaseq_module.blockSignals(False)
        except Exception:
            try:
                self.cmb_rnaseq_module.blockSignals(False)
            except Exception:
                pass

        try:
            if (self.ed_rnaseq_title.text() or "").strip() == "":
                self.ed_rnaseq_title.setText(str(title))
        except Exception:
            pass

        # enable RNA-seq controls; disable other style panels
        try:
            self.gb_style.setEnabled(False)
            self.gb_qtl_style.setEnabled(False)
            self.gb_map_style.setEnabled(False)
            self.gb_gp_style.setEnabled(False)
            try:
                self.gb_preprocess_style.setEnabled(False)
            except Exception:
                pass
            self.gb_rnaseq_style.setEnabled(True)
        except Exception:
            pass
        try:
            self.set_style_panel("rnaseq", rebuild=False)
        except Exception:
            pass

        # build
        self._on_rnaseq_module_changed(self.cmb_rnaseq_module.currentIndex())

        self._rebuild_rnaseq_plotly()


    def set_rnaseq_cluster_context(self, out_dir: Path, *, title: str = "Cluster/DimRed"):
        """Enable RNA-seq Cluster/DimRed style controls and allow Plotly regeneration from outputs."""
        self._plot_mode = "rnaseq"
        self._rnaseq_cluster_out_dir = Path(out_dir)
        self._rnaseq_cluster_df = None  # lazy load

        # Defaults
        try:
            if (self.ed_rnaseq_cl_title.text() or "").strip() == "":
                self.ed_rnaseq_cl_title.setText(str(title))
        except Exception:
            pass

        # Populate Color-by choices from available tables (best-effort)
        try:
            emb = self._load_rnaseq_cluster_df()
            cols = list(emb.columns)
            skip = set(["sample"])
            for k, (x, y) in self._rnaseq_cluster_embed_cols.items():
                skip.add(x); skip.add(y)
            candidates = [c for c in cols if c not in skip]
            # prefer cluster + condition
            preferred = []
            for c in ["cluster", "condition", "group"]:
                if c in candidates:
                    preferred.append(c)
            rest = [c for c in candidates if c not in preferred]
            items = ["auto"] + preferred + rest + ["none"]
            self.cmb_rnaseq_cl_color_by.blockSignals(True)
            self.cmb_rnaseq_cl_color_by.clear()
            for it in items:
                self.cmb_rnaseq_cl_color_by.addItem(it, it)
            # auto select cluster if exists
            if "cluster" in items:
                self.cmb_rnaseq_cl_color_by.setCurrentText("cluster")
            else:
                self.cmb_rnaseq_cl_color_by.setCurrentText("auto")
            self.cmb_rnaseq_cl_color_by.setEnabled(True)
            self.cmb_rnaseq_cl_color_by.blockSignals(False)
        except Exception:
            try:
                self.cmb_rnaseq_cl_color_by.setEnabled(True)
                self.cmb_rnaseq_cl_color_by.blockSignals(False)
            except Exception:
                pass

        # Load a reasonable table into Results table tab
        try:
            p = self._rnaseq_cluster_out_dir / "sample_clusters.tsv"
            if p.exists():
                self.load_table(p)
        except Exception:
            pass

        # Switch module to Cluster
        try:
            self.cmb_rnaseq_module.blockSignals(True)
            self.cmb_rnaseq_module.setCurrentText("Cluster/DimRed")
            self.cmb_rnaseq_module.blockSignals(False)
        except Exception:
            try:
                self.cmb_rnaseq_module.blockSignals(False)
            except Exception:
                pass

        # enable RNA-seq controls; disable other style panels
        try:
            self.gb_style.setEnabled(False)
            self.gb_qtl_style.setEnabled(False)
            self.gb_map_style.setEnabled(False)
            self.gb_gp_style.setEnabled(False)
            try:
                self.gb_preprocess_style.setEnabled(False)
            except Exception:
                pass
            self.gb_rnaseq_style.setEnabled(True)
        except Exception:
            pass
        try:
            self.set_style_panel("rnaseq", rebuild=False)
        except Exception:
            pass

        try:
            self._rnaseq_geneclust_refresh_cluster_selectors()
        except Exception:
            pass

        self._on_rnaseq_module_changed(self.cmb_rnaseq_module.currentIndex())
        self._rebuild_rnaseq_plotly()


    def set_rnaseq_enrich_context(self, out_dir: Path, *, title: str = "Enrichment"):
        """Enable RNA-seq Enrichment style controls and allow Plotly regeneration from outputs."""
        self._plot_mode = "rnaseq"
        self._rnaseq_enrich_out_dir = Path(out_dir)
        self._rnaseq_enrich_df = None
        self._rnaseq_enrich_selected = None

        try:
            if (self.ed_rnaseq_en_title.text() or "").strip() == "":
                self.ed_rnaseq_en_title.setText(str(title))
        except Exception:
            pass

        # Discover enrichment tables (artifacts.json preferred)
        tables: list[Path] = []
        try:
            art = self._rnaseq_enrich_out_dir / "artifacts.json"
            if art.exists():
                data = json.loads(art.read_text(encoding="utf-8", errors="ignore"))
                if isinstance(data, dict) and isinstance(data.get("artifacts"), dict):
                    for k, rel in data["artifacts"].items():
                        try:
                            p = self._rnaseq_enrich_out_dir / str(rel)
                            if p.suffix.lower() in [".tsv", ".csv", ".txt"] and p.exists():
                                tables.append(p)
                        except Exception:
                            pass
        except Exception:
            tables = []

        if not tables:
            try:
                tables = sorted(self._rnaseq_enrich_out_dir.glob("*.tsv"))
            except Exception:
                tables = []

        self._rnaseq_enrich_tables = tables

        # Fill table selector
        try:
            self.cmb_rnaseq_en_table.blockSignals(True)
            self.cmb_rnaseq_en_table.clear()
            for p in self._rnaseq_enrich_tables:
                self.cmb_rnaseq_en_table.addItem(p.name, str(p))
            self.cmb_rnaseq_en_table.setEnabled(len(self._rnaseq_enrich_tables) > 0)
            self.cmb_rnaseq_en_table.blockSignals(False)
        except Exception:
            try:
                self.cmb_rnaseq_en_table.blockSignals(False)
            except Exception:
                pass

        # Load first table in Results table tab
        try:
            if self._rnaseq_enrich_tables:
                self._rnaseq_enrich_selected = self._rnaseq_enrich_tables[0]
                self.load_table(self._rnaseq_enrich_selected)
        except Exception:
            pass

        # Switch module to Enrichment
        try:
            self.cmb_rnaseq_module.blockSignals(True)
            self.cmb_rnaseq_module.setCurrentText("Enrichment")
            self.cmb_rnaseq_module.blockSignals(False)
        except Exception:
            try:
                self.cmb_rnaseq_module.blockSignals(False)
            except Exception:
                pass

        # enable RNA-seq controls; disable other style panels
        try:
            self.gb_style.setEnabled(False)
            self.gb_qtl_style.setEnabled(False)
            self.gb_map_style.setEnabled(False)
            self.gb_gp_style.setEnabled(False)
            try:
                self.gb_preprocess_style.setEnabled(False)
            except Exception:
                pass
            self.gb_rnaseq_style.setEnabled(True)
        except Exception:
            pass
        try:
            self.set_style_panel("rnaseq", rebuild=False)
        except Exception:
            pass

        try:
            self._rnaseq_geneclust_refresh_cluster_selectors()
        except Exception:
            pass

        self._on_rnaseq_module_changed(self.cmb_rnaseq_module.currentIndex())
        self._rebuild_rnaseq_plotly()


    def set_rnaseq_geneclust_context(self, out_dir: Path, *, title: str = "GeneClust (Model)"):
        """Enable RNA-seq GeneClust(Model) style controls and allow Plotly regeneration from outputs."""
        self._plot_mode = "rnaseq"
        self._rnaseq_geneclust_out_dir = Path(out_dir)
        try:
            self._rnaseq_geneclust_cache = {}
        except Exception:
            pass

        # Defaults
        try:
            if hasattr(self, "ed_rnaseq_gc_title"):
                cur = (self.ed_rnaseq_gc_title.text() or "").strip()
                if cur == "" or cur.lower().startswith("geneclust") or cur.lower().startswith("rna-seq"):
                    self.ed_rnaseq_gc_title.setText(str(title))
        except Exception:
            pass

        # Populate Color-by (best-effort; cluster is always valid for most plots)
        try:
            self.cmb_rnaseq_cl_color_by.blockSignals(True)
            self.cmb_rnaseq_cl_color_by.clear()
            for it in ["auto", "cluster", "none"]:
                self.cmb_rnaseq_cl_color_by.addItem(it, it)
            self.cmb_rnaseq_cl_color_by.setCurrentText("cluster")
            self.cmb_rnaseq_cl_color_by.setEnabled(True)
            self.cmb_rnaseq_cl_color_by.blockSignals(False)
        except Exception:
            try:
                self.cmb_rnaseq_cl_color_by.setEnabled(True)
                self.cmb_rnaseq_cl_color_by.blockSignals(False)
            except Exception:
                pass

        # Load a reasonable table into Results table tab
        try:
            for fn in ["gene_clusters.tsv", "cluster_profiles.tsv", "cluster_sizes.tsv", "gene_embedding.tsv", "model_scores.tsv", "artifacts.json"]:
                p = self._rnaseq_geneclust_out_dir / fn
                if p.exists():
                    self.load_table(p)
                    break
        except Exception:
            pass

        # Switch module to GeneClust
        try:
            self.cmb_rnaseq_module.blockSignals(True)
            self.cmb_rnaseq_module.setCurrentText("GeneClust (Model)")
            self.cmb_rnaseq_module.blockSignals(False)
        except Exception:
            try:
                self.cmb_rnaseq_module.blockSignals(False)
            except Exception:
                pass

        # enable RNA-seq controls; disable other style panels
        try:
            self.gb_style.setEnabled(False)
            self.gb_qtl_style.setEnabled(False)
            self.gb_map_style.setEnabled(False)
            self.gb_gp_style.setEnabled(False)
            try:
                self.gb_preprocess_style.setEnabled(False)
            except Exception:
                pass
            self.gb_rnaseq_style.setEnabled(True)
        except Exception:
            pass
        try:
            self.set_style_panel("rnaseq", rebuild=False)
        except Exception:
            pass

        try:
            self._rnaseq_geneclust_refresh_cluster_selectors()
        except Exception:
            pass

        self._on_rnaseq_module_changed(self.cmb_rnaseq_module.currentIndex())
        self._rebuild_rnaseq_plotly()

    def _rnaseq_geneclust_refresh_cluster_selectors(self):
        """Refresh cluster selector options for representative gene plots (Phase D)."""
        cmb = getattr(self, 'cmb_rnaseq_gc_rep_cluster', None)
        if cmb is None:
            return
        # collect clusters from sizes/membership
        try:
            cs = self._load_rnaseq_geneclust_sizes()
            clusters = []
            if cs is not None and (not cs.empty) and 'cluster' in cs.columns:
                clusters = [str(x) for x in cs['cluster'].astype(str).tolist()]
            clusters = list(dict.fromkeys([c for c in clusters if c and c != 'nan']))
            if not clusters:
                # fallback from profiles
                prof = self._load_rnaseq_geneclust_profiles_long()
                if prof is not None and (not prof.empty) and 'cluster' in prof.columns:
                    clusters = list(dict.fromkeys([str(x) for x in prof['cluster'].astype(str).tolist()]))
        except Exception:
            clusters = []
        try:
            cur = cmb.currentText()
        except Exception:
            cur = ''
        try:
            cmb.blockSignals(True)
            cmb.clear()
            cmb.addItem('AUTO')
            for cl in clusters:
                cmb.addItem(str(cl))
            # restore selection
            if cur and cmb.findText(cur) >= 0:
                cmb.setCurrentText(cur)
            else:
                cmb.setCurrentIndex(0)
            cmb.blockSignals(False)
        except Exception:
            try:
                cmb.blockSignals(False)
            except Exception:
                pass



    def _on_rnaseq_module_changed(self, _idx: int):
        mod = (self.cmb_rnaseq_module.currentText() or "").strip()

        # sync style sub-tabs (reuse existing tabs: DEG / Cluster / Enrichment)
        try:
            if mod.startswith("DEG"):
                self.rnaseq_style_tabs.setCurrentIndex(0)
            elif mod.startswith("Cluster"):
                self.rnaseq_style_tabs.setCurrentIndex(1)
            elif mod.startswith("GeneClust"):
                self.rnaseq_style_tabs.setCurrentIndex(2)
            else:
                self.rnaseq_style_tabs.setCurrentIndex(3)
        except Exception:
            pass

        # update plot types
        try:
            self.cmb_rnaseq_plot_kind.blockSignals(True)
            self.cmb_rnaseq_plot_kind.clear()
            if mod.startswith("DEG"):
                self.cmb_rnaseq_plot_kind.addItems(["Volcano", "MA"])
                self.cmb_rnaseq_plot_kind.setEnabled(True)
            elif mod.startswith("Cluster"):
                # Cluster/DimRed
                self.cmb_rnaseq_plot_kind.addItems(["PCA", "UMAP", "t-SNE", "Cluster sizes"])
                self.cmb_rnaseq_plot_kind.setEnabled(True)
            elif mod.startswith("GeneClust"):
                # GeneClust (Model): interpretation-oriented plots
                self.cmb_rnaseq_plot_kind.addItems([
                    "Cluster profiles (lines)",
                    "Cluster profiles (heatmap)",
                    "Representative genes (lines)",
                    "Representative genes (heatmap)",
                    "Gene embedding",
                    "Cluster sizes",
                    "Model selection",
                ])
                self.cmb_rnaseq_plot_kind.setEnabled(True)
            else:
                # Enrichment
                self.cmb_rnaseq_plot_kind.addItems(["Dotplot", "Barplot"])
                self.cmb_rnaseq_plot_kind.setEnabled(True)
            self.cmb_rnaseq_plot_kind.blockSignals(False)
        except Exception:
            try:
                self.cmb_rnaseq_plot_kind.blockSignals(False)
            except Exception:
                pass

        self._rebuild_rnaseq_plotly()


    def _load_rnaseq_cluster_df(self) -> pd.DataFrame:
        """Load and merge cluster embedding + cluster assignments from out_dir (best-effort)."""
        if self._rnaseq_cluster_df is not None:
            return self._rnaseq_cluster_df
        if not self._rnaseq_cluster_out_dir:
            self._rnaseq_cluster_df = pd.DataFrame()
            return self._rnaseq_cluster_df

        out_dir = Path(self._rnaseq_cluster_out_dir)
        emb_path = out_dir / "sample_embedding.tsv"
        clu_path = out_dir / "sample_clusters.tsv"

        # embedding
        df_emb = pd.DataFrame()
        if emb_path.exists():
            try:
                df_emb = pd.read_csv(emb_path, sep="\t")
            except Exception:
                try:
                    df_emb = pd.read_csv(emb_path, sep="\s+", engine="python")
                except Exception:
                    df_emb = pd.DataFrame()

        # clusters
        df_clu = pd.DataFrame()
        if clu_path.exists():
            try:
                df_clu = pd.read_csv(clu_path, sep="\t")
            except Exception:
                try:
                    df_clu = pd.read_csv(clu_path, sep="\s+", engine="python")
                except Exception:
                    df_clu = pd.DataFrame()

        # ensure sample column
        def _ensure_sample(df: pd.DataFrame) -> pd.DataFrame:
            if df is None or df.empty:
                return pd.DataFrame()
            cols = list(df.columns)
            if "sample" in cols:
                return df
            # common variants
            for c in ["Sample", "sample_id", "id", "ID", "name"]:
                if c in cols:
                    df = df.rename(columns={c: "sample"})
                    return df
            # fallback: first col
            if cols:
                df = df.rename(columns={cols[0]: "sample"})
            return df

        df_emb = _ensure_sample(df_emb)
        df_clu = _ensure_sample(df_clu)

        # merge if possible
        df = df_emb.copy()
        if not df_clu.empty and "sample" in df.columns and "sample" in df_clu.columns:
            try:
                df = df.merge(df_clu, on="sample", how="left", suffixes=("", "_meta"))
            except Exception:
                pass

        # guess coordinate columns
        cols = list(df.columns)
        def _find_pair(prefixes: list[str]) -> tuple[str, str] | None:
            for p in prefixes:
                c1 = None; c2 = None
                for cand in [p + "1", p + "_1", p + "01", p + "X", p + "_X", p + "x", p + "_x"]:
                    if cand in cols:
                        c1 = cand; break
                for cand in [p + "2", p + "_2", p + "02", p + "Y", p + "_Y", p + "y", p + "_y"]:
                    if cand in cols:
                        c2 = cand; break
                if c1 and c2:
                    return c1, c2
            return None

        embed_cols: dict[str, tuple[str, str]] = {}
        pca = _find_pair(["PC", "PCA", "Dim", "DIM"])
        if pca:
            embed_cols["PCA"] = pca
        umap = _find_pair(["UMAP", "umap"])
        if umap:
            embed_cols["UMAP"] = umap
        tsne = _find_pair(["tSNE", "TSNE", "tsne", "t_sne", "tSNE_"])
        if tsne:
            embed_cols["t-SNE"] = tsne

        self._rnaseq_cluster_embed_cols = embed_cols
        self._rnaseq_cluster_df = df
        return df


