        b_mp = QPushButton('Browse')
        b_mp.setStyleSheet(GE_BTN_BROWSE_QSS)
        b_mp.setToolTip('Select marker_map.tsv (optional, for TSV genotype)')
        b_mp.clicked.connect(lambda *args, **kwargs: self.pick_marker_map())
        b_out = QPushButton('Browse')
        b_out.setStyleSheet(GE_BTN_BROWSE_QSS)
        b_out.setToolTip('Select output folder')
        b_out.clicked.connect(lambda *args, **kwargs: self.pick_output_dir())
        b_cv = QPushButton('Browse')
        b_cv.setStyleSheet(GE_BTN_BROWSE_QSS)
        #b_cv.setToolTip('Select covariates.tsv (optional)')
        b_cv.clicked.connect(lambda *args, **kwargs: self.pick_cov())
        self.gaston_K_button = QPushButton('Browse')
        self.gaston_K_button.setStyleSheet(GE_BTN_BROWSE_QSS)
        #self.gaston_K_button.setToolTip('Select K (.rds) (optional; multiple allowed)')
        self.gaston_K_button.clicked.connect(lambda *args, **kwargs: self.pick_K())
        b_run = QPushButton('Run')
        b_run.setStyleSheet(GE_BTN_RUN_QSS)
        b_run.clicked.connect(lambda *args, **kwargs: self.run_gwas())
