        #form.addRow('genotype input', self.geno_mode)
        #form.addRow('PLINK prefix', _hbox(self.plink_prefix, b_pl))
        #form.addRow('VCF path', _hbox(self.vcf_path, b_vcf))
        
        form.addRow(b_run)

