        h.addWidget(QLabel('MAF'))
        h.addWidget(self.maf)
        h.addWidget(QLabel('missing_max'))
        h.addWidget(self.missing_max)
        h.addWidget(QLabel('LMM'))
        h.addWidget(self.use_lmm)
        wrap = QWidget()
        wrap.setLayout(h)
        form.addRow('params', wrap)

        # gaston-specific options (only enabled when method=gaston)
        form.addRow('LM/LMM test', self.gaston_test)
        form.addRow('LM/LMM p (PCs)', self.gaston_p)
        form.addRow('LMM/MLMM Kmat', _hbox(self.gaston_K, self.gaston_K_button))

        # method-specific params
        mlmm_wrap = QWidget()
        mlmm_h = QHBoxLayout()
        mlmm_h.addWidget(QLabel('max_steps'))
        mlmm_h.addWidget(self.mlmm_max_steps)
        #mlmm_h.addSpacing(12)
        #mlmm_h.addWidget(QLabel('criterion'))
        #mlmm_h.addWidget(self.mlmm_criterion)
        mlmm_h.addStretch(1)
        mlmm_wrap.setLayout(mlmm_h)
        form.addRow('MLMM', mlmm_wrap)

        farm_wrap = QWidget()
        farm_h = QHBoxLayout()
        farm_h.addWidget(QLabel('method'))
        farm_h.addWidget(self.farmcpu_method)
        farm_h.addSpacing(12)
        farm_h.addWidget(QLabel('method.bin'))
        farm_h.addWidget(self.farmcpu_method_bin)
        farm_h.addSpacing(12)
        farm_h.addWidget(QLabel('maxLoop'))
        farm_h.addWidget(self.farmcpu_n_iter)
