    def _read_gwas_sampled_df(
        self,
        path: Path,
        *,
        sample_n: int = 250000,
        top_keep: int = 50000,
        sep: str = "\t",
        comment_prefix: str = "#",
        seed: int = 1,
    ) -> pd.DataFrame:
        """Stream-read large GWAS results and return a sampled DataFrame.

        Keeps:
          - a uniform reservoir sample (sample_n)
          - plus top hits by p-value (top_keep)

        This is a fallback to avoid loading very large results.tsv into memory.
        """
        import csv
        import random

        path = Path(path)
        if not path.exists():
            return pd.DataFrame()

        rng = random.Random(int(seed))
        reservoir: list[dict] = []
        heap = []  # (-p, counter, rec) keep best hits
        counter = 0
        seen = 0

        with open(path, "r", encoding="utf-8", errors="replace", newline="") as f:
            reader = csv.reader(f, delimiter=sep)
            header = None
            for rec in reader:
                if not rec:
                    continue
                if rec[0].startswith(comment_prefix):
                    continue
                header = [str(x) for x in rec]
                if header:
                    header[0] = header[0].lstrip("\ufeff")
                break
            if not header:
                return pd.DataFrame()

            cols_map = {str(c).strip().lower(): i for i, c in enumerate(header)}

            def pick(cands: list[str]) -> int | None:
                for cand in cands:
                    cand_l = cand.lower()
                    if cand_l in cols_map:
                        return cols_map[cand_l]
                for name_l, i in cols_map.items():
                    for cand in cands:
                        cand_l = cand.lower()
                        if name_l.endswith(cand_l) or cand_l in name_l:
                            return i
                return None

            i_chr = pick(["chr", "chrom", "chromosome", "seqid"])
            i_pos = pick(["pos", "bp", "position", "physical_pos"])
            i_p   = pick(["p", "pvalue", "p_value", "p.val", "pval", "p.value"])
            i_q   = pick(["q", "qvalue", "q_value", "fdr", "padj", "adj_p"])
            i_m   = pick(["marker", "snp", "id", "rsid", "locus", "variant", "markerid"])

            if i_chr is None or i_pos is None or i_p is None:
                return pd.DataFrame()

            for rec in reader:
                if not rec:
                    continue
                if rec[0].startswith(comment_prefix):
                    continue
                try:
                    chr_v = str(rec[i_chr]).strip()
                    pos_v = float(str(rec[i_pos]).replace(",", ""))
                    p_v = float(str(rec[i_p]))
                    if not (p_v > 0.0):
                        continue
                    q_v = None
                    if i_q is not None and i_q < len(rec):
                        try:
                            q_v = float(str(rec[i_q]))
                        except Exception:
                            q_v = None
                    m_v = None
                    if i_m is not None and i_m < len(rec):
                        m_v = str(rec[i_m]).strip()

                    r = {"marker": m_v, "chr": chr_v, "pos": pos_v, "pvalue": p_v, "qvalue": q_v}

                    # reservoir sample
                    seen += 1
                    if sample_n and len(reservoir) < int(sample_n):
                        reservoir.append(r)
                    elif sample_n:
                        j = rng.randrange(seen)
                        if j < int(sample_n):
                            reservoir[j] = r

                    # top hits heap
                    item = (-p_v, counter, r)
                    counter += 1
                    if top_keep and len(heap) >= int(top_keep):
                        if item[0] > heap[0][0]:
                            heapq.heapreplace(heap, item)
                    elif top_keep:
                        heapq.heappush(heap, item)
                except Exception:
                    continue

        # merge reservoir + top hits (deduplicate)
        out: list[dict] = []
        seen_keys = set()
        def add_rec(rr: dict):
            key = (rr.get("chr"), rr.get("pos"), rr.get("marker"))
            if key in seen_keys:
                return
            seen_keys.add(key)
            out.append(rr)

        for rr in reservoir:
            add_rec(rr)
        for t in heap:
            add_rec(t[2])

        return pd.DataFrame(out)

    def draw_gwas(self):
        out_dir_txt = self.draw_out_dir.text().strip()
        res_txt = self.draw_results_tsv.text().strip()

        out_dir = Path(out_dir_txt) if out_dir_txt else None
        res_path = Path(res_txt) if res_txt else None

        if res_path is not None and res_path.exists() and out_dir is None:
            out_dir = res_path.parent

        if out_dir is None:
            QMessageBox.warning(self, "Error", "Please set output folder or results.tsv")
            return

        # prefer explicit results.tsv
        if res_path is None or not res_path.exists():
            cand = out_dir / "results.tsv"
            if cand.exists():
                res_path = cand
            else:
                QMessageBox.warning(self, "Error", f"results.tsv not found under: {out_dir}")
                return

        title = self.draw_title.text().strip()
        if not title:
            tr = self.trait.currentText().strip()
            title = f"GWAS: {tr}" if tr else "GWAS"

        # Remember as 'last output' so other tabs can reuse (Annotate / Locus builder etc.)
        self.last_out_dir = out_dir
        try:
            if hasattr(self, "draw_dir"):
                self.draw_dir.setText(str(out_dir))
                self._refresh_draw_view_items()
        except Exception:
            pass

        # Table: show top hits quickly (avoid giant table)
        try:
            recs = read_gwas_top_records(res_path, top_keep=5000, sep="\t")
            if recs:
                cols = ["marker", "chr", "pos", "pvalue", "qvalue"]
                rows = [[r.get("marker"), r.get("chr"), r.get("pos"), r.get("pvalue"), r.get("qvalue")] for r in recs]
                self.results.set_table_rows(cols, rows)
            else:
                df_head = read_table_robust(res_path).head(200)
                self.results.set_table_df(df_head, source_path=res_path)
        except Exception as e:
            self.append_log(f"[WARN] failed to load GWAS table: {e}")

        # Static PNG (optional)
        try:
            png = out_dir / "plots" / "manhattan.png"
            if png.exists():
                self.results.set_plot(png)
        except Exception:
            pass

        # Plotly Manhattan
        try:
            # For very large results.tsv, sample to keep GUI responsive
            try:
                size_mb = float(res_path.stat().st_size) / 1e6
            except Exception:
                size_mb = 0.0

            if size_mb > 150:
                self.append_log(f"[INFO] Large results.tsv ({size_mb:.1f} MB): using sampled load for Plotly")
                df = self._read_gwas_sampled_df(res_path, sample_n=250000, top_keep=50000)
            else:
                df = read_table_robust(res_path)

            if df is None or len(df) == 0:
                raise RuntimeError("failed to load results.tsv")
            self.results.set_plotly_context(df, out_dir, title=title)
            self.append_log(f"[OK] Drawn from: {res_path}")
        except Exception as e:
            self.append_log(f"[WARN] plotly manhattan failed: {e}")

    def get_last_results_tsv(self) -> Path | None:
        """For annotation: GWAS results"""
        if not self.last_out_dir:
            return None
        p = self.last_out_dir / "results.tsv"
        return p if p.exists() else None

