        self.n_perm.setSingleStep(10)
        self.n_perm.setValue(20)
        
        self.trait = QComboBox()
        self.trait.addItems(["normal", "binary"])

        self.alpha = QLineEdit("0.05")
        self.step = QLineEdit("1.0")
