def build_genotype_imputation_qc_figure_marker_summary(
    marker_summary_tsv: Path,
    sample_summary_tsv: Path | None = None,
    *,
    title: str = "Genotype Imputation QC",
    settings: dict | None = None,
):
    """Return a Plotly figure for genotype-imputation QC using marker/sample summary TSVs.

    Focus on what matters for QC:
      - Missingness BEFORE imputation (marker & sample)
      - MAF shift (before vs after) and ΔMAF distribution

    Works with both newer summaries (maf_before/maf_after) and older ones (maf_after only).
    """
    go, pio, _qual = _try_import_plotly()
    if go is None:
        return None
    try:
        from plotly.subplots import make_subplots  # type: ignore
    except Exception:
        return None

    try:
        md = pd.read_csv(marker_summary_tsv, sep="	")
    except Exception:
        return None

    sd = None
    if sample_summary_tsv is not None:
        try:
            if Path(sample_summary_tsv).exists():
                sd = pd.read_csv(sample_summary_tsv, sep="	")
        except Exception:
            sd = None

    # normalize column names to lowercase
    md2 = md.rename(columns={c: str(c).strip().lower() for c in md.columns})
    sd2 = None
    if sd is not None and not sd.empty:
        sd2 = sd.rename(columns={c: str(c).strip().lower() for c in sd.columns})

    # columns
    marker_col = None
    for cand in ["marker", "snp", "id"]:
        if cand in md2.columns:
            marker_col = cand
            break

    miss_b_col = None
    for cand in [
        "missing_before",
        "missing_rate_before",
        "missing_before_rate",
        "missingrate_before",
        "missing_rate",
        "missing",
        "miss",
        "miss_rate",
    ]:
        if cand in md2.columns:
            miss_b_col = cand
            break

    maf_b_col = None
    for cand in [
        "maf_before",
        "minor_allele_frequency_before",
        "minorallelefrequency_before",
    ]:
        if cand in md2.columns:
            maf_b_col = cand
            break

    maf_a_col = None
    for cand in [
        "maf_after",
        "minor_allele_frequency_after",
        "minorallelefrequency_after",
        "maf",
        "minor_allele_frequency",
        "minorallelefrequency",
    ]:
        if cand in md2.columns:
            maf_a_col = cand
            break

    smiss_b_col = None
    if sd2 is not None:
        for cand in [
            "missing_before",
            "missing_rate_before",
            "missing_before_rate",
            "missingrate_before",
            "missing_rate",
            "missing",
            "miss",
            "miss_rate",
        ]:
            if cand in sd2.columns:
                smiss_b_col = cand
                break

    fig = make_subplots(
        rows=2,
        cols=2,
        subplot_titles=[
            "Marker missingness (before)",
            "Sample missingness (before)",
            "MAF (before vs after)",
            "ΔMAF (after - before)",
        ],
        specs=[[{"type": "histogram"}, {"type": "histogram"}],
               [{"type": "scatter"}, {"type": "histogram"}]],
        vertical_spacing=0.15,
        horizontal_spacing=0.10,
    )

    # marker missingness before
    try:
        if miss_b_col:
            x = pd.to_numeric(md2[miss_b_col], errors="coerce")
            if x.notna().any():
                fig.add_trace(go.Histogram(x=x, nbinsx=50, showlegend=False), row=1, col=1)
                fig.update_xaxes(title_text="missing rate", row=1, col=1)
                fig.update_yaxes(title_text="# markers", row=1, col=1)
    except Exception:
        pass

    # sample missingness before
    try:
        if sd2 is not None and smiss_b_col:
            x = pd.to_numeric(sd2[smiss_b_col], errors="coerce")
            if x.notna().any():
                fig.add_trace(go.Histogram(x=x, nbinsx=50, showlegend=False), row=1, col=2)
                fig.update_xaxes(title_text="missing rate", row=1, col=2)
                fig.update_yaxes(title_text="# samples", row=1, col=2)
    except Exception:
        pass

    # MAF before vs after (fallback: maf_after hist)
    maf_scatter_ok = False
    try:
        if maf_b_col and maf_a_col:
            xb = pd.to_numeric(md2[maf_b_col], errors="coerce")
            ya = pd.to_numeric(md2[maf_a_col], errors="coerce")
            if xb.notna().any() and ya.notna().any():
                mx = float(np.nanmax([np.nanmax(xb.values), np.nanmax(ya.values), 0.0]))
                fig.add_trace(go.Scatter(x=[0, mx], y=[0, mx], mode="lines", line=dict(dash="dash"), showlegend=False), row=2, col=1)

                mk = dict(size=4, opacity=0.75)
                if miss_b_col:
                    cb = pd.to_numeric(md2[miss_b_col], errors="coerce")
                    if cb.notna().any():
                        mk["color"] = cb
                        mk["colorscale"] = "Viridis"
                        mk["showscale"] = True
                        mk["colorbar"] = dict(title="missing_before")

                hover = None
                if marker_col and marker_col in md2.columns:
                    try:
                        hover = md2[marker_col].astype(str).tolist()
                    except Exception:
                        hover = None

                fig.add_trace(
                    go.Scatter(
                        x=xb,
                        y=ya,
                        mode="markers",
                        marker=mk,
                        text=hover,
                        hovertemplate=(
                            "marker=%{text}<br>MAF(before)=%{x:.3f}<br>MAF(after)=%{y:.3f}<extra></extra>" if hover else None
                        ),
                        showlegend=False,
                    ),
                    row=2,
                    col=1,
                )
                fig.update_xaxes(title_text="MAF (before)", row=2, col=1)
                fig.update_yaxes(title_text="MAF (after)", row=2, col=1)
                maf_scatter_ok = True
    except Exception:
        maf_scatter_ok = False

    if not maf_scatter_ok:
        try:
            if maf_a_col:
                x = pd.to_numeric(md2[maf_a_col], errors="coerce")
                if x.notna().any():
                    fig.add_trace(go.Histogram(x=x, nbinsx=50, showlegend=False), row=2, col=1)
                    fig.update_xaxes(title_text="MAF (after)", row=2, col=1)
                    fig.update_yaxes(title_text="# markers", row=2, col=1)
        except Exception:
            pass

    # ΔMAF
    try:
        if maf_b_col and maf_a_col:
            xb = pd.to_numeric(md2[maf_b_col], errors="coerce")
            ya = pd.to_numeric(md2[maf_a_col], errors="coerce")
            d = (ya - xb).replace([np.inf, -np.inf], np.nan).dropna()
            if len(d) > 0:
                fig.add_trace(go.Histogram(x=d, nbinsx=60, showlegend=False), row=2, col=2)
                fig.update_xaxes(title_text="ΔMAF", row=2, col=2)
                fig.update_yaxes(title_text="# markers", row=2, col=2)
                fig.add_vline(x=0.0, line_dash="dash", row=2, col=2)
    except Exception:
        pass

    fig = _apply_common_plotly_layout(fig, title, settings)
    return fig


def build_phenotype_imputation_qc_figure_trait_summary(
    trait_summary_tsv: Path,
    sample_summary_tsv: Path | None = None,
    *,
    title: str = "Phenotype Imputation QC",
    settings: dict | None = None,
):
    """Return a Plotly figure for phenotype-imputation QC using trait/sample summary TSVs.

    Focus on what is informative for phenotype imputation:
      - Missingness BEFORE imputation (trait & sample)
      - Distribution shift induced by imputation (mean / SD before vs after)

    Runner `impute_phenotypes` writes:
      - trait_summary.tsv: missing_before/after, mean_before/after, sd_before/after
      - sample_summary.tsv: missing_before/after
    """
    go, pio, _qual = _try_import_plotly()
    if go is None:
        return None
    try:
        from plotly.subplots import make_subplots  # type: ignore
    except Exception:
        return None

    try:
        td = pd.read_csv(trait_summary_tsv, sep="	")
    except Exception:
        return None

    sd = None
    if sample_summary_tsv is not None:
        try:
            if Path(sample_summary_tsv).exists():
                sd = pd.read_csv(sample_summary_tsv, sep="	")
        except Exception:
            sd = None

    # normalize column names to lowercase
    td2 = td.rename(columns={c: str(c).strip().lower() for c in td.columns})
    sd2 = None
    if sd is not None and not sd.empty:
        sd2 = sd.rename(columns={c: str(c).strip().lower() for c in sd.columns})

    # pick columns
    trait_col = None
    for cand in ["trait", "id", "pheno", "phenotype"]:
        if cand in td2.columns:
            trait_col = cand
            break

    miss_b_col = None
    for cand in [
        "missing_before",
        "missing_rate_before",
        "missing_before_rate",
        "missingrate_before",
        "missing_rate",
        "missing",
        "miss",
        "miss_rate",
    ]:
        if cand in td2.columns:
            miss_b_col = cand
            break

    mean_b_col = None
    for cand in ["mean_before", "mu_before", "avg_before", "mean"]:
        if cand in td2.columns:
            mean_b_col = cand
            break

    mean_a_col = None
    for cand in ["mean_after", "mu_after", "avg_after"]:
        if cand in td2.columns:
            mean_a_col = cand
            break

    sd_b_col = None
    for cand in ["sd_before", "stdev_before", "std_before", "sd"]:
        if cand in td2.columns:
            sd_b_col = cand
            break

    sd_a_col = None
    for cand in ["sd_after", "stdev_after", "std_after"]:
        if cand in td2.columns:
            sd_a_col = cand
            break

    smiss_b_col = None
    if sd2 is not None:
        for cand in [
            "missing_before",
            "missing_rate_before",
            "missing_before_rate",
            "missingrate_before",
            "missing_rate",
            "missing",
            "miss",
            "miss_rate",
        ]:
            if cand in sd2.columns:
                smiss_b_col = cand
                break

    fig = make_subplots(
        rows=2,
        cols=2,
        subplot_titles=[
            "Trait missingness (before)",
            "Sample missingness (before)",
            "Trait mean (before vs after)",
            "Trait SD (before vs after)",
        ],
        specs=[[{"type": "histogram"}, {"type": "histogram"}],
               [{"type": "scatter"}, {"type": "scatter"}]],
        vertical_spacing=0.15,
        horizontal_spacing=0.10,
    )

    # trait missingness before
    try:
        if miss_b_col:
            x = pd.to_numeric(td2[miss_b_col], errors="coerce")
            if x.notna().any():
                fig.add_trace(go.Histogram(x=x, nbinsx=50, showlegend=False), row=1, col=1)
                fig.update_xaxes(title_text="missing rate", row=1, col=1)
                fig.update_yaxes(title_text="# traits", row=1, col=1)
    except Exception:
        pass

    # sample missingness before
    try:
        if sd2 is not None and smiss_b_col:
            x = pd.to_numeric(sd2[smiss_b_col], errors="coerce")
            if x.notna().any():
                fig.add_trace(go.Histogram(x=x, nbinsx=50, showlegend=False), row=1, col=2)
                fig.update_xaxes(title_text="missing rate", row=1, col=2)
                fig.update_yaxes(title_text="# samples", row=1, col=2)
    except Exception:
        pass

    # mean before vs after
    mean_scatter_ok = False
    try:
        if mean_b_col and mean_a_col:
            xb = pd.to_numeric(td2[mean_b_col], errors="coerce")
            ya = pd.to_numeric(td2[mean_a_col], errors="coerce")
            if xb.notna().any() and ya.notna().any():
                mx = float(np.nanmax([np.nanmax(xb.values), np.nanmax(ya.values), 0.0]))
                mn = float(np.nanmin([np.nanmin(xb.values), np.nanmin(ya.values), 0.0]))
                fig.add_trace(
                    go.Scatter(x=[mn, mx], y=[mn, mx], mode="lines", line=dict(dash="dash"), showlegend=False),
                    row=2,
                    col=1,
                )

                mk = dict(size=5, opacity=0.75)
                if miss_b_col:
                    cb = pd.to_numeric(td2[miss_b_col], errors="coerce")
                    if cb.notna().any():
                        mk["color"] = cb
                        mk["colorscale"] = "Viridis"
                        mk["showscale"] = True
                        mk["colorbar"] = dict(title="missing_before")

                hover = None
                if trait_col and trait_col in td2.columns:
                    try:
                        hover = td2[trait_col].astype(str).tolist()
                    except Exception:
                        hover = None

                fig.add_trace(
                    go.Scatter(
                        x=xb,
                        y=ya,
                        mode="markers",
                        marker=mk,
                        text=hover,
                        hovertemplate=(
                            "trait=%{text}<br>mean(before)=%{x:.4g}<br>mean(after)=%{y:.4g}<extra></extra>" if hover else None
                        ),
                        showlegend=False,
                    ),
                    row=2,
                    col=1,
                )
                fig.update_xaxes(title_text="mean (before)", row=2, col=1)
                fig.update_yaxes(title_text="mean (after)", row=2, col=1)
                mean_scatter_ok = True
    except Exception:
        mean_scatter_ok = False

    if not mean_scatter_ok:
        try:
            if mean_a_col:
                x = pd.to_numeric(td2[mean_a_col], errors="coerce")
                if x.notna().any():
                    fig.add_trace(go.Histogram(x=x, nbinsx=50, showlegend=False), row=2, col=1)
                    fig.update_xaxes(title_text="mean (after)", row=2, col=1)
                    fig.update_yaxes(title_text="# traits", row=2, col=1)
        except Exception:
            pass

    # SD before vs after
    sd_scatter_ok = False
    try:
        if sd_b_col and sd_a_col:
            xb = pd.to_numeric(td2[sd_b_col], errors="coerce")
            ya = pd.to_numeric(td2[sd_a_col], errors="coerce")
            if xb.notna().any() and ya.notna().any():
                mx = float(np.nanmax([np.nanmax(xb.values), np.nanmax(ya.values), 0.0]))
                mn = float(np.nanmin([np.nanmin(xb.values), np.nanmin(ya.values), 0.0]))
                fig.add_trace(
                    go.Scatter(x=[mn, mx], y=[mn, mx], mode="lines", line=dict(dash="dash"), showlegend=False),
                    row=2,
                    col=2,
                )

                mk = dict(size=5, opacity=0.75)
                if miss_b_col:
                    cb = pd.to_numeric(td2[miss_b_col], errors="coerce")
                    if cb.notna().any():
                        mk["color"] = cb
                        mk["colorscale"] = "Viridis"
                        mk["showscale"] = True
                        mk["colorbar"] = dict(title="missing_before")

                hover = None
                if trait_col and trait_col in td2.columns:
                    try:
                        hover = td2[trait_col].astype(str).tolist()
                    except Exception:
                        hover = None

                fig.add_trace(
                    go.Scatter(
                        x=xb,
                        y=ya,
                        mode="markers",
                        marker=mk,
                        text=hover,
                        hovertemplate=(
                            "trait=%{text}<br>sd(before)=%{x:.4g}<br>sd(after)=%{y:.4g}<extra></extra>" if hover else None
                        ),
                        showlegend=False,
                    ),
                    row=2,
                    col=2,
                )
                fig.update_xaxes(title_text="sd (before)", row=2, col=2)
                fig.update_yaxes(title_text="sd (after)", row=2, col=2)
                sd_scatter_ok = True
    except Exception:
        sd_scatter_ok = False

    if not sd_scatter_ok:
        try:
            if sd_a_col:
                x = pd.to_numeric(td2[sd_a_col], errors="coerce")
                if x.notna().any():
                    fig.add_trace(go.Histogram(x=x, nbinsx=50, showlegend=False), row=2, col=2)
                    fig.update_xaxes(title_text="sd (after)", row=2, col=2)
                    fig.update_yaxes(title_text="# traits", row=2, col=2)
        except Exception:
            pass

    fig = _apply_common_plotly_layout(fig, title, settings)
    return fig


def build_cross_imputation_qc_figure_from_imputed(
    imputed_tsv: Path,
    *,
    title: str = "Cross-population Imputation QC",
    settings: dict | None = None,
):
    """Return a Plotly figure for cross-population imputation QC using an imputed genotype matrix TSV."""
    go, pio, _qual = _try_import_plotly()
    if go is None:
        return None
    try:
        from plotly.subplots import make_subplots  # type: ignore
    except Exception:
        return None

    summ = summarize_genotype_matrix_tsv(imputed_tsv)
    if not summ:
        return None

    mm = summ.get("marker_missing") or []
    sm = summ.get("sample_missing") or []
    maf = summ.get("marker_maf") or []
    gc = summ.get("genotype_counts") or {"0": 0, "1": 0, "2": 0, "NA": 0}

    fig = make_subplots(
        rows=2, cols=2,
        subplot_titles=[
            "Marker missingness (after)",
            "Sample missingness (after)",
            "MAF (after)",
            "Genotype counts (after)"
        ],
        horizontal_spacing=0.12, vertical_spacing=0.15
    )

    try:
        if mm:
            fig.add_trace(go.Histogram(x=mm, nbinsx=50, showlegend=False), row=1, col=1)
            fig.update_xaxes(title_text="missing rate", row=1, col=1)
            fig.update_yaxes(title_text="count", row=1, col=1)
    except Exception:
        pass
    try:
        if sm:
            fig.add_trace(go.Histogram(x=sm, nbinsx=50, showlegend=False), row=1, col=2)
            fig.update_xaxes(title_text="missing rate", row=1, col=2)
            fig.update_yaxes(title_text="count", row=1, col=2)
    except Exception:
        pass
    try:
        if maf:
            fig.add_trace(go.Histogram(x=maf, nbinsx=50, showlegend=False), row=2, col=1)
            fig.update_xaxes(title_text="MAF", row=2, col=1)
            fig.update_yaxes(title_text="count", row=2, col=1)
    except Exception:
        pass

    try:
        fig.add_trace(go.Bar(x=list(gc.keys()), y=[gc[k] for k in gc.keys()], showlegend=False), row=2, col=2)
        fig.update_xaxes(title_text="genotype", row=2, col=2)
        fig.update_yaxes(title_text="count", row=2, col=2)
    except Exception:
        pass

    extra = f"(orientation={summ.get('orientation')}, used_cols={summ.get('used_cols')}/{summ.get('n_cols')})"
    fig = _apply_common_plotly_layout(fig, f"{title} {extra}", settings)
    return fig

class PreprocessTab(QWidget):
    """
    Preprocess:
      - TSV genotype -> PLINK
      - VCF -> PLINK
      - Genotype imputation (Mean / rrBLUP-EM / missRanger-RF / Beagle)

    Reads out/artifacts.json and can auto-fill GWAS plink prefix.
    """
    PLUGIN_TSV = "prep_tsv_to_plink"
    PLUGIN_VCF = "prep_vcf_to_plink"

    PLUGIN_PLINK_TO_TSV = "prep_plink_to_tsv"
    PLUGIN_VCF_TO_TSV = "prep_vcf_to_tsv"
    PLUGIN_RQTL_TO_TSV = "prep_rqtl_to_tsv"
    PLUGIN_CROSS2_TO_TSV = "prep_cross2_to_tsv"

    PLUGIN_TSV_TO_PLINK = "prep_tsv_to_plink"
    PLUGIN_TSV_TO_VCF = "prep_tsv_to_vcf"
    PLUGIN_TSV_TO_CROSS = "prep_tsv_to_cross"
    PLUGIN_TSV_TO_CROSS2 = "prep_tsv_to_cross2"
    
    PLUGIN_IMPUTE = "impute_genotypes"
    PLUGIN_IMPUTE_PHENO = "impute_phenotypes"

    MODES = ["TSV", "VCF", "PLINK", "RQTL", "RQTL2"]

    def __init__(self, app_log: QTextEdit, results: ResultsPane, gwas_tab: GWASTab, gp_tab: 'GenomicPredictionTab', map_tab: 'LinkageMapTab'):
        super().__init__()
        self.app_log = app_log
        self.log = app_log  # alias for compatibility
        self.results = results
        self.gwas_tab = gwas_tab
        self.gp_tab = gp_tab
        self.map_tab = map_tab

        # --- File converter (input -> all other formats) ---
