    def _hbox(self, le: QLineEdit, btn: QPushButton) -> QWidget:
        w = QWidget()
        h = QHBoxLayout()
        h.setContentsMargins(0, 0, 0, 0)
        h.addWidget(le)
        h.addWidget(btn)
        w.setLayout(h)
        return w

    def append_log(self, s: str):
        self.app_log.append(s)

    def _refresh_mode_ui(self, mode_text: str):
        mt = (mode_text or "").strip().upper()

        # Marker map is only necessary for TSV input.
        self.fc_marker_map_file.setEnabled(mt == "TSV")

        # Cross type is only relevant when generating RQTL output (i.e. input is not already RQTL).
        self.fc_cross_type.setEnabled(mt != "RQTL")

        # Hint for genotype input
        if mt == "TSV":
            self.fc_genotype_file.setPlaceholderText("genotype.tsv (wide; id + markers)")
        elif mt == "VCF":
            self.fc_genotype_file.setPlaceholderText("genotype.vcf or genotype.vcf.gz")
        elif mt == "PLINK":
            self.fc_genotype_file.setPlaceholderText("PLINK .bed (with matching .bim/.fam)")
        elif mt == "RQTL":
            self.fc_genotype_file.setPlaceholderText("R/qtl cross object (.rds)")
        elif mt == "RQTL2":
            self.fc_genotype_file.setPlaceholderText("qtl2 cross2 YAML (.yaml/.yml) or RDS")
    def _refresh_imp_ui(self, method: str):
        is_beagle = (method == "Beagle")
        is_em = (method == "EM")
        is_rf = (method == "RF")

        self.imp_marker_map_tsv.setEnabled(is_beagle)
        self.imp_vcf_path.setEnabled(is_beagle)
        self.imp_beagle_jar.setEnabled(is_beagle)

        # EM
        self.em_tol.setEnabled(is_em)
        self.em_n_core.setEnabled(is_em)
        self.em_clip.setEnabled(is_em)

        # RF
        for w in [self.rf_num_trees, self.rf_maxiter, self.rf_pmm_k, self.rf_seed, self.rf_max_markers, self.rf_allow_large]:
            w.setEnabled(is_rf)

        # Beagle
        self.beagle_nthreads.setEnabled(is_beagle)
        self.beagle_java_mem.setEnabled(is_beagle)

        # Show only the selected method's option box (reduce vertical clutter)
        try:
            self.imp_em_box.setVisible(is_em)
            self.imp_rf_box.setVisible(is_rf)
            self.imp_beagle_box.setVisible(is_beagle)
        except Exception:
            pass


    def _refresh_pheno_imp_ui(self, method: str):
        mt = method.strip().lower()
        is_phenix = (mt == "phenix")
        is_mf = (mt in ("missforest", "rf"))
        is_mice = (mt == "mice")
        is_si = (mt == "softimpute")

        self.ph_kinship_tsv.setEnabled(is_phenix)

        for w in [self.ph_rf_ntree, self.ph_rf_maxiter]:
            w.setEnabled(is_mf)

        for w in [self.ph_mice_m, self.ph_mice_maxit]:
            w.setEnabled(is_mice)

        for w in [self.si_rank_max, self.si_type]:
            w.setEnabled(is_si)

        for w in [self.ph_phenix_scale, self.ph_phenix_quantnorm]:
            w.setEnabled(is_phenix)

        # Show only the selected method's option box (Map/Construction-style)
        try:
            self.ph_rf_box.setVisible(is_mf)
            self.ph_mice_box.setVisible(is_mice)
            self.ph_si_box.setVisible(is_si)
            self.ph_phenix_box.setVisible(is_phenix)
        except Exception:
            pass



    def pick_fc_genotype_file(self):
        mt = (self.mode.currentText() or "").strip().upper()
        if mt == "TSV":
            flt = "TSV (*.tsv *.txt *.csv);;All (*.*)"
        elif mt == "VCF":
            flt = "VCF (*.vcf *.vcf.gz);;All (*.*)"
        elif mt == "PLINK":
            flt = "PLINK (*.bed *.bim *.fam);;All (*.*)"
        elif mt == "RQTL":
            flt = "RDS (*.rds);;All (*.*)"
        elif mt == "RQTL2":
            flt = "YAML (*.yaml *.yml);;RDS (*.rds);;All (*.*)"
        else:
            flt = "All (*.*)"
        fp, _ = QFileDialog.getOpenFileName(self, f"Select genotype file ({mt})", "", flt)
        if fp:
            self.fc_genotype_file.setText(fp)

    def pick_fc_marker_map_file(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select marker_map.tsv", "", "TSV (*.tsv *.txt);;All (*.*)")
        if fp:
            self.fc_marker_map_file.setText(fp)

    def pick_fc_phenotype_file(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select phenotype file", "", "TSV/CSV (*.tsv *.txt *.csv);;All (*.*)")
        if fp:
            self.fc_phenotype_file.setText(fp)

    def pick_fc_output_folder(self):
        d = QFileDialog.getExistingDirectory(self, "Select output folder")
        if d:
            self.fc_output_folder.setText(d)

    def _safe_copy(self, src: Path, dst: Path):
        dst.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(src, dst)

    def _run_plugin_step(self, plugin_id: str, params: dict, label: str):
        # Run a plugin step using the global registry.
        # Returns: (ok: bool, out_dir: Path, run_dir: Path)
        run_dir = Path(tempfile.mkdtemp(prefix=f"fileconv_{plugin_id}_"))
        self._log_msg(f"Running: {label} (plugin={plugin_id})")
        try:
            out_dir = Path(run_plugin(REGISTRY_PATH, plugin_id, params, run_dir))
            return True, out_dir, run_dir
        except Exception as e:
            # Try to enrich the message with stderr tail if present
            out_dir = run_dir / "out"
            tail = ""
            try:
                stderr_path = out_dir / "stderr.txt"
                if stderr_path.exists():
                    lines = stderr_path.read_text(encoding='utf-8', errors='ignore').splitlines()
                    tail = "\n".join(lines[-20:])
            except Exception:
                tail = ""
            msg = f"{label} failed: {e}"
            if tail:
                msg += "\n--- stderr tail ---\n" + tail
            self._log_msg("[ERROR] " + msg)
            return False, out_dir, run_dir
    def _log_msg(self, msg: str) -> None:
        """Append message to log widget regardless of QPlainTextEdit/QTextEdit"""
        w = getattr(self, 'log', None)
        if w is None:
            return
        if hasattr(w, 'appendPlainText'):
            w.appendPlainText(msg)
        elif hasattr(w, 'append'):
            w.append(msg)
        else:
            try:
                w.setPlainText((w.toPlainText() if hasattr(w, 'toPlainText') else '') + msg + '\n')
            except Exception:
                pass

    def run_preprocess(self):
        """File converter: generate all formats except the selected input format."""
        in_mode = (self.mode.currentText() or "").strip().upper()
        geno_txt = self.fc_genotype_file.text().strip()
        out_txt = self.fc_output_folder.text().strip()

        if in_mode not in set(self.MODES):
            QMessageBox.warning(self, "Error", "Please select a valid Mode")
            return
        if not geno_txt:
            QMessageBox.warning(self, "Error", "Please select a genotype file")
            return
        geno_path = Path(geno_txt)
        if not geno_path.exists():
            QMessageBox.warning(self, "Error", "Genotype file not found")
            return
        if not out_txt:
            QMessageBox.warning(self, "Error", "Please select an output folder")
            return
        out_folder = Path(out_txt)
        out_folder.mkdir(parents=True, exist_ok=True)

        prefix = self.fc_prefix.text().strip()
        cross_type = (self.fc_cross_type.currentText() or "f2").strip() or "f2"

        # PLINK input is a prefix; accept .bed selection and derive the prefix
        plink_prefix = None
        if in_mode == "PLINK":
            if geno_path.suffix.lower() in {".bed", ".bim", ".fam"}:
                plink_prefix = geno_path.with_suffix("")
            else:
                plink_prefix = geno_path
            if not (Path(str(plink_prefix) + '.bed').exists() and Path(str(plink_prefix) + '.bim').exists() and Path(str(plink_prefix) + '.fam').exists()):
                QMessageBox.warning(self, "Error", "PLINK input requires .bed/.bim/.fam with the same prefix")
                return

        # auto prefix
        if not prefix:
            stem = plink_prefix.name if plink_prefix else geno_path.stem
            stem = re.sub(r'[^0-9A-Za-z._-]+', '_', stem)
            prefix = stem + '_' + time.strftime('%Y%m%d_%H%M%S')

        out_root = out_folder / prefix
        if out_root.exists():
            out_root = out_folder / (prefix + '_' + time.strftime('%H%M%S'))
        out_root.mkdir(parents=True, exist_ok=True)

        self._log_msg(f"[INFO] Output: {out_root}")

        inter_tsv = out_root / '_intermediate' / 'tsv'
        inter_tsv.mkdir(parents=True, exist_ok=True)

        user_ph = Path(self.fc_phenotype_file.text().strip()) if self.fc_phenotype_file.text().strip() else None
        if user_ph and not user_ph.exists():
            QMessageBox.warning(self, "Error", "Phenotype file not found")
            return
        user_mm = Path(self.fc_marker_map_file.text().strip()) if self.fc_marker_map_file.text().strip() else None
        if user_mm and not user_mm.exists():
            QMessageBox.warning(self, "Error", "Marker map file not found")
            return

        geno_tsv = None
        marker_map_tsv = None
        phenotype_tsv = None

        try:
            if in_mode == "TSV":
                geno_tsv = geno_path
                marker_map_tsv = user_mm
                phenotype_tsv = user_ph
                # Auto-detect marker_map.tsv / phenotype.tsv in the same folder when not specified
                if marker_map_tsv is None:
                    cand = geno_path.parent / 'marker_map.tsv'
                    if cand.exists():
                        marker_map_tsv = cand
                if phenotype_tsv is None:
                    cand = geno_path.parent / 'phenotype.tsv'
                    if cand.exists():
                        phenotype_tsv = cand
            elif in_mode == "VCF":
                ok, _, _ = self._run_plugin_step(self.PLUGIN_VCF_TO_TSV, {'vcf_path': str(geno_path), 'out_dir_override': str(inter_tsv)}, 'VCF -> TSV')
                if not ok:
                    raise RuntimeError('VCF -> TSV failed')
                geno_tsv = inter_tsv / 'genotype.tsv'
                marker_map_tsv = inter_tsv / 'marker_map.tsv'
            elif in_mode == "PLINK":
                ok, _, _ = self._run_plugin_step(self.PLUGIN_PLINK_TO_TSV, {'plink_prefix': str(plink_prefix), 'out_dir_override': str(inter_tsv)}, 'PLINK -> TSV')
                if not ok:
                    raise RuntimeError('PLINK -> TSV failed')
                geno_tsv = inter_tsv / 'genotype.tsv'
                marker_map_tsv = inter_tsv / 'marker_map.tsv'
            elif in_mode == "RQTL":
                ok, _, _ = self._run_plugin_step(self.PLUGIN_RQTL_TO_TSV, {'cross_rds': str(geno_path), 'out_dir_override': str(inter_tsv)}, 'RQTL -> TSV')
                if not ok:
                    raise RuntimeError('RQTL -> TSV failed')
                geno_tsv = inter_tsv / 'genotype.tsv'
                marker_map_tsv = inter_tsv / 'marker_map.tsv'
                phenotype_tsv = inter_tsv / 'phenotype.tsv'
            elif in_mode == "RQTL2":
                ok, _, _ = self._run_plugin_step(self.PLUGIN_CROSS2_TO_TSV, {'cross2_path': str(geno_path), 'out_dir_override': str(inter_tsv)}, 'RQTL2 -> TSV')
                if not ok:
                    raise RuntimeError('RQTL2 -> TSV failed')
                geno_tsv = inter_tsv / 'genotype.tsv'
                marker_map_tsv = inter_tsv / 'marker_map.tsv'
                phenotype_tsv = inter_tsv / 'phenotype.tsv'

            if not geno_tsv or not geno_tsv.exists():
                raise RuntimeError('genotype.tsv not found after conversion')

            if user_ph:
                dst = inter_tsv / 'phenotype.tsv'
                self._safe_copy(user_ph, dst)
                phenotype_tsv = dst

            if marker_map_tsv and not marker_map_tsv.exists():
                marker_map_tsv = None
            if phenotype_tsv and not phenotype_tsv.exists():
                phenotype_tsv = None

        except Exception as e:
            QMessageBox.critical(self, "Error", str(e))
            return

        outputs = []
        self.last_plink_prefix = None

        try:
            for fmt in self.MODES:
                if fmt == in_mode:
                    continue

                if fmt == "TSV":
                    od = out_root / 'tsv'
                    od.mkdir(parents=True, exist_ok=True)
                    self._safe_copy(geno_tsv, od / 'genotype.tsv')
                    if marker_map_tsv:
                        self._safe_copy(marker_map_tsv, od / 'marker_map.tsv')
                    if phenotype_tsv:
                        self._safe_copy(phenotype_tsv, od / 'phenotype.tsv')
                    outputs.append((fmt, str(od)))

                elif fmt == "VCF":
                    od = out_root / 'vcf'
                    od.mkdir(parents=True, exist_ok=True)
                    out_vcf = od / f"{prefix}.vcf"
                    ok, _, _ = self._run_plugin_step(self.PLUGIN_TSV_TO_VCF, {'genotype_tsv': str(geno_tsv), 'marker_map_tsv': str(marker_map_tsv) if marker_map_tsv else '', 'out_vcf': str(out_vcf)}, 'TSV -> VCF')
                    if not ok:
                        raise RuntimeError('TSV -> VCF failed')
                    outputs.append((fmt, str(out_vcf)))

                elif fmt == "PLINK":
                    od = out_root / 'plink'
                    od.mkdir(parents=True, exist_ok=True)
                    out_prefix = od / prefix
                    ok, outp, _ = self._run_plugin_step(self.PLUGIN_TSV_TO_PLINK, {'genotype_tsv': str(geno_tsv), 'marker_map_tsv': str(marker_map_tsv) if marker_map_tsv else '', 'out_prefix': str(out_prefix)}, 'TSV -> PLINK')
                    if not ok:
                        raise RuntimeError('TSV -> PLINK failed')
                    bm = outp / 'bedmatrix.rds'
                    if bm.exists():
                        self._safe_copy(bm, od / 'bedmatrix.rds')
                    self.last_plink_prefix = str(out_prefix)
                    outputs.append((fmt, str(out_prefix)))

                elif fmt == "RQTL":
                    od = out_root / 'rqtl'
                    od.mkdir(parents=True, exist_ok=True)
                    ok, outp, _ = self._run_plugin_step(self.PLUGIN_TSV_TO_CROSS, {'genotype_tsv': str(geno_tsv), 'phenotype_tsv': str(phenotype_tsv) if phenotype_tsv else '', 'marker_map_tsv': str(marker_map_tsv) if marker_map_tsv else '', 'cross_type': cross_type}, 'TSV -> RQTL')
                    if not ok:
                        raise RuntimeError('TSV -> RQTL failed')
                    for fn in ['cross.rds', 'sample_summary.tsv', 'marker_summary.tsv']:
                        fsrc = outp / fn
                        if fsrc.exists():
                            self._safe_copy(fsrc, od / fn)
                    outputs.append((fmt, str(od / 'cross.rds')))

                elif fmt == "RQTL2":
                    od = out_root / 'rqtl2'
                    od.mkdir(parents=True, exist_ok=True)
                    ok, _, _ = self._run_plugin_step(self.PLUGIN_TSV_TO_CROSS2, {'genotype_tsv': str(geno_tsv), 'phenotype_tsv': str(phenotype_tsv) if phenotype_tsv else '', 'marker_map_tsv': str(marker_map_tsv) if marker_map_tsv else '', 'cross_type': cross_type, 'out_dir_override': str(od)}, 'TSV -> RQTL2')
                    if not ok:
                        raise RuntimeError('TSV -> RQTL2 failed')
                    outputs.append((fmt, str(od / 'cross2.yaml')))

            import pandas as pd
            df = pd.DataFrame(outputs, columns=['format', 'path'])
            summary_path = out_root / 'file_converter_summary.tsv'
            df.to_csv(summary_path, sep='	', index=False)
            self.results.set_table_df(df, source_path=summary_path)
            self._log_msg('[OK] File conversion completed')

        except Exception as e:
            QMessageBox.critical(self, "Error", str(e))
            return

    def send_prefix_to_gwas(self):
        """Compatibility: send last PLINK output prefix to GWAS tab."""
        if not getattr(self, 'last_plink_prefix', None):
            QMessageBox.warning(self, "Info", "No PLINK output prefix available yet")
            return
        self.gwas_tab.plink_prefix.setText(self.last_plink_prefix)
        QMessageBox.information(self, "OK", "Sent PLINK prefix to GWAS tab")

