    def _detect_preprocess_kind_from_outdir(self, base: Path) -> str:
        """Heuristic detection of which QC dashboard can be built from the folder."""
        b = Path(base)
        # phenotype
        if (b / "trait_summary.tsv").exists() or (b / "pheno_missing_before.tsv").exists() or (b / "qc_phenotype_imputation.html").exists() or (b / "plots" / "qc_phenotype_imputation.html").exists():
            return "phenotype"
        # cross
        if (b / "imputed.tsv").exists() or (b / "missing_rates_before.tsv").exists() or (b / "qc_cross_imputation.html").exists() or (b / "plots" / "qc_cross_imputation.html").exists():
            return "cross"
        # genotype (default)
        if (b / "marker_summary.tsv").exists() or (b / "missing_before.tsv").exists() or (b / "qc_genotype_imputation.html").exists() or (b / "plots" / "qc_genotype_imputation.html").exists():
            return "genotype"
        return "genotype"

    def draw_from_out_dir(self):
        out_dir = (self.draw_out_dir.text() or "").strip()
        if not out_dir:
            QMessageBox.warning(self, "Missing", "Please select output_folder.")
            return
        base = Path(out_dir)
        if not base.exists():
            QMessageBox.warning(self, "Not found", f"output_folder not found: {base}")
            return

        ktxt = str(self.draw_kind.currentText()).strip().lower()
        if ktxt.startswith("auto"):
            kind = self._detect_preprocess_kind_from_outdir(base)
        elif ktxt.startswith("geno"):
            kind = "genotype"
        elif ktxt.startswith("pheno"):
            kind = "phenotype"
        else:
            kind = "cross"

        title = (self.draw_title.text() or "").strip() or None
        try:
            self.results.set_preprocess_plotly_context(base, kind=kind, title=title)
        except Exception as e:
            QMessageBox.warning(self, "Draw failed", f"Failed to draw preprocess QC.\n\n{e}")

