        self.results = results
        self.anno_tab = anno_tab
        self.gene_pred_tab = gene_pred_tab
        self.blast_tab = blast_tab

        self.gff_per_peak_tsv = QLineEdit()
        self.pred_near_tsv = QLineEdit()
        self.pred_gff3 = QLineEdit()

        self.genome_fasta = QLineEdit()
        self.gff_files = QLineEdit("")  # comma-separated

        self.only_best_per_peak = QComboBox()
        self.only_best_per_peak.addItems(["FALSE", "TRUE"])

        self.output_view = QComboBox()
        self.output_view.addItems(["merged_candidates.tsv", "extract_summary.tsv", "queries.faa"])

        # Buttons
        b_pick_gff = QPushButton("Select Annotate per_peak_genes.tsv")
        b_pick_gff.clicked.connect(lambda *args, **kwargs: self.pick_gff_per_peak())
        b_pick_pred = QPushButton("Select GenePred predicted_near_peaks.tsv")
        b_pick_pred.clicked.connect(lambda *args, **kwargs: self.pick_pred_near())
        b_pick_predgff = QPushButton("Select GenePred predicted.gff3")
        b_pick_predgff.clicked.connect(lambda *args, **kwargs: self.pick_pred_gff3())

        b_use_last_anno = QPushButton("Use last Annotate per_peak_genes.tsv")
        b_use_last_anno.clicked.connect(lambda *args, **kwargs: self.use_last_annotate())
        b_use_last_pred = QPushButton("Use last GenePred outputs")
        b_use_last_pred.clicked.connect(lambda *args, **kwargs: self.use_last_gene_pred())

        b_merge = QPushButton("Merge candidates")
        b_merge.clicked.connect(lambda *args, **kwargs: self.merge_candidates())
        b_save = QPushButton("Save merged TSV")
        b_save.clicked.connect(lambda *args, **kwargs: self.save_merged())

        b_genome = QPushButton("Select genome FASTA")
        b_genome.clicked.connect(lambda *args, **kwargs: self.pick_genome())
        b_gffs = QPushButton("Add GFF/GTF to search (append)")
        b_gffs.clicked.connect(lambda *args, **kwargs: self.add_gff_file())

        b_extract = QPushButton("Prepare protein FASTA for BLAST (experimental)")
        b_extract.clicked.connect(lambda *args, **kwargs: self.run_extract())
        b_send = QPushButton("Send queries.faa to BLAST")
        b_send.clicked.connect(lambda *args, **kwargs: self.send_to_blast())

        # Layout
        form = QFormLayout()
        form.addRow(QLabel("Inputs (from previous runs)"))
        form.addRow("annotate per_peak_genes.tsv", self.gff_per_peak_tsv)
        h1 = QHBoxLayout(); h1.addWidget(b_pick_gff); h1.addWidget(b_use_last_anno)
        w1 = QWidget(); w1.setLayout(h1)
        form.addRow("", w1)

        form.addRow("genePred predicted_near_peaks.tsv", self.pred_near_tsv)
        h2 = QHBoxLayout(); h2.addWidget(b_pick_pred); h2.addWidget(b_use_last_pred)
        w2 = QWidget(); w2.setLayout(h2)
        form.addRow("", w2)

        form.addRow("genePred predicted.gff3 (opt)", self.pred_gff3)
        h3 = QHBoxLayout(); h3.addWidget(b_pick_predgff)
        w3 = QWidget(); w3.setLayout(h3)
        form.addRow("", w3)

        form.addRow(QLabel("Merge options"))
        form.addRow("only_best_per_peak", self.only_best_per_peak)

        form.addRow(QLabel("Sequence extraction (to feed BLAST)"))
        form.addRow("genome FASTA", self.genome_fasta)
        form.addRow("", b_genome)
        form.addRow("gff_files (comma)", self.gff_files)
        form.addRow("", b_gffs)

        form.addRow("view", self.output_view)

        h4 = QHBoxLayout(); h4.addWidget(b_merge); h4.addWidget(b_save)
        w4 = QWidget(); w4.setLayout(h4)
        form.addRow("", w4)

        h5 = QHBoxLayout(); h5.addWidget(b_extract); h5.addWidget(b_send)
        w5 = QWidget(); w5.setLayout(h5)
        form.addRow("", w5)

