    def _on_advanced_toggled(self, checked: bool):
        self.adv_box.setVisible(checked)
        if checked:
            # provide helpful defaults without overwriting user's edits
            if not self.design_formula.text().strip():
                col = self.condition_col.text().strip() or "condition"
                self.design_formula.setText(f"~ {col}")
            if not self.reference_level.text().strip():
                # in 2-group comparisons, reference=B is common
                b = self.cond_b.text().strip()
                if b:
                    self.reference_level.setText(b)

    def _refresh_go_ui(self, v: str):
        enabled = ("GOstats" in v)
        self.orgdb.setEnabled(enabled)
        self.keytype.setEnabled(enabled)
        self.ontology.setEnabled(enabled)


    def _refresh_method_opts(self, *_):
        """Update method-specific option panel (Step2)."""
        m = (self.method.currentText() or "").strip().lower()
        if m == "edger":
            idx = 0
        elif m.startswith("deseq"):
            idx = 1
        elif m == "limma" or m.startswith("voom"):
            idx = 2
        elif m == "noiseq":
            idx = 3
        elif m == "ebseq":
            idx = 4
        else:
            idx = 5
    
        if hasattr(self, "method_opts_stack"):
            self.method_opts_stack.setCurrentIndex(idx)
    
        # enable/disable LRT reduced formula
        self.deseq2_reduced_formula.setEnabled(self.deseq2_test.currentText().strip().upper() == "LRT")
    
        # enable/disable treat thresholds
        self.edger_treat_lfc.setEnabled(self.edger_use_treat.isChecked())
        self.limma_treat_lfc.setEnabled(self.limma_use_treat.isChecked())
    
    
    def pick_counts(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select counts matrix", "", "TSV/CSV (*.tsv *.txt *.csv);;All (*.*)")
        if fp:
            self.counts_path.setText(fp)

    def pick_design(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select design table", "", "TSV/CSV (*.tsv *.txt *.csv);;All (*.*)")
        if fp:
            self.design_path.setText(fp)


    def pick_output_dir(self):
        d = QFileDialog.getExistingDirectory(self, "Select output folder", "")
        if d:
            self.output_dir.setText(d)

    def probe_design(self):
        """Step3: run rnaseq_deg in probe_only mode to obtain model matrix columns / levels.

        This avoids hand-typing coef/contrast names and prevents many runtime errors.
        """
        counts = self.counts_path.text().strip()
        design = self.design_path.text().strip()
        if not counts or not Path(counts).exists():
            QMessageBox.warning(self, "Error", "Counts matrix not set / not found")
            return
        if not design or not Path(design).exists():
            QMessageBox.warning(self, "Error", "Design table not set / not found")
            return

        # Build minimal params; force advanced behavior for probing
        df = self.design_formula.text().strip()
        if not df:
            col = self.condition_col.text().strip() or "condition"
            df = f"~ {col}"
            self.design_formula.setText(df)

        params = {
            "counts_matrix": counts,
            "design_table": design,
            "method": self.method.currentText().strip(),
            "sample_col": self.sample_col.text().strip() or "sample",
            "condition_col": self.condition_col.text().strip() or "condition",
            # "cond_a": self.cond_a.text().strip(),
            # "cond_b": self.cond_b.text().strip(),
            "advanced": True,
            "design_formula": df,
            "reference_level": self.reference_level.text().strip(),
            "subset_to_conditions": ("TRUE" in self.subset_to_conditions.currentText()),
            "probe_only": True,
        }

        run_dir = Path(tempfile.mkdtemp(prefix="rnaseq_probe_"))
        self.append_log(f"Running plugin={self.PLUGIN_ID} (probe_only)")
        self.append_log(f"work_dir={run_dir}")
        try:
            out_dir = run_plugin(REGISTRY_PATH, self.PLUGIN_ID, params, run_dir)
        except Exception as e:
            self.append_log(f"[ERROR] {e}")
            QMessageBox.critical(self, "Probe failed", str(e))
            return

        info_path = Path(out_dir) / "design_info.json"
        if not info_path.exists():
            QMessageBox.warning(self, "Error", f"design_info.json not found: {info_path}")
            self.probe_status.setText("(probe failed)")
            return

        try:
            info = json.loads(info_path.read_text(encoding="utf-8", errors="ignore"))
        except Exception as e:
            QMessageBox.warning(self, "Error", f"Failed to parse design_info.json: {e}")
            self.probe_status.setText("(probe failed)")
            return

        cols = info.get("model_matrix_cols") or []
        rn = info.get("deseq2_results_names") or []
        lv = info.get("condition_levels") or []

        # Update coefficient combos
        self.coef_name.blockSignals(True)
        self.coef_name.clear()
        for c in cols:
            self.coef_name.addItem(str(c))
        self.coef_name.blockSignals(False)
        self.coef_name.setEnabled(len(cols) > 0)

        self.deseq2_results_name.blockSignals(True)
        self.deseq2_results_name.clear()
        for c in rn:
            self.deseq2_results_name.addItem(str(c))
        self.deseq2_results_name.blockSignals(False)
        self.deseq2_results_name.setEnabled(len(rn) > 0)

        # Helpful defaults for A/B if empty
        # if (not self.cond_a.text().strip() or not self.cond_b.text().strip()) and len(lv) >= 2:
        #     if not self.cond_b.text().strip():
        #         self.cond_b.setText(str(lv[0]))
        #     if not self.cond_a.text().strip():
        #         self.cond_a.setText(str(lv[1]))

        self.probe_status.setText(f"(OK: {len(cols)} coef cols, {len(rn)} DESeq2 names)")
        self.append_log(f"[rnaseq_probe] design_info.json: coef_cols={len(cols)}, deseq2_names={len(rn)}")

    def append_log(self, s: str):
        self.log.append(s)

    def _refresh_plot_selector(self, out_dir: Path):
        # Populate with plots that exist
        candidates = [
            ("Volcano", "volcano.png"),
            ("MA", "ma_plot.png"),
            ("QC: PCA", "qc_pca.png"),
            ("QC: sample distance", "qc_sample_distance.png"),
            ("QC: library size", "qc_libsize.png"),
        ]
        self.plot_select.blockSignals(True)
        self.plot_select.clear()
        avail = []
        for label, fn in candidates:
            if (out_dir / fn).exists():
                avail.append((label, fn))
                self.plot_select.addItem(label, fn)
        self.plot_select.blockSignals(False)
        self.plot_select.setEnabled(len(avail) > 0)

        # show first available plot
        if avail:
            self.results.show_plot(out_dir / avail[0][1])
        else:
            self.results.clear_plot("No plot")

    def _enable_plotly_controls(self, enabled: bool):
        self.plotly_select.setEnabled(enabled)
        self.btn_plotly_build.setEnabled(enabled)
        for b in [self.btn_plotly_export_html, self.btn_plotly_export_png, self.btn_plotly_export_svg, self.btn_plotly_export_pdf]:
            b.setEnabled(enabled)

    def _build_rnaseq_plotly(self):
        if not getattr(self, 'last_out_dir', None):
            return
        out_dir = self.last_out_dir
        kind = self.plotly_select.currentText()
        self._rnaseq_plotly_kind = kind

        go, pio, _qual = _try_import_plotly()
        if pio is None:
            QMessageBox.warning(self, 'Plotly', 'Plotly is not available in this environment.')
            return

        try:
            deg_tsv = out_dir / 'deg.tsv'
            norm_tsv = out_dir / 'normalized_counts.tsv'
            design = Path(self.design_path.text().strip())

            fdr = float(self.fdr.text()) if self.fdr.text().strip() else 0.05
            lfc = float(self.lfc.text()) if self.lfc.text().strip() else 1.0
            topn_labels = int(self.plotly_topn_labels.value())

            fig = None
            if kind.startswith('Volcano'):
                df = _read_table_auto_pd(deg_tsv)
                fig = build_rnaseq_volcano_figure(df, title='Volcano plot', fdr=fdr, lfc=lfc, topn_labels=topn_labels)
            elif kind.startswith('MA'):
                df = _read_table_auto_pd(deg_tsv)
                fig = build_rnaseq_ma_figure(df, title='MA plot', lfc=lfc, topn_labels=topn_labels)
            elif 'PCA' in kind:
                if not norm_tsv.exists():
                    norm_tsv = out_dir / 'norm_counts.tsv'
                fig = build_rnaseq_pca_figure(
                    norm_tsv,
                    design,
                    sample_col=(self.sample_col.text().strip() or 'sample'),
                    color_col=(self.condition_col.text().strip() or 'condition'),
                    title='PCA (samples)',
                )
            elif 'Heatmap' in kind:
                if not norm_tsv.exists():
                    norm_tsv = out_dir / 'norm_counts.tsv'
                fig = build_rnaseq_heatmap_figure(
                    norm_tsv,
                    design,
                    sample_col=(self.sample_col.text().strip() or 'sample'),
                    order_col=(self.condition_col.text().strip() or 'condition'),
                    topn=int(self.plotly_heatmap_topn.value()),
                    mode='variance',
                    zscore=bool(self.plotly_heatmap_z.isChecked()),
                    title='Expression heatmap (Top genes)',
                )

            if fig is None:
                raise RuntimeError('Failed to build figure (Plotly not available or insufficient inputs).')

            html_path = out_dir / 'plots' / 'rnaseq_plotly.html'
            html_path.parent.mkdir(parents=True, exist_ok=True)
            html = _plotly_html(fig, pio, add_selection_js=False)
            html_path.write_text(html, encoding='utf-8')

            self._rnaseq_plotly_fig = fig
            self.results.set_plot_html(html_path)
            self.append_log(f"[rnaseq][plotly] built: {kind} -> {html_path}")
        except Exception as e:
            QMessageBox.warning(self, 'Plotly failed', f"Failed to build Plotly figure.\n\n{e}")

    def _export_rnaseq_plotly_html(self):
        if getattr(self, '_rnaseq_plotly_fig', None) is None or not getattr(self, 'last_out_dir', None):
            QMessageBox.information(self, 'Export', 'No Plotly figure available. Build Plotly first.')
            return

        default = str((self.last_out_dir / 'rnaseq_plot.html').resolve())
        out, _ = QFileDialog.getSaveFileName(self, 'Export HTML', default, 'HTML (*.html)')
        if not out:
            return

        go, pio, _qual = _try_import_plotly()
        if pio is None:
            QMessageBox.warning(self, 'Export', 'Plotly is not available.')
            return

        try:
            html = _plotly_html(self._rnaseq_plotly_fig, pio, add_selection_js=False)
            Path(out).write_text(html, encoding='utf-8')
            QMessageBox.information(self, 'Export', f"Saved: {out}")
        except Exception as e:
            QMessageBox.warning(self, 'Export failed', f"Failed to export HTML.\n\n{e}")

    def _export_rnaseq_plotly_image(self, ext: str):
        if getattr(self, '_rnaseq_plotly_fig', None) is None or not getattr(self, 'last_out_dir', None):
            QMessageBox.information(self, 'Export', 'No Plotly figure available. Build Plotly first.')
            return

        out, _ = QFileDialog.getSaveFileName(
            self,
            f"Export {ext.upper()}",
            str((self.last_out_dir / f"rnaseq_plot.{ext}").resolve()),
            f"*.{ext}",
        )
        if not out:
            return

        go, pio, _qual = _try_import_plotly()
        if pio is None:
            QMessageBox.warning(self, 'Export', 'Plotly is not available.')
            return

        try:
            w = int(self.plotly_export_w.value())
            h = int(self.plotly_export_h.value())
            pio.write_image(self._rnaseq_plotly_fig, out, width=w, height=h)
            QMessageBox.information(self, 'Export', f"Saved: {out}")
        except Exception as e:
            QMessageBox.warning(
                self,
                'Export failed',
                f"Failed to export image ({ext}).\n\n{e}\n\nTip: install 'kaleido' in your Python environment to enable static image export.",
            )

    def _on_plot_select(self, label: str):
        if not getattr(self, 'last_out_dir', None):
            return
        fn = self.plot_select.currentData()
        if fn:
            self.results.show_plot(self.last_out_dir / fn)

    def run_deg(self):
        counts = self.counts_path.text().strip()
        design = self.design_path.text().strip()
        if not counts or not Path(counts).exists():
            QMessageBox.warning(self, 'Error', 'Counts matrix not set / not found')
            return
        if not design or not Path(design).exists():
            QMessageBox.warning(self, 'Error', 'Design table not set / not found')
            return

        #cond_a = self.cond_a.text().strip()
        #cond_b = self.cond_b.text().strip()

        # if not self.advanced.isChecked() and (not cond_a or not cond_b):
        #     QMessageBox.warning(self, 'Error', 'Condition A/B are required (Simple mode)')
        #     return

        try:
            fdr = float(self.fdr.text()) if self.fdr.text().strip() else 0.05
        except Exception:
            fdr = 0.05
        try:
            lfc = float(self.lfc.text()) if self.lfc.text().strip() else 0.0
        except Exception:
            lfc = 0.0

        params = {
            'counts': counts,
            'design': design,
            'method': self.method.currentText(),
            'sample_col': self.sample_col.text().strip() or 'sample',
            'condition_col': self.condition_col.text().strip() or 'condition',
            # 'cond_a': cond_a,
            # 'cond_b': cond_b,
            'fdr': fdr,
            'lfc': lfc,
            'gene_id_col': self.gene_id_col.text().strip(),
            'design_formula': self.design_formula.text().strip(),
            'contrast': self.contrast.text().strip(),
            'reference_level': self.reference_level.text().strip(),
            'coef_name': self.coef_name.currentText().strip(),
            'do_go': 'No GO',
            'orgdb': self.orgdb.text().strip(),
            'keytype': self.keytype.text().strip(),
            'ontology': self.ontology.currentText(),
            'k': self.noi_k.value(),
            'norm': self.noi_norm.currentText(),
            'nclust': self.noi_nclust.value(),
            'lc': self.noi_lc.value(),
            'r': self.noi_r.value(),
            'adj': self.noi_adj.value(),
            'a0per': self.noi_a0per.value(),
            'filter': self.noi_filter.value(),
            'eb_fast': self.eb_fast.currentText(),
            'eb_maxround': self.eb_maxround.value(),
        }


        # Optional: export outputs to a user-specified folder (copied by core layer)
        out_root = self.output_dir.text().strip() if hasattr(self, 'output_dir') else ''
        if out_root:
            try:
                Path(out_root).mkdir(parents=True, exist_ok=True)
                params['export_dir'] = out_root
            except Exception as e:
                QMessageBox.warning(self, 'Error', f"Cannot create output_folder: {e}")
                return

        # DESeq2 extra options
        params['deseq2_use_shrink'] = bool(self.deseq2_use_shrink.isChecked())
        params['deseq2_shrink_type'] = self.deseq2_shrink_type.currentText()
        params['deseq2_qc_transform'] = self.deseq2_qc_transform.currentText()
        params['independentFiltering'] = bool(self.deseq2_independentFiltering.isChecked())
        params['cooksCutoff'] = bool(self.deseq2_cooksCutoff.isChecked())

        # limma extra options
        params['limma_quality_weights'] = bool(self.limma_quality_weights.isChecked())
        params['limma_use_treat'] = bool(self.limma_use_treat.isChecked())
        try:
            params['limma_treat_lfc'] = float(self.limma_treat_lfc.text())
        except Exception:
            params['limma_treat_lfc'] = 0.0

        run_dir = Path(tempfile.mkdtemp(prefix='rnaseq_deg_'))
        self.append_log(f"Running plugin={self.PLUGIN_ID}")
        self.append_log(f"work_dir={run_dir}")

        try:
            out_dir = run_plugin(REGISTRY_PATH, self.PLUGIN_ID, params, run_dir)
        except Exception as e:
            self.append_log(f"[ERROR] {e}")
            out_guess = run_dir / 'out'
            for name in ['error.txt', 'stdout.txt', 'stderr.txt', 'run.log']:
                pp = out_guess / name
                if pp.exists() and pp.stat().st_size > 0:
                    self.append_log(f"---- {name} ----")
                    self.append_log(pp.read_text(encoding='utf-8', errors='ignore'))
            QMessageBox.critical(self, 'Run failed', str(e))
            return

        self.append_log(f"Done. out_dir={out_dir}")
        self.last_out_dir = Path(out_dir)

        try:
            self.results.load_table(Path(out_dir) / 'deg.tsv')
        except Exception:
            pass

        self._refresh_plot_selector(Path(out_dir))
        self._enable_plotly_controls(True)
        try:
            self._build_rnaseq_plotly()
        except Exception:
            pass

        # Provide context to the right-side RNA-seq Style/Export panel (Phase1)
        try:
            self.results.set_rnaseq_plotly_context(
                Path(out_dir) / "deg.tsv",
                out_dir=Path(out_dir),
                title="RNA-seq DEG",
            )
        except Exception:
            pass


