        self.do_tsne = QCheckBox("t-SNE (Rtsne)")
        self.do_tsne.setChecked(False)
        self.tsne_perplexity = QDoubleSpinBox(); self.tsne_perplexity.setRange(1.0, 200.0); self.tsne_perplexity.setDecimals(1); self.tsne_perplexity.setValue(30.0)
        self.tsne_theta = QDoubleSpinBox(); self.tsne_theta.setRange(0.0, 1.0); self.tsne_theta.setDecimals(2); self.tsne_theta.setValue(0.5)

