        self.btn_run.clicked.connect(lambda *args, **kwargs: self.run())

        # output selectors
        self.table_select = QComboBox()
        self.table_select.currentIndexChanged.connect(lambda *args, **kwargs: self._on_table_select(*args, **kwargs))

        self.plot_select = QComboBox()
        self.plot_select.currentIndexChanged.connect(lambda *args, **kwargs: self._on_plot_select(*args, **kwargs))

        # quick GO/enrichment linkage
        self.cluster_pick = QComboBox()
