        self.go_ontology = QComboBox(); self.go_ontology.addItems(["BP", "MF", "CC", "ALL"])
        self.enrich_engine = QComboBox(); self.enrich_engine.addItems(["clusterProfiler", "goseq", "topGO", "all"])
        self.btn_enrich = QPushButton("Run enrichment for selected cluster")
