        self.go_heatmap_top_terms = QSpinBox(); self.go_heatmap_top_terms.setRange(5, 200); self.go_heatmap_top_terms.setValue(25)
        self.btn_go_heatmap = QPushButton("Cluster×GO heatmap (all clusters)")
        self.btn_go_heatmap.clicked.connect(lambda *args, **kwargs: self._run_go_heatmap_all_clusters())

        # ---- layout ----
        form = QFormLayout()

