        wout = QWidget(); wout.setLayout(row_out)
        form.addRow("output_folder", wout)

        row = QHBoxLayout(); row.addWidget(self.counts_path); row.addWidget(b_counts)
        w = QWidget(); w.setLayout(row)
        form.addRow("Counts matrix", w)

        row = QHBoxLayout(); row.addWidget(self.design_path); row.addWidget(b_design)
        w = QWidget(); w.setLayout(row)
        form.addRow("Design table", w)

        form.addRow("sample_col", self.sample_col)
        form.addRow("group_col", self.group_col)
        form.addRow(self.btn_run)

        form.addRow("Backend", self.backend)

        form.addRow("HVG (top N genes; 0=all)", self.n_hvg)

        row = QHBoxLayout(); row.addWidget(QLabel("min_CPM")); row.addWidget(self.min_cpm); row.addSpacing(10); row.addWidget(QLabel("min_samples")); row.addWidget(self.min_samples)
        w = QWidget(); w.setLayout(row)
        form.addRow("Low expression filter (optional)", w)

        gb = QGroupBox("Inputs / filtering")
        gb.setLayout(form)

        adv = QGroupBox("Model options")
        adv_form = QFormLayout()

        row = QHBoxLayout(); row.addWidget(QLabel("gmin")); row.addWidget(self.gmin); row.addSpacing(10); row.addWidget(QLabel("gmax")); row.addWidget(self.gmax)
        w = QWidget(); w.setLayout(row)
        adv_form.addRow("HTSCluster: search range", w)

        row = QHBoxLayout(); row.addWidget(QLabel("choose_by")); row.addWidget(self.choose_by); row.addSpacing(10); row.addWidget(QLabel("force_g (0=auto)")); row.addWidget(self.force_g)
        w = QWidget(); w.setLayout(row)
        adv_form.addRow("HTSCluster: model selection", w)

        adv_form.addRow("HTSCluster: norm", self.norm_method)

        row = QHBoxLayout(); row.addWidget(QLabel("MB model")); row.addWidget(self.mb_model); row.addSpacing(10); row.addWidget(QLabel("k")); row.addWidget(self.mb_k)
        w = QWidget(); w.setLayout(row)
        adv_form.addRow("MBCluster.Seq", w)

        row = QHBoxLayout(); row.addWidget(QLabel("model")); row.addWidget(self.coseq_model); row.addSpacing(10)
        row.addWidget(QLabel("kmin")); row.addWidget(self.coseq_kmin); row.addSpacing(10)
        row.addWidget(QLabel("kmax")); row.addWidget(self.coseq_kmax); row.addSpacing(10)
        row.addWidget(QLabel("transform")); row.addWidget(self.coseq_transform)
        w = QWidget(); w.setLayout(row)
        adv_form.addRow("coseq", w)

        row = QHBoxLayout(); row.addWidget(QLabel("k")); row.addWidget(self.clusterseq_k)
        w = QWidget(); w.setLayout(row)
        adv_form.addRow("clusterSeq", w)

        adv.setLayout(adv_form)

        box_out = QGroupBox("View outputs")
        out_form = QFormLayout()
        out_form.addRow("Table", self.table_select)
        out_form.addRow("Plot", self.plot_select)
        box_out.setLayout(out_form)

        lay = QVBoxLayout()

        # GO shortcut box (wrapped as a collapsible section)
        go_box = QGroupBox("GO analysis shortcut (from cluster gene list)")
