    def _wrap_form(self, form: QFormLayout) -> QWidget:
        w = QWidget(); w.setLayout(form); return w

    def _add_pri_gwas_file(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select GWAS results.tsv/CSV", "", "Table (*.tsv *.txt *.csv);;All (*.*)")
        if not fp:
            return
        p = Path(fp)
        self._add_row_2col(self.tbl_pri_gwas, self._infer_label(p), str(p))

    def _add_pri_last_gwas(self):
        p = self.gwas_tab.get_last_results_tsv() if hasattr(self.gwas_tab, "get_last_results_tsv") else None
        if p is None:
            QMessageBox.information(self, "Info", "No last GWAS output found yet.")
            return
        self._add_row_2col(self.tbl_pri_gwas, self._infer_label(Path(p)), str(p))

    def _add_pri_qtl_file(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select QTL peaks.tsv/CSV", "", "Table (*.tsv *.txt *.csv);;All (*.*)")
        if not fp:
            return
        p = Path(fp)
        self._add_row_2col(self.tbl_pri_qtl, self._infer_label(p), str(p))

    def _add_pri_last_qtl(self):
        p = self.qtl_tab.get_last_peaks_tsv() if hasattr(self.qtl_tab, "get_last_peaks_tsv") else None
        if p is None:
            QMessageBox.information(self, "Info", "No last QTL output found yet.")
            return
        self._add_row_2col(self.tbl_pri_qtl, self._infer_label(Path(p)), str(p))

    def _add_pri_deg_file(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select DEG TSV", "", "Table (*.tsv *.txt *.csv);;All (*.*)")
        if not fp:
            return
        p = Path(fp)
        self._add_row_2col(self.tbl_pri_deg, self._infer_label(p), str(p))



    def _add_pri_blast_file(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select BLAST TSV", "", "Table (*.tsv *.txt *.csv);;All (*.*)")
        if not fp:
            return
        p = Path(fp)
        self._add_row_2col(self.tbl_pri_blast, self._infer_label(p), str(p))

    def _add_pri_last_blast(self):
        try:
            if self.blast_tab and getattr(self.blast_tab, "last_out_dir", None):
                out_dir = Path(self.blast_tab.last_out_dir)
                # Prefer best_hit_per_query.tsv
                cand = out_dir / "best_hit_per_query.tsv"
                if not cand.exists():
                    cand = out_dir / "blast_results.tsv"
                if cand.exists():
                    self._add_row_2col(self.tbl_pri_blast, self._infer_label(cand), str(cand))
                    return
        except Exception:
            pass
        QMessageBox.information(self, "Info", "No last BLAST output found.")

    def _add_pri_eggnog_file(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select eggNOG-mapper .annotations", "", "eggNOG annotations (*.annotations *.tsv *.txt);;All (*.*)")
        if not fp:
            return
        p = Path(fp)
        self._add_row_2col(self.tbl_pri_eggnog, self._infer_label(p), str(p))
    def _use_last_genepred_predicted_gff(self):
        try:
            if self.gene_pred_tab and getattr(self.gene_pred_tab, "last_out_dir", None):
                p = Path(self.gene_pred_tab.last_out_dir) / "predicted.gff3"
                if p.exists():
                    self.ed_pri_pred_gff.setText(str(p))
                    return
        except Exception:
            pass
        QMessageBox.information(self, "Info", "No last GenePred predicted.gff3 found.")

    def run_prioritize(self):
        gwas_files = self._paths_from_tbl(self.tbl_pri_gwas)
        qtl_files = self._paths_from_tbl(self.tbl_pri_qtl)
        deg_files = self._paths_from_tbl(self.tbl_pri_deg)
        blast_files = self._paths_from_tbl(self.tbl_pri_blast)
        eggnog_files = self._paths_from_tbl(self.tbl_pri_eggnog)

        if not gwas_files and not qtl_files:
            QMessageBox.information(self, "No input", "Add one or more GWAS and/or QTL peak files first.")
            return

        genome_gff = self.ed_pri_genome_gff.text().strip()
        pred_gff = self.ed_pri_pred_gff.text().strip()
        if not genome_gff and not pred_gff:
            QMessageBox.warning(self, "No gene source", "Genome annotation (GFF3/GTF) and/or predicted.gff3 is required to output candidates.")

        params = {
            "gwas_results": gwas_files,
            "qtl_peaks": qtl_files,
            "mode_gwas": self.pri_gwas_pick_mode.currentText(),
            "gwas_top_n": int(self.pri_gwas_top_n.value()),
            "gwas_p_threshold": str(self.pri_gwas_p_threshold.text()).strip(),
            "mode_qtl": self.pri_qtl_pick_mode.currentText(),
            "qtl_top_n": int(self.pri_qtl_top_n.value()),
            "qtl_lod_threshold": str(self.pri_qtl_lod_threshold.text()).strip(),
            "window_bp": int(self.pri_window_bp.value()),
            "chr_normalize": True if self.pri_normalize_chr.currentText() == "TRUE" else False,
            "genome_gff": genome_gff,
            "predicted_gff": pred_gff,
            "deg_tsv_list": deg_files,
            "deg_padj_max": str(self.pri_deg_padj.text()).strip(),
            "deg_abs_logfc_min": str(self.pri_deg_abs_lfc.text()).strip(),
            "blast_tsv_list": blast_files,
            "blast_evalue_max": str(self.pri_blast_evalue.text()).strip(),
            "blast_bitscore_min": str(self.pri_blast_bitscore.text()).strip(),
            "eggnog_annotations_list": eggnog_files,
            "go_map_file": str(self.ed_pri_go_map.text()).strip(),
            "go_keywords": str(self.pri_go_keywords.toPlainText()).strip(),
            "max_genes_per_locus": int(self.pri_max_genes.value()),
            "dist_decay_bp": int(self.pri_dist_decay.value()),
            "w_peak": float(self.pri_w_peak.value()),
            "w_dist": float(self.pri_w_dist.value()),
            "w_deg": float(self.pri_w_deg.value()),
            "w_blast": float(self.pri_w_blast.value()),
            "w_eggnog": float(self.pri_w_eggnog.value()),
            "w_go": float(self.pri_w_go.value()),
        }

        out_root = self.ed_pri_export_dir.text().strip()
        if out_root:
            try:
                Path(out_root).mkdir(parents=True, exist_ok=True)
            except Exception:
                QMessageBox.warning(self, "Invalid output", "Cannot create output folder.")
                out_root = ""

        ts = time.strftime("%Y%m%d_%H%M%S")
        run_dir = Path(out_root) / f"integrate_prioritize_{ts}" if out_root else Path(tempfile.mkdtemp(prefix="integrate_prioritize_"))
        run_dir.mkdir(parents=True, exist_ok=True)

        self.append_log(f"Running plugin={self.PLUGIN_PRIORITIZE}")
        self.append_log(f"work_dir={run_dir}")
        try:
            out_dir = run_plugin(REGISTRY_PATH, self.PLUGIN_PRIORITIZE, params, run_dir)
        except Exception as e:
            self.append_log(f"[ERROR] {e}")
            QMessageBox.critical(self, "integrate_prioritize failed", str(e))
            return

        self.last_out_dir = Path(out_dir)
        self.last_prioritize_out_dir = Path(out_dir)
        self.last_candidates_ranked = self.last_out_dir / "candidates_ranked.tsv"

        self.ed_pri_last_out.setText(str(self.last_out_dir))
        self.ed_pri_last_candidates.setText(str(self.last_candidates_ranked) if self.last_candidates_ranked.exists() else "")

        self.reload_prioritize_view()
        self.append_log(f"Done. out_dir={self.last_out_dir}")

    def reload_prioritize_view(self):
        if not getattr(self, "last_candidates_ranked", None) or not self.last_candidates_ranked.exists():
            QMessageBox.information(self, "Info", "candidates_ranked.tsv not available yet.")
            return
        try:
            df = read_table_robust(self.last_candidates_ranked)
            head = df.head(500)
            self.results.set_table_rows(list(head.columns), head.values.tolist())
            try:
                self._pri_df_cache = df
                self._pri_plot_refresh_locus_choices(df)
            except Exception:
                pass
        except Exception as e:
            self.append_log(f"[WARN] failed to render candidates_ranked.tsv: {e}")



    # -------------------------
    # Prioritize plots (Phase A)
    # -------------------------
    def _pri_plot_refresh_locus_choices(self, df: pd.DataFrame):
        """Populate locus selector from candidates_ranked.tsv."""
        try:
            if getattr(self, 'pri_plot_locus', None) is None:
                return
        except Exception:
            return
        try:
            if df is None or df.empty or 'locus_id' not in df.columns:
                return
            cur = ''
            try:
                cur = str(self.pri_plot_locus.currentText() or '').strip()
            except Exception:
                cur = ''
            locs = [str(x) for x in df['locus_id'].dropna().astype(str).unique().tolist()]
            # natural-ish sort: locus_1, locus_2 ...
            def _key(s: str):
                m = re.search(r"(\d+)$", s)
                return (re.sub(r"\d+$", "", s), int(m.group(1)) if m else 10**18, s)
            locs = sorted(locs, key=_key)
            try:
                self.pri_plot_locus.blockSignals(True)
            except Exception:
                pass
            try:
                self.pri_plot_locus.clear()
                self.pri_plot_locus.addItems(locs)
                if cur and cur in locs:
                    self.pri_plot_locus.setCurrentText(cur)
            finally:
                try:
                    self.pri_plot_locus.blockSignals(False)
                except Exception:
                    pass
        except Exception:
            pass

    def _pri_plot_refresh_deg_choices(self):
        """Populate DEG selector from the DEG table in Evidence (optional)."""
        try:
            cmb = getattr(self, 'pri_plot_deg_source', None)
            tbl = getattr(self, 'tbl_pri_deg', None)
            if cmb is None or tbl is None:
                return
        except Exception:
            return

        try:
            cur = ''
            try:
                cur = str(cmb.currentData() or '').strip()
            except Exception:
                cur = ''

            cmb.blockSignals(True)
            cmb.clear()
            cmb.addItem('(auto)', '')
            for i in range(tbl.rowCount()):
                lab = tbl.item(i, 0).text().strip() if tbl.item(i, 0) else ''
                fp = tbl.item(i, 1).text().strip() if tbl.item(i, 1) else ''
                if not fp:
                    continue
                if not lab:
                    lab = Path(fp).stem
                cmb.addItem(lab, fp)
            # restore
            if cur:
                for j in range(cmb.count()):
                    if str(cmb.itemData(j) or '').strip() == cur:
                        cmb.setCurrentIndex(j)
                        break
        finally:
            try:
                cmb.blockSignals(False)
            except Exception:
                pass

    def _pri_plot_set_locus_from_selected_row(self):
        """Set locus selector from the currently selected row in Results table."""
        try:
            tbl = getattr(self.results, 'table', None)
            if tbl is None:
                return
            r = int(tbl.currentRow())
            if r < 0:
                QMessageBox.information(self, 'Info', 'Select a row in the results table first.')
                return
            # find locus_id column
            locus_col = None
            for c in range(tbl.columnCount()):
                it = tbl.horizontalHeaderItem(c)
                if it and (it.text() == 'locus_id'):
                    locus_col = c
                    break
            if locus_col is None:
                QMessageBox.information(self, 'Info', 'No locus_id column in current table.')
                return
            it = tbl.item(r, locus_col)
            if not it:
                return
            locus = str(it.text()).strip()
            if locus:
                try:
                    self.pri_plot_locus.setCurrentText(locus)
                except Exception:
                    pass
        except Exception as e:
            try:
                self.append_log(f"[WARN] set locus from selected row failed: {e}")
            except Exception:
                pass

    def draw_prioritize_plot(self, kind: str | None = None):
        """Draw ranking plot or locus view from candidates_ranked.tsv and show in Results pane."""
        # Determine kind
        if kind is None:
            try:
                t = (self.pri_plot_type.currentText() or '').lower()
                if t.startswith('rank'):
                    kind = 'ranking'
                elif 'heat' in t:
                    kind = 'heatmap'
                elif 'deg' in t:
                    kind = 'deg'
                else:
                    kind = 'locus'
            except Exception:
                kind = 'ranking'
        kind = (kind or '').strip().lower()
        if kind in {'rank', 'ranking', 'rankplot'}:
            kind = 'ranking'
        elif kind in {'locus', 'locusview', 'region'}:
            kind = 'locus'
        elif kind in {'heat', 'heatmap', 'evidence', 'evidence_heatmap'}:
            kind = 'heatmap'
        elif kind in {'deg', 'degplot', 'degoverlay', 'volcano', 'ma'}:
            kind = 'deg'

        # Load candidates table
        cand_path = getattr(self, 'last_candidates_ranked', None)
        if cand_path is None or not Path(cand_path).exists():
            QMessageBox.information(self, 'Info', 'candidates_ranked.tsv not available yet.')
            return
        try:
            df = getattr(self, '_pri_df_cache', None)
            if df is None or df.empty:
                df = read_table_robust(Path(cand_path))
                self._pri_df_cache = df
        except Exception:
            df = read_table_robust(Path(cand_path))
            self._pri_df_cache = df

        go, pio, qualitative = _try_import_plotly()
        if go is None or pio is None:
            QMessageBox.critical(self, 'Plotly not available', 'Plotly is required for plotting. Install plotly and restart.')
            return

        out_dir = None
        try:
            out_dir = Path(getattr(self, 'last_prioritize_out_dir', None) or getattr(self, 'last_out_dir', None) or Path(cand_path).parent)
        except Exception:
            out_dir = Path(cand_path).parent
        plot_dir = out_dir / 'plots'
        try:
            plot_dir.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass

        try:
            if kind == 'ranking':
                fig, title = self._pri_make_ranking_plot(df, go, qualitative)
                out_html = plot_dir / 'prioritize_ranking.html'
            elif kind == 'locus':
                fig, title = self._pri_make_locus_plot(df, go, qualitative, out_dir)
                locus = str(self.pri_plot_locus.currentText() or '').strip()
                safe = re.sub(r"[^A-Za-z0-9_.-]+", "_", locus) if locus else 'locus'
                out_html = plot_dir / f'prioritize_locus_{safe}.html'
            elif kind == 'deg':
                fig, title, suffix = self._pri_make_deg_overlay_plot(df, go)
                out_html = plot_dir / f'prioritize_deg_{suffix}.html'
            else:
                fig, title = self._pri_make_evidence_heatmap(df, go)
                out_html = plot_dir / 'prioritize_evidence_heatmap.html'

            # Always write HTML (embed plotly.js so it works offline / in QtWebEngine)
            try:
                html = _plotly_html(fig, pio, add_selection_js=False)
                out_html.write_text(html, encoding='utf-8')
            except Exception:
                # fallback: write_html with embedded plotlyjs
                pio.write_html(fig, file=str(out_html), include_plotlyjs=True, full_html=True)

            # Optional static exports if kaleido is available
            try:
                out_png = Path(str(out_html).replace('.html', '.png'))
                pio.write_image(fig, str(out_png), format='png', width=1400, height=800, scale=2)
            except Exception:
                pass
            try:
                out_pdf = Path(str(out_html).replace('.html', '.pdf'))
                pio.write_image(fig, str(out_pdf), format='pdf', width=1400, height=800, scale=2)
            except Exception:
                pass

            # Show in Results pane (and enable Integrate Style/Export panel)
            try:
                self.results.set_integrate_plotly_context(fig, out_dir=out_dir, html_path=out_html, title=title)
            except Exception:
                try:
                    self.results.set_plot_html(out_html)
                except Exception:
                    pass

            self.append_log(f"[INFO] Plot saved: {out_html}")
        except Exception as e:
            self.append_log(f"[ERROR] plotting failed: {e}")
            QMessageBox.critical(self, 'Plot failed', str(e))

    def _pri_make_ranking_plot(self, df: pd.DataFrame, go, qualitative):
        """Ranking plot: rank vs score, colored by locus."""
        import numpy as _np
        import pandas as _pd

        topn = int(getattr(self, 'pri_plot_topn', None).value()) if getattr(self, 'pri_plot_topn', None) is not None else 300
        d = df.copy()
        # Ensure numeric
        if 'rank' in d.columns:
            d['rank'] = _pd.to_numeric(d['rank'], errors='coerce')
        if 'score' in d.columns:
            d['score'] = _pd.to_numeric(d['score'], errors='coerce')
        d = d[_np.isfinite(d.get('rank'))] if 'rank' in d.columns else d
        if 'rank' not in d.columns or d['rank'].isna().all():
            # fallback: order by score
            d = d.sort_values('score', ascending=False)
            d['rank'] = _np.arange(1, len(d) + 1)
        d = d.sort_values('rank', ascending=True)
        d = d[d['rank'] <= float(topn)]

        # palette
        try:
            pal = getattr(qualitative, 'Plotly', None) or getattr(qualitative, 'D3', None) or ['#1f77b4', '#ff7f0e', '#2ca02c', '#d62728']
        except Exception:
            pal = ['#1f77b4', '#ff7f0e', '#2ca02c', '#d62728']

        # Build traces by locus
        fig = go.Figure()
        if 'locus_id' not in d.columns:
            d['locus_id'] = 'NA'
        loci = [str(x) for x in d['locus_id'].fillna('NA').astype(str).unique().tolist()]
        loci = loci[:200]  # safety
        color_map = {l: pal[i % len(pal)] for i, l in enumerate(sorted(loci))}

        hover_cols = ['gene_id', 'chr', 'distance', 'deg_hit', 'blast_hit', 'go_hit', 'peak_source']
        for locus in sorted(loci):
            dd = d[d['locus_id'].astype(str) == str(locus)]
            if dd.empty:
                continue
            custom = []
            for _, r in dd.iterrows():
                custom.append([str(r.get(c, '')) for c in hover_cols])
            fig.add_trace(
                go.Scatter(
                    x=dd['rank'],
                    y=dd['score'],
                    mode='markers',
                    name=str(locus),
                    marker=dict(size=7, opacity=0.85, color=color_map.get(str(locus))),
                    customdata=custom,
                    hovertemplate=(
                        "<b>gene</b>=%{customdata[0]}<br>"
                        "<b>chr</b>=%{customdata[1]}<br>"
                        "<b>distance</b>=%{customdata[2]}<br>"
                        "<b>DEG</b>=%{customdata[3]}  <b>BLAST</b>=%{customdata[4]}  <b>GO</b>=%{customdata[5]}<br>"
                        "<b>peak</b>=%{customdata[6]}<br>"
                        "<b>rank</b>=%{x}  <b>score</b>=%{y}<extra></extra>"
                    ),
                )
            )

        fig.update_layout(
            title=f"Prioritize: Candidate ranking (Top {topn})",
            xaxis_title='Rank',
            yaxis_title='Score',
            template='plotly_white',
            legend_title='locus_id',
            margin=dict(l=60, r=20, t=60, b=50),
            height=720,
        )
        return fig, f"Integrate / Prioritize: Ranking (Top {topn})"

    def _pri_make_locus_plot(self, df: pd.DataFrame, go, qualitative, out_dir: Path):
        """Locus view: peaks + gene track within a locus."""
        import numpy as _np
        import pandas as _pd
        try:
            from plotly.subplots import make_subplots  # type: ignore
        except Exception:
            make_subplots = None

        locus_id = str(self.pri_plot_locus.currentText() or '').strip()
        if not locus_id:
            # fallback: pick the first
            try:
                locus_id = str(df['locus_id'].dropna().astype(str).iloc[0])
            except Exception:
                locus_id = ''
        if not locus_id:
            raise ValueError('No locus selected')

        d = df[df.get('locus_id').astype(str) == locus_id].copy() if 'locus_id' in df.columns else df.copy()
        if d.empty:
            raise ValueError(f'No rows for locus_id={locus_id}')

        # locus boundaries
        chr_ = str(d.get('chr').iloc[0]) if 'chr' in d.columns else ''
        try:
            locus_start = int(_pd.to_numeric(d.get('locus_start'), errors='coerce').min())
            locus_end = int(_pd.to_numeric(d.get('locus_end'), errors='coerce').max())
        except Exception:
            locus_start = int(_pd.to_numeric(d.get('gene_start'), errors='coerce').min())
            locus_end = int(_pd.to_numeric(d.get('gene_end'), errors='coerce').max())

        peak_pos = None
        try:
            peak_pos = float(_pd.to_numeric(d.get('peak_pos'), errors='coerce').dropna().iloc[0])
        except Exception:
            peak_pos = None

        # peaks in locus
        peaks_path = Path(out_dir) / 'locus_peaks.tsv'
        peaks_df = None
        if peaks_path.exists():
            try:
                peaks_df = read_table_robust(peaks_path)
                if 'locus_id' in peaks_df.columns:
                    peaks_df = peaks_df[peaks_df['locus_id'].astype(str) == locus_id]
            except Exception:
                peaks_df = None

        # subplot figure
        if make_subplots is not None:
            fig = make_subplots(rows=2, cols=1, shared_xaxes=True, vertical_spacing=0.08, row_heights=[0.62, 0.38])
        else:
            fig = go.Figure()

        # Peak strength y
        if peaks_df is not None and (not peaks_df.empty):
            p = peaks_df.copy()
            p['pos'] = _pd.to_numeric(p.get('pos'), errors='coerce')
            p['pvalue'] = _pd.to_numeric(p.get('pvalue'), errors='coerce')
            p['lod'] = _pd.to_numeric(p.get('lod'), errors='coerce')
            y = []
            for pv, lod in zip(p['pvalue'].tolist(), p['lod'].tolist()):
                if _np.isfinite(pv) and pv > 0:
                    y.append(-_np.log10(pv))
                elif _np.isfinite(lod):
                    y.append(float(lod))
                else:
                    y.append(_np.nan)
            p['strength'] = y

            # plot by dataset_label
            labcol = 'dataset_label' if 'dataset_label' in p.columns else ('source_type' if 'source_type' in p.columns else None)
            labels = [str(x) for x in (p[labcol].fillna('NA').astype(str).unique().tolist() if labcol else ['peaks'])]
            try:
                pal = getattr(qualitative, 'Plotly', None) or getattr(qualitative, 'D3', None)
            except Exception:
                pal = None
            pal = pal or ['#1f77b4', '#ff7f0e', '#2ca02c', '#d62728']
            colmap = {l: pal[i % len(pal)] for i, l in enumerate(labels)}
            for l in labels:
                pp = p[p[labcol].astype(str) == l] if labcol else p
                fig.add_trace(
                    go.Scatter(
                        x=pp['pos'],
                        y=pp['strength'],
                        mode='markers',
                        name=str(l),
                        marker=dict(size=7, opacity=0.85, color=colmap.get(str(l))),
                        hovertemplate=(
                            "<b>peak</b>=%{x}<br>"
                            "<b>strength</b>=%{y}<extra></extra>"
                        ),
                    ),
                    row=1, col=1
                )
        else:
            # fallback: representative peak from candidates
            try:
                s = _pd.to_numeric(d.get('peak_strength'), errors='coerce')
                fig.add_trace(go.Scatter(x=[peak_pos], y=[float(s.dropna().iloc[0])], mode='markers', name='peak'), row=1, col=1)
            except Exception:
                pass

        # Gene track (candidates within locus)
        genes = d.copy()
        genes['gene_start'] = _pd.to_numeric(genes.get('gene_start'), errors='coerce')
        genes['gene_end'] = _pd.to_numeric(genes.get('gene_end'), errors='coerce')
        genes = genes[_np.isfinite(genes['gene_start']) & _np.isfinite(genes['gene_end'])]
        genes = genes.sort_values(['gene_start', 'gene_end'], ascending=[True, True])

        # interval packing (rows)
        rows_end = []
        row_idx = []
        for _, r in genes.iterrows():
            s = float(r['gene_start']); e = float(r['gene_end'])
            placed = False
            for i, endv in enumerate(rows_end):
                if s > endv:
                    rows_end[i] = e
                    row_idx.append(i)
                    placed = True
                    break
            if not placed:
                rows_end.append(e)
                row_idx.append(len(rows_end) - 1)
        genes = genes.copy()
        genes['_row'] = row_idx

        # highlight topK by score
        topk = int(self.pri_plot_label_topk.value()) if getattr(self, 'pri_plot_label_topk', None) is not None else 5
        try:
            genes['_score'] = _pd.to_numeric(genes.get('score'), errors='coerce')
        except Exception:
            genes['_score'] = _np.nan
        genes_sorted = genes.sort_values('_score', ascending=False)
        top_genes = set([str(x) for x in genes_sorted.head(topk).get('gene_id').astype(str).tolist()]) if topk > 0 else set()

        # combined trace for non-top genes
        x_all = []; y_all = []
        for _, r in genes.iterrows():
            gid = str(r.get('gene_id', ''))
            if gid in top_genes:
                continue
            x_all += [float(r['gene_start']), float(r['gene_end']), None]
            y_all += [float(r['_row']), float(r['_row']), None]
        if x_all:
            fig.add_trace(
                go.Scatter(
                    x=x_all,
                    y=y_all,
                    mode='lines',
                    line=dict(width=7, color='#777777'),
                    name='genes',
                    hoverinfo='skip',
                    showlegend=False,
                ),
                row=2, col=1
            )

        # top genes: individual traces + labels
        label_x = []; label_y = []; label_t = []
        for _, r in genes.iterrows():
            gid = str(r.get('gene_id', ''))
            if gid not in top_genes:
                continue
            xs = float(r['gene_start']); xe = float(r['gene_end']); yy = float(r['_row'])
            mid = (xs + xe) / 2.0
            label_x.append(mid); label_y.append(yy); label_t.append(gid)
            fig.add_trace(
                go.Scatter(
                    x=[xs, xe],
                    y=[yy, yy],
                    mode='lines',
                    line=dict(width=10, color='#d62728'),
                    name=gid,
                    hovertemplate=(
                        f"<b>gene</b>={gid}<br>"
                        f"<b>range</b>={int(xs)}-{int(xe)}<br>"
                        f"<b>score</b>={r.get('_score', '')}<extra></extra>"
                    ),
                    showlegend=False,
                ),
                row=2, col=1
            )

        if label_x:
            fig.add_trace(
                go.Scatter(
                    x=label_x,
                    y=label_y,
                    mode='text',
                    text=label_t,
                    textposition='top center',
                    showlegend=False,
                    hoverinfo='skip',
                ),
                row=2, col=1
            )

        # Peak vertical line
        try:
            if peak_pos is not None and _np.isfinite(peak_pos):
                fig.add_vline(x=peak_pos, line_width=1, line_dash='dash', line_color='black', row='all', col=1)
        except Exception:
            pass

        # Layout
        pad = max(int((locus_end - locus_start) * 0.03), 1)
        x0 = locus_start - pad
        x1 = locus_end + pad
        fig.update_xaxes(range=[x0, x1], title_text=f"Position on {chr_}" if chr_ else 'Position', row=2, col=1)
        fig.update_yaxes(title_text='Peak strength', row=1, col=1)
        fig.update_yaxes(showticklabels=False, title_text='Genes', row=2, col=1)

        fig.update_layout(
            title=f"Locus view: {locus_id} ({chr_}:{locus_start}-{locus_end})",
            template='plotly_white',
            margin=dict(l=60, r=20, t=60, b=50),
            height=780,
        )
        return fig, f"Integrate / Prioritize: Locus view ({locus_id})"

    def _pri_make_evidence_heatmap(self, df: pd.DataFrame, go):
        """Evidence heatmap for top candidates.

        Rows: candidate genes (Top N overall or per-locus top K)
        Cols: evidence columns selected by user
        """
        import numpy as _np
        import pandas as _pd

        d = df.copy()
        # Ensure numeric score/rank
        if 'score' in d.columns:
            d['score'] = _pd.to_numeric(d['score'], errors='coerce')
        if 'rank' in d.columns:
            d['rank'] = _pd.to_numeric(d['rank'], errors='coerce')

        # Subset rows
        mode = str(self.pri_plot_hm_mode.currentText() or '').strip().lower()
        topn = int(self.pri_plot_hm_topn.value())
        topk = int(self.pri_plot_hm_topk.value())
        if 'score' in d.columns:
            d = d.sort_values('score', ascending=False)
        if ('per locus' in mode) and ('locus_id' in d.columns):
            # top K per locus
            out_parts = []
            for locus, sub in d.groupby(d['locus_id'].astype(str), sort=False):
                ss = sub.sort_values('score', ascending=False) if 'score' in sub.columns else sub
                out_parts.append(ss.head(topk))
            d = _pd.concat(out_parts, axis=0, ignore_index=True) if out_parts else d.head(topn)
            d = d.sort_values('score', ascending=False)
        else:
            d = d.head(topn)

        if d.empty:
            raise ValueError('No rows available for heatmap.')

        # Columns to show
        raw_cols = str(self.pri_plot_hm_cols.text() or '').strip()
        cols = []
        if raw_cols:
            for t in re.split(r"[\s,;]+", raw_cols):
                tt = t.strip()
                if tt:
                    cols.append(tt)
        if not cols:
            cols = ['peak_score_norm', 'dist_score', 'deg_score_norm', 'blast_score_norm', 'eggnog_hit', 'go_score']
        cols = [c for c in cols if c in d.columns]
        if not cols:
            raise ValueError('Heatmap columns not found in candidates table.')

        # Prepare matrix
        z = []
        for c in cols:
            d[c] = _pd.to_numeric(d[c], errors='coerce').fillna(0.0)
        for _, r in d.iterrows():
            z.append([float(r.get(c, 0.0) or 0.0) for c in cols])
        z = _np.array(z, dtype=float)

        # Row labels
        gene_ids = d.get('gene_id').astype(str).fillna('NA') if 'gene_id' in d.columns else _pd.Series(['NA'] * len(d))
        locus_ids = d.get('locus_id').astype(str).fillna('NA') if 'locus_id' in d.columns else _pd.Series(['NA'] * len(d))
        y = [f"{g} | {l}" for g, l in zip(gene_ids.tolist(), locus_ids.tolist())]

        # Custom hover info
        hover_extra_cols = ['gene_id', 'locus_id', 'chr', 'distance', 'score', 'deg_hit', 'blast_hit', 'go_hit', 'blast_best_hit', 'go_matches', 'eggnog_pref_name']
        custom = []
        for _, r in d.iterrows():
            custom.append([str(r.get(c, '')) for c in hover_extra_cols])

        fig = go.Figure(
            data=go.Heatmap(
                z=z,
                x=cols,
                y=y,
                customdata=custom,
                hovertemplate=(
                    "<b>gene</b>=%{customdata[0]}<br>"
                    "<b>locus</b>=%{customdata[1]}<br>"
                    "<b>chr</b>=%{customdata[2]}  <b>distance</b>=%{customdata[3]}<br>"
                    "<b>score</b>=%{customdata[4]}<br>"
                    "<b>evidence</b>=%{x}  <b>value</b>=%{z:.3f}<br>"
                    "<b>DEG</b>=%{customdata[5]}  <b>BLAST</b>=%{customdata[6]}  <b>GO</b>=%{customdata[7]}<br>"
                    "<b>BLAST hit</b>=%{customdata[8]}<br>"
                    "<b>GO matches</b>=%{customdata[9]}<br>"
                    "<b>eggNOG</b>=%{customdata[10]}<extra></extra>"
                ),
            )
        )

        n_rows = int(len(d))
        height = max(520, min(1600, 22 * n_rows + 260))
        fig.update_layout(
            title=f"Prioritize: Evidence heatmap ({self.pri_plot_hm_mode.currentText()} | n={n_rows})",
            template='plotly_white',
            margin=dict(l=260, r=20, t=60, b=50),
            height=height,
            xaxis_title='Evidence',
            yaxis_title='Candidate (gene | locus)',
        )
        fig.update_yaxes(autorange='reversed')

        return fig, "Integrate / Prioritize: Evidence heatmap"

    def _pri_make_deg_overlay_plot(self, cand_df: pd.DataFrame, go):
        """Phase C: DEG overlay plot (Volcano/MA) with candidate genes highlighted."""
        import numpy as _np
        import pandas as _pd

        # pick DEG file
        fp = ''
        deg_label = ''
        try:
            fp = str(self.pri_plot_deg_source.currentData() or '').strip()
            deg_label = str(self.pri_plot_deg_source.currentText() or '').strip()
        except Exception:
            fp = ''
            deg_label = ''

        if not fp:
            # auto = first DEG file in the table
            try:
                if getattr(self, 'tbl_pri_deg', None) is not None and self.tbl_pri_deg.rowCount() > 0:
                    fp = (self.tbl_pri_deg.item(0, 1).text().strip() if self.tbl_pri_deg.item(0, 1) else '')
                    deg_label = (self.tbl_pri_deg.item(0, 0).text().strip() if self.tbl_pri_deg.item(0, 0) else Path(fp).stem)
            except Exception:
                fp = ''

        if not fp:
            raise ValueError('No DEG file available. Add DEG TSV in Evidence (optional) or select one, then Refresh.')

        deg_path = Path(fp)
        if not deg_path.exists():
            raise ValueError(f'DEG file not found: {deg_path}')

        # thresholds (reuse Evidence settings)
        try:
            fdr = float(str(self.pri_deg_padj.text()).strip() or '0.05')
        except Exception:
            fdr = 0.05
        try:
            lfc_thr = float(str(self.pri_deg_abs_lfc.text()).strip() or '0')
        except Exception:
            lfc_thr = 0.0

        # candidate subset
        scope = str(self.pri_plot_deg_scope.currentText() or '').strip()
        dsub = cand_df.copy()
        if 'gene_id' not in dsub.columns:
            raise ValueError('candidates_ranked.tsv must contain gene_id')
        if 'score' in dsub.columns:
            dsub['score'] = _pd.to_numeric(dsub['score'], errors='coerce')
        if 'rank' in dsub.columns:
            dsub['rank'] = _pd.to_numeric(dsub['rank'], errors='coerce')

        if scope.lower().startswith('selected'):
            locus_id = str(self.pri_plot_locus.currentText() or '').strip()
            if locus_id and ('locus_id' in dsub.columns):
                dsub = dsub[dsub['locus_id'].astype(str) == locus_id].copy()
        else:
            topn = int(self.pri_plot_topn.value()) if getattr(self, 'pri_plot_topn', None) is not None else 300
            if 'rank' in dsub.columns and _np.isfinite(dsub['rank']).any():
                dsub = dsub.sort_values('rank', ascending=True).head(topn)
            elif 'score' in dsub.columns:
                dsub = dsub.sort_values('score', ascending=False).head(topn)
            else:
                dsub = dsub.head(topn)

        if dsub.empty:
            raise ValueError('No candidate rows available for the selected DEG scope.')

        # best row per gene for hover/labels
        if 'score' in dsub.columns:
            dsub = dsub.sort_values('score', ascending=False)
        best = dsub.drop_duplicates(subset=['gene_id'], keep='first').copy()
        best['gene_id'] = best['gene_id'].astype(str)
        cand_set = set(best['gene_id'].tolist())
        best_map = {str(r['gene_id']): r for _, r in best.iterrows()}

        # load DEG table
        deg = read_table_robust(deg_path)
        if deg is None or deg.empty:
            raise ValueError(f'Empty DEG table: {deg_path}')

        gene_col = _rnaseq_guess_gene_col(deg)
        pcol = _rnaseq_guess_pcol(deg)
        lfc_col = _rnaseq_guess_lfc_col(deg)
        if pcol is None or lfc_col is None:
            raise ValueError('DEG table must contain pvalue/padj and logFC/log2FoldChange columns.')

        deg['_gene'] = deg[gene_col].astype(str)
        deg[pcol] = _pd.to_numeric(deg[pcol], errors='coerce')
        deg[lfc_col] = _pd.to_numeric(deg[lfc_col], errors='coerce')
        deg = deg.dropna(subset=[pcol, lfc_col]).copy()

        hit = deg[deg['_gene'].isin(cand_set)].copy()
        # include -log10(p) for volcano overlay coords
        hit['_mlog10p'] = -_np.log10(_np.clip(hit[pcol].values.astype(float), 1e-300, 1.0))

        kind = str(self.pri_plot_deg_kind.currentText() or 'Volcano').strip().lower()
        if kind.startswith('vol'):
            fig = build_rnaseq_volcano_figure(
                deg,
                title=f"Prioritize: DEG overlay (Volcano) | {deg_label or deg_path.stem} | {scope}",
                fdr=float(fdr),
                lfc=float(lfc_thr),
                topn_labels=0,
            )
            if fig is None:
                raise ValueError('Plotly not available')

            if not hit.empty:
                custom = []
                for g in hit['_gene'].tolist():
                    r = best_map.get(str(g))
                    if r is None:
                        custom.append(['', '', ''])
                    else:
                        custom.append([
                            str(r.get('locus_id', '')),
                            str(r.get('score', '')),
                            str(r.get('distance', '')),
                        ])
                fig.add_trace(
                    go.Scatter(
                        x=hit[lfc_col],
                        y=hit['_mlog10p'],
                        mode='markers',
                        marker=dict(size=9, opacity=0.95, symbol='diamond', color='#111111'),
                        text=hit['_gene'],
                        customdata=custom,
                        hovertemplate=(
                            "<b>%{text}</b><br>locus=%{customdata[0]}<br>score=%{customdata[1]}<br>distance=%{customdata[2]}<br>"
                            "log2FC=%{x:.3g}<br>-log10(p)=%{y:.3g}<extra></extra>"
                        ),
                        name='candidates',
                        showlegend=False,
                    )
                )

                # label top K candidates by prioritize score
                topk = int(self.pri_plot_label_topk.value()) if getattr(self, 'pri_plot_label_topk', None) is not None else 5
                if topk and topk > 0:
                    lab_best = best.copy()
                    if 'score' in lab_best.columns:
                        lab_best = lab_best.sort_values('score', ascending=False)
                    lab_best = lab_best.head(topk)
                    lab = hit[hit['_gene'].isin(set(lab_best['gene_id'].astype(str).tolist()))].copy()
                    if not lab.empty:
                        fig.add_trace(
                            go.Scatter(
                                x=lab[lfc_col],
                                y=lab['_mlog10p'],
                                mode='markers+text',
                                text=lab['_gene'],
                                textposition='top center',
                                marker=dict(size=9, opacity=0.98, symbol='diamond', color='#111111'),
                                hoverinfo='skip',
                                showlegend=False,
                            )
                        )

        else:
            # MA overlay
            fig = build_rnaseq_ma_figure(
                deg,
                title=f"Prioritize: DEG overlay (MA) | {deg_label or deg_path.stem} | {scope}",
                lfc=float(lfc_thr),
                topn_labels=0,
            )
            if fig is None:
                raise ValueError('Plotly not available')

            mean_col = _rnaseq_guess_mean_col(deg)
            if mean_col is None:
                raise ValueError('MA plot requires baseMean/logCPM/AveExpr-like column in the DEG table.')
            deg[mean_col] = _pd.to_numeric(deg[mean_col], errors='coerce')
            hit[mean_col] = _pd.to_numeric(hit.get(mean_col), errors='coerce')
            hit = hit.dropna(subset=[mean_col]).copy()

            if not hit.empty:
                x_all = deg[mean_col].values
                x_hit = hit[mean_col].values
                if _np.nanmax(x_all) > 1000:
                    x_hit_plot = _np.log10(_np.clip(x_hit, 1e-9, None))
                else:
                    x_hit_plot = x_hit

                custom = []
                for g in hit['_gene'].tolist():
                    r = best_map.get(str(g))
                    if r is None:
                        custom.append(['', '', ''])
                    else:
                        custom.append([
                            str(r.get('locus_id', '')),
                            str(r.get('score', '')),
                            str(r.get('distance', '')),
                        ])
                fig.add_trace(
                    go.Scatter(
                        x=x_hit_plot,
                        y=hit[lfc_col],
                        mode='markers',
                        marker=dict(size=9, opacity=0.95, symbol='diamond', color='#111111'),
                        text=hit['_gene'],
                        customdata=custom,
                        hovertemplate=(
                            "<b>%{text}</b><br>locus=%{customdata[0]}<br>score=%{customdata[1]}<br>distance=%{customdata[2]}<br>"
                            "x=%{x:.3g}<br>log2FC=%{y:.3g}<extra></extra>"
                        ),
                        name='candidates',
                        showlegend=False,
                    )
                )

                topk = int(self.pri_plot_label_topk.value()) if getattr(self, 'pri_plot_label_topk', None) is not None else 5
                if topk and topk > 0:
                    lab_best = best.copy()
                    if 'score' in lab_best.columns:
                        lab_best = lab_best.sort_values('score', ascending=False)
                    lab_best = lab_best.head(topk)
                    lab = hit[hit['_gene'].isin(set(lab_best['gene_id'].astype(str).tolist()))].copy()
                    if not lab.empty:
                        x_lab = lab[mean_col].values
                        if _np.nanmax(x_all) > 1000:
                            x_lab_plot = _np.log10(_np.clip(x_lab, 1e-9, None))
                        else:
                            x_lab_plot = x_lab
                        fig.add_trace(
                            go.Scatter(
                                x=x_lab_plot,
                                y=lab[lfc_col],
                                mode='markers+text',
                                text=lab['_gene'],
                                textposition='top center',
                                marker=dict(size=9, opacity=0.98, symbol='diamond', color='#111111'),
                                hoverinfo='skip',
                                showlegend=False,
                            )
                        )

        # filename suffix
        safe_label = re.sub(r"[^A-Za-z0-9_.-]+", "_", (deg_label or deg_path.stem))
        safe_scope = re.sub(r"[^A-Za-z0-9_.-]+", "_", scope.lower().replace(' ', '_'))
        suffix = f"{('volcano' if kind.startswith('vol') else 'ma')}_{safe_label}_{safe_scope}"
        title = f"Integrate / Prioritize: DEG overlay ({'Volcano' if kind.startswith('vol') else 'MA'})"
        return fig, title, suffix
    def open_legacy_tools(self):
        """Open legacy multi-tab tools (Locus builder / Annotate / Candidates / Evidence) in a separate window."""
        if getattr(self, "legacy_tools_window", None) is not None:
            try:
                self.legacy_tools_window.show()
                self.legacy_tools_window.raise_()
                self.legacy_tools_window.activateWindow()
                return
            except Exception:
                pass

        w = QWidget()
        w.setWindowTitle("Integrate (legacy tools)")
        tabs = QTabWidget()
        tabs.addTab(self._build_locus_ui(), "Locus builder")
        if self.anno_tab is not None:
            tabs.addTab(self.anno_tab, "Annotate")
        if self.cand_tab is not None:
            tabs.addTab(self.cand_tab, "Candidates")
        tabs.addTab(self._build_evidence_ui(), "Evidence builder")

        lay = QVBoxLayout(); lay.addWidget(tabs)
        w.setLayout(lay)
        w.resize(1100, 800)
        self.legacy_tools_window = w
        w.show()
    # -------------------------
    # Phase 2: Locus builder (integrate_loci)
    # -------------------------
    def _build_locus_ui(self) -> QWidget:
        # GWAS inputs
        self.tbl_locus_gwas = QTableWidget(0, 2)
        self.tbl_locus_gwas.setHorizontalHeaderLabels(["Label", "GWAS results file"])
        try:
            self.tbl_locus_gwas.horizontalHeader().setSectionResizeMode(0, QHeaderView.ResizeToContents)
            self.tbl_locus_gwas.horizontalHeader().setSectionResizeMode(1, QHeaderView.Stretch)
        except Exception:
            pass

        b_g_add = QPushButton("Add GWAS results.tsv/CSV")
        b_g_add.clicked.connect(lambda *a, **k: self._add_locus_gwas_file())
        b_g_last = QPushButton("Add last GWAS results.tsv")
        b_g_last.clicked.connect(lambda *a, **k: self._add_locus_last_gwas())
        b_g_rm = QPushButton("Remove")
        b_g_rm.clicked.connect(lambda *a, **k: self._remove_selected(self.tbl_locus_gwas))
        b_g_cl = QPushButton("Clear")
        b_g_cl.clicked.connect(lambda *a, **k: self.tbl_locus_gwas.setRowCount(0))

        hb_g = QHBoxLayout()
        hb_g.addWidget(b_g_add)
        hb_g.addWidget(b_g_last)
        hb_g.addWidget(b_g_rm)
        hb_g.addWidget(b_g_cl)
        wg = QWidget(); wg.setLayout(hb_g)

        # QTL inputs
        self.tbl_locus_qtl = QTableWidget(0, 2)
        self.tbl_locus_qtl.setHorizontalHeaderLabels(["Label", "QTL peaks file"])
        try:
            self.tbl_locus_qtl.horizontalHeader().setSectionResizeMode(0, QHeaderView.ResizeToContents)
            self.tbl_locus_qtl.horizontalHeader().setSectionResizeMode(1, QHeaderView.Stretch)
        except Exception:
            pass

        b_q_add = QPushButton("Add QTL peaks.tsv/CSV")
        b_q_add.clicked.connect(lambda *a, **k: self._add_locus_qtl_file())
        b_q_last = QPushButton("Add last QTL peaks.tsv")
        b_q_last.clicked.connect(lambda *a, **k: self._add_locus_last_qtl())
        b_q_rm = QPushButton("Remove")
        b_q_rm.clicked.connect(lambda *a, **k: self._remove_selected(self.tbl_locus_qtl))
        b_q_cl = QPushButton("Clear")
        b_q_cl.clicked.connect(lambda *a, **k: self.tbl_locus_qtl.setRowCount(0))

        hb_q = QHBoxLayout()
        hb_q.addWidget(b_q_add)
        hb_q.addWidget(b_q_last)
        hb_q.addWidget(b_q_rm)
        hb_q.addWidget(b_q_cl)
        wq = QWidget(); wq.setLayout(hb_q)

        # Options
        self.gwas_pick_mode = QComboBox()
        self.gwas_pick_mode.addItems(["top_n", "p_threshold"])
        self.gwas_top_n = QSpinBox(); self.gwas_top_n.setRange(1, 10000000); self.gwas_top_n.setValue(200)
        self.gwas_p_threshold = QLineEdit("1e-6")

        self.qtl_pick_mode = QComboBox()
        self.qtl_pick_mode.addItems(["top_n", "lod_threshold"])
        self.qtl_top_n = QSpinBox(); self.qtl_top_n.setRange(1, 10000000); self.qtl_top_n.setValue(50)
        self.qtl_lod_threshold = QLineEdit("3.0")

        self.window_bp = QSpinBox(); self.window_bp.setRange(0, 2_000_000_000); self.window_bp.setValue(50000); self.window_bp.setSingleStep(1000)
        self.normalize_chr = QComboBox(); self.normalize_chr.addItems(["TRUE", "FALSE"]); self.normalize_chr.setCurrentText("TRUE")

        self.ed_out_peaks_merged = QLineEdit()
        self.ed_out_peaks_merged.setReadOnly(True)

        b_run = QPushButton("Run locus builder (integrate_loci)")
        b_run.setStyleSheet(GE_BTN_RUN_QSS)
        b_run.clicked.connect(lambda *a, **k: self.run_locus_builder())

        b_send = QPushButton("Send peaks_merged.tsv → Annotate")
        b_send.clicked.connect(lambda *a, **k: self.send_to_annotate())

        b_open_out = QPushButton("Open output folder")
        b_open_out.clicked.connect(lambda *a, **k: self.open_last_out_dir())

        opt = QFormLayout()
        opt.addRow(QLabel("Peak picking"))
        opt.addRow("GWAS mode", self.gwas_pick_mode)
        opt.addRow("GWAS top_n", self.gwas_top_n)
        opt.addRow("GWAS p_threshold", self.gwas_p_threshold)
        opt.addRow("QTL mode", self.qtl_pick_mode)
        opt.addRow("QTL top_n", self.qtl_top_n)
        opt.addRow("QTL LOD threshold", self.qtl_lod_threshold)
        opt.addRow("window_bp (±)", self.window_bp)
        opt.addRow("normalize_chr", self.normalize_chr)

        row_out = QHBoxLayout()
        row_out.addWidget(self.ed_out_peaks_merged)
        row_out.addWidget(b_send)
        w_out = QWidget(); w_out.setLayout(row_out)
        opt.addRow("peaks_merged.tsv", w_out)

        gbox = QGroupBox("GWAS inputs")
        gv = QVBoxLayout()
        gv.addWidget(wg)
        gv.addWidget(self.tbl_locus_gwas)
        gbox.setLayout(gv)

        qbox = QGroupBox("QTL inputs")
        qv = QVBoxLayout()
        qv.addWidget(wq)
        qv.addWidget(self.tbl_locus_qtl)
        qbox.setLayout(qv)

        obox = QGroupBox("Options / Run")
        ov = QVBoxLayout()
        ov.addLayout(opt)
        hb = QHBoxLayout()
        hb.addWidget(b_run)
        hb.addWidget(b_open_out)
        hb.addStretch(1)
        ov.addLayout(hb)
        obox.setLayout(ov)

        w = QWidget()
        lay = QVBoxLayout()
        lay.addWidget(gbox)
        lay.addWidget(qbox)
        lay.addWidget(obox)
        lay.addStretch(1)
        w.setLayout(lay)
        return w

    def _add_locus_gwas_file(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select GWAS results.tsv/CSV", "", "Table (*.tsv *.txt *.csv);;All (*.*)")
        if not fp:
            return
        p = Path(fp)
        self._add_row_2col(self.tbl_locus_gwas, self._infer_label(p), str(p))

    def _add_locus_last_gwas(self):
        p = self.gwas_tab.get_last_results_tsv() if hasattr(self.gwas_tab, "get_last_results_tsv") else None
        if p is None:
            QMessageBox.information(self, "Info", "No last GWAS output found yet.")
            return
        self._add_row_2col(self.tbl_locus_gwas, self._infer_label(Path(p)), str(p))

    def _add_locus_qtl_file(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select QTL peaks.tsv/CSV", "", "Table (*.tsv *.txt *.csv);;All (*.*)")
        if not fp:
            return
        p = Path(fp)
        self._add_row_2col(self.tbl_locus_qtl, self._infer_label(p), str(p))

    def _add_locus_last_qtl(self):
        p = self.qtl_tab.get_last_peaks_tsv() if hasattr(self.qtl_tab, "get_last_peaks_tsv") else None
        if p is None:
            QMessageBox.information(self, "Info", "No last QTL output found yet.")
            return
        self._add_row_2col(self.tbl_locus_qtl, self._infer_label(Path(p)), str(p))

    def run_locus_builder(self):
        gwas_files = self._paths_from_tbl(self.tbl_locus_gwas)
        qtl_files = self._paths_from_tbl(self.tbl_locus_qtl)

        if not gwas_files and not qtl_files:
            QMessageBox.information(self, "No input", "Add one or more GWAS and/or QTL peak files first.")
            return

        params = {
            "gwas_results": gwas_files,
            "qtl_peaks": qtl_files,
            "mode_gwas": self.gwas_pick_mode.currentText(),
            "gwas_top_n": int(self.gwas_top_n.value()),
            "gwas_p_threshold": str(self.gwas_p_threshold.text()).strip(),
            "mode_qtl": self.qtl_pick_mode.currentText(),
            "qtl_top_n": int(self.qtl_top_n.value()),
            "qtl_lod_threshold": str(self.qtl_lod_threshold.text()).strip(),
            "window_bp": int(self.window_bp.value()),
            "chr_normalize": True if self.normalize_chr.currentText() == "TRUE" else False,
        }

        run_dir = Path(tempfile.mkdtemp(prefix="integrate_loci_"))
        self.append_log(f"Running plugin={self.PLUGIN_LOCUS}")
        self.append_log(f"work_dir={run_dir}")
        try:
            out_dir = run_plugin(REGISTRY_PATH, self.PLUGIN_LOCUS, params, run_dir)
        except Exception as e:
            self.append_log(f"[ERROR] {e}")
            QMessageBox.critical(self, "integrate_loci failed", str(e))
            return

        self.last_out_dir = Path(out_dir)
        self.last_peaks_merged = self.last_out_dir / "peaks_merged.tsv"
        self.ed_out_peaks_merged.setText(str(self.last_peaks_merged) if self.last_peaks_merged.exists() else "")

        loci_tsv = self.last_out_dir / "loci.tsv"
        if loci_tsv.exists():
            try:
                df = read_table_robust(loci_tsv)
                head = df.head(200)
                self.results.set_table_rows(list(head.columns), head.values.tolist())
            except Exception as e:
                self.append_log(f"[WARN] failed to render loci.tsv: {e}")

        self.append_log(f"Done. out_dir={self.last_out_dir}")

    def send_to_annotate(self):
        if not self.last_peaks_merged or not self.last_peaks_merged.exists():
            QMessageBox.information(self, "Info", "peaks_merged.tsv not available yet. Run locus builder first.")
            return
        try:
            self.anno_tab.peaks_tsv.setText(str(self.last_peaks_merged))
            QMessageBox.information(self, "Sent", "peaks_merged.tsv was set in the Annotate tab (peaks_tsv).")
        except Exception as e:
            QMessageBox.warning(self, "Failed", str(e))

    def open_last_out_dir(self):
        if not self.last_out_dir or not self.last_out_dir.exists():
            QMessageBox.information(self, "Info", "No output directory yet. Run locus builder first.")
            return
        try:
            folder = str(self.last_out_dir)
            if sys.platform.startswith("linux"):
                subprocess.Popen(["xdg-open", folder])
            elif sys.platform.startswith("darwin"):
                subprocess.Popen(["open", folder])
            elif sys.platform.startswith("win"):
                os.startfile(folder)  # type: ignore
        except Exception as e:
            QMessageBox.warning(self, "Failed", str(e))

    # -------------------------
    # Phase 3: Evidence builder (integrate_evidence)
    # -------------------------
    def _build_evidence_ui(self) -> QWidget:
        # core inputs
        self.ed_evi_loci = QLineEdit()
        b_loci = QPushButton("Browse")
        b_loci.setStyleSheet(GE_BTN_BROWSE_QSS)
        b_loci.clicked.connect(lambda *a, **k: self._pick_file_lineedit(self.ed_evi_loci, "TSV (*.tsv *.txt *.csv);;All (*.*)"))
        b_loci_last = QPushButton("Use last loci.tsv")
        b_loci_last.clicked.connect(lambda *a, **k: self._use_last_locus_file("loci.tsv", self.ed_evi_loci))

        self.ed_evi_locus_peaks = QLineEdit()
        b_lp = QPushButton("Browse")
        b_lp.setStyleSheet(GE_BTN_BROWSE_QSS)
        b_lp.clicked.connect(lambda *a, **k: self._pick_file_lineedit(self.ed_evi_locus_peaks, "TSV (*.tsv *.txt *.csv);;All (*.*)"))
        b_lp_last = QPushButton("Use last locus_peaks.tsv")
        b_lp_last.clicked.connect(lambda *a, **k: self._use_last_locus_file("locus_peaks.tsv", self.ed_evi_locus_peaks))

        self.ed_evi_anno = QLineEdit()
        b_anno = QPushButton("Browse")
        b_anno.setStyleSheet(GE_BTN_BROWSE_QSS)
        b_anno.clicked.connect(lambda *a, **k: self._pick_file_lineedit(self.ed_evi_anno, "TSV (*.tsv *.txt *.csv);;All (*.*)"))

        # DEG list
        self.tbl_evi_deg = QTableWidget(0, 2)
        self.tbl_evi_deg.setHorizontalHeaderLabels(["Label", "DEG file"])
        try:
            self.tbl_evi_deg.horizontalHeader().setSectionResizeMode(0, QHeaderView.ResizeToContents)
            self.tbl_evi_deg.horizontalHeader().setSectionResizeMode(1, QHeaderView.Stretch)
        except Exception:
            pass
        b_deg_add = QPushButton("Add DEG TSV")
        b_deg_add.clicked.connect(lambda *a, **k: self._add_evi_deg_file())
        b_deg_rm = QPushButton("Remove")
        b_deg_rm.clicked.connect(lambda *a, **k: self._remove_selected(self.tbl_evi_deg))
        b_deg_cl = QPushButton("Clear")
        b_deg_cl.clicked.connect(lambda *a, **k: self.tbl_evi_deg.setRowCount(0))
        hb_deg = QHBoxLayout(); hb_deg.addWidget(b_deg_add); hb_deg.addWidget(b_deg_rm); hb_deg.addWidget(b_deg_cl); hb_deg.addStretch(1)
        w_deg_btn = QWidget(); w_deg_btn.setLayout(hb_deg)

        # BLAST list
        self.tbl_evi_blast = QTableWidget(0, 2)
        self.tbl_evi_blast.setHorizontalHeaderLabels(["Label", "BLAST file"])
        try:
            self.tbl_evi_blast.horizontalHeader().setSectionResizeMode(0, QHeaderView.ResizeToContents)
            self.tbl_evi_blast.horizontalHeader().setSectionResizeMode(1, QHeaderView.Stretch)
        except Exception:
            pass
        b_bl_add = QPushButton("Add BLAST TSV")
        b_bl_add.clicked.connect(lambda *a, **k: self._add_evi_blast_file())
        b_bl_rm = QPushButton("Remove")
        b_bl_rm.clicked.connect(lambda *a, **k: self._remove_selected(self.tbl_evi_blast))
        b_bl_cl = QPushButton("Clear")
        b_bl_cl.clicked.connect(lambda *a, **k: self.tbl_evi_blast.setRowCount(0))
        hb_bl = QHBoxLayout(); hb_bl.addWidget(b_bl_add); hb_bl.addWidget(b_bl_rm); hb_bl.addWidget(b_bl_cl); hb_bl.addStretch(1)
        w_bl_btn = QWidget(); w_bl_btn.setLayout(hb_bl)

        self.ed_out_locus_evidence = QLineEdit(); self.ed_out_locus_evidence.setReadOnly(True)
        self.ed_out_locus_gene = QLineEdit(); self.ed_out_locus_gene.setReadOnly(True)

        b_run = QPushButton("Run evidence builder (integrate_evidence)")
        b_run.setStyleSheet(GE_BTN_RUN_QSS)
        b_run.clicked.connect(lambda *a, **k: self.run_evidence_builder())
        b_open = QPushButton("Open output folder")
        b_open.clicked.connect(lambda *a, **k: self.open_evidence_out_dir())

        form = QFormLayout()
        row = QHBoxLayout(); row.addWidget(self.ed_evi_loci); row.addWidget(b_loci); row.addWidget(b_loci_last)
        form.addRow("loci.tsv", row)
        row = QHBoxLayout(); row.addWidget(self.ed_evi_locus_peaks); row.addWidget(b_lp); row.addWidget(b_lp_last)
        form.addRow("locus_peaks.tsv", row)
        row = QHBoxLayout(); row.addWidget(self.ed_evi_anno); row.addWidget(b_anno)
        form.addRow("Annotate/GenePred genes TSV", row)

        out_form = QFormLayout()
        out_form.addRow("locus_evidence.tsv", self.ed_out_locus_evidence)
        out_form.addRow("locus_gene_evidence.tsv", self.ed_out_locus_gene)

        box_in = QGroupBox("Evidence inputs")
        v_in = QVBoxLayout(); v_in.addLayout(form); box_in.setLayout(v_in)

        box_deg = QGroupBox("DEG inputs (optional)")
        v_deg = QVBoxLayout(); v_deg.addWidget(w_deg_btn); v_deg.addWidget(self.tbl_evi_deg); box_deg.setLayout(v_deg)

        box_bl = QGroupBox("BLAST inputs (optional)")
        v_bl = QVBoxLayout(); v_bl.addWidget(w_bl_btn); v_bl.addWidget(self.tbl_evi_blast); box_bl.setLayout(v_bl)

        box_out = QGroupBox("Outputs")
        v_out = QVBoxLayout(); v_out.addLayout(out_form); box_out.setLayout(v_out)

        w = QWidget()
        lay = QVBoxLayout()
        lay.addWidget(box_in)
        lay.addWidget(box_deg)
        lay.addWidget(box_bl)
        hb = QHBoxLayout(); hb.addWidget(b_run); hb.addWidget(b_open); hb.addStretch(1)
        lay.addLayout(hb)
        lay.addWidget(box_out)
        lay.addStretch(1)
        w.setLayout(lay)
        return w

    def _pick_file_lineedit(self, le: QLineEdit, filt: str):
        fp, _ = QFileDialog.getOpenFileName(self, "Select file", "", filt)
        if fp:
            le.setText(fp)

    def _pick_dir_lineedit(self, le: QLineEdit):
        d = QFileDialog.getExistingDirectory(self, "Select folder", "")
        if d:
            le.setText(d)

    def _use_last_locus_file(self, name: str, le: QLineEdit):
        if self.last_out_dir and (self.last_out_dir / name).exists():
            le.setText(str(self.last_out_dir / name))
        else:
            QMessageBox.information(self, "Info", f"No last output found for {name}. Run locus builder first or browse manually.")

    def _add_evi_deg_file(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select DEG TSV/CSV", "", "Table (*.tsv *.txt *.csv);;All (*.*)")
        if not fp:
            return
        p = Path(fp)
        self._add_row_2col(self.tbl_evi_deg, self._infer_label(p), str(p))

    def _add_evi_blast_file(self):
        fp, _ = QFileDialog.getOpenFileName(self, "Select BLAST TSV/CSV", "", "Table (*.tsv *.txt *.csv);;All (*.*)")
        if not fp:
            return
        p = Path(fp)
        self._add_row_2col(self.tbl_evi_blast, self._infer_label(p), str(p))

    def run_evidence_builder(self):
        loci = str(self.ed_evi_loci.text()).strip()
        locus_peaks = str(self.ed_evi_locus_peaks.text()).strip()
        anno = str(self.ed_evi_anno.text()).strip()
        if not loci or not locus_peaks or not anno:
            QMessageBox.information(self, "Missing input", "Please provide loci.tsv, locus_peaks.tsv, and an annotate genes TSV.")
            return

        params = {
            "loci_tsv": loci,
            "locus_peaks_tsv": locus_peaks,
            "annotate_genes_tsv": anno,
            "deg_tsv_list": self._paths_from_tbl(self.tbl_evi_deg),
            "blast_tsv_list": self._paths_from_tbl(self.tbl_evi_blast),
        }

        run_dir = Path(tempfile.mkdtemp(prefix="integrate_evidence_"))
        self.append_log(f"Running plugin={self.PLUGIN_EVIDENCE}")
        self.append_log(f"work_dir={run_dir}")
        try:
            out_dir = run_plugin(REGISTRY_PATH, self.PLUGIN_EVIDENCE, params, run_dir)
        except Exception as e:
            self.append_log(f"[ERROR] {e}")
            QMessageBox.critical(self, "integrate_evidence failed", str(e))
            return

        self.last_evidence_out_dir = Path(out_dir)
        p1 = self.last_evidence_out_dir / "locus_evidence.tsv"
        p2 = self.last_evidence_out_dir / "locus_gene_evidence.tsv"
        self.ed_out_locus_evidence.setText(str(p1) if p1.exists() else "")
        self.ed_out_locus_gene.setText(str(p2) if p2.exists() else "")

        if p1.exists():
            try:
                df = read_table_robust(p1)
                head = df.head(200)
                self.results.set_table_rows(list(head.columns), head.values.tolist())
            except Exception as e:
                self.append_log(f"[WARN] failed to render locus_evidence.tsv: {e}")

        self.append_log(f"Done. out_dir={self.last_evidence_out_dir}")

    def open_evidence_out_dir(self):
        if not self.last_evidence_out_dir or not self.last_evidence_out_dir.exists():
            QMessageBox.information(self, "Info", "No output directory yet. Run evidence builder first.")
            return
        try:
            folder = str(self.last_evidence_out_dir)
            if sys.platform.startswith("linux"):
                subprocess.Popen(["xdg-open", folder])
            elif sys.platform.startswith("darwin"):
                subprocess.Popen(["open", folder])
            elif sys.platform.startswith("win"):
                os.startfile(folder)  # type: ignore
        except Exception as e:
            QMessageBox.warning(self, "Failed", str(e))


