class PolyOutputLinkState(QObject):
    """One-shot output_folder propagation across Polyploid subtabs.

    Behavior
    --------
    - The first time the user selects (or edits) an output_folder in any Polyploid subtab,
      we propagate it to other Polyploid subtabs *only if* their output_folder is still empty.
    - After initialization, no further automatic linking is performed; users can freely edit
      each subtab's output_folder independently.
    """

    sig_init = Signal(str)

    def __init__(self):
        super().__init__()
        self._initialized = False
        self._folder = ''

    def try_init(self, folder: str) -> bool:
        folder = str(folder or '').strip()
        if not folder:
            return False
        if self._initialized:
            return False
        self._initialized = True
        self._folder = folder
        try:
            self.sig_init.emit(folder)
        except Exception:
            pass
        return True

    @property
    def initialized(self) -> bool:
        return bool(self._initialized)

    @property
    def folder(self) -> str:
        return str(self._folder)




class PolyPrepareTab(QWidget):
    """Build and QC PolyCounts (ref/total read count matrices) for polyploid calling.

    Workflow:
      1) Prepare counts from VCF (AD/DP) or two TSV matrices or cached RDS -> poly_counts.rds
      2) QC/filter counts -> poly_counts_filtered.rds
      3) Feed filtered RDS into updog / PolyRAD / etc.
    """
    PLUGIN_PREP = "poly_prepare_counts"
    PLUGIN_QC = "poly_qc_counts"

    def __init__(self, app_log: QTextEdit, results: ResultsPane, shared_state=None):
        super().__init__()
        self.app_log = app_log
        self.results = results
        self.shared_state = shared_state

        # output_folder (optional): results will be exported here (core layer copies out/*)
        self.output_dir = QLineEdit()
        self.output_dir.setPlaceholderText("Select output folder (optional)")
        b_out = QPushButton("Browse")
        b_out.setStyleSheet(GE_BTN_BROWSE_QSS)
        b_out.setToolTip("Select output folder")
        b_out.clicked.connect(self.pick_output_dir)
        try:
            self.output_dir.editingFinished.connect(self._maybe_init_output_link)
        except Exception:
            pass
        if self.shared_state is not None:
            try:
                self.shared_state.sig_init.connect(self._on_shared_init_folder)
            except Exception:
                pass
        self.last_out_dir = None
        self.prepared_counts_rds = ""
        self.filtered_counts_rds = ""

        # ---------- Prepare ----------
        self.ploidy = QSpinBox()
        self.ploidy.setRange(2, 16)
        self.ploidy.setValue(4)

        self.input_mode = QComboBox()
        self.input_mode.addItems(["VCF (AD/DP)", "Counts TSV (ref+total)", "Counts RDS (cached)"])
        self.input_mode.currentIndexChanged.connect(lambda *args, **kwargs: self._sync_mode(*args, **kwargs))

        # VCF inputs
        self.vcf_path = QLineEdit()
        btn_v = QPushButton("Browse")
        btn_v.setStyleSheet(GE_BTN_BROWSE_QSS)
        btn_v.clicked.connect(lambda: self._pick_file(self.vcf_path, "VCF (*.vcf *.vcf.gz);;All (*.*)"))

        self.ad_field = QLineEdit("AD")
        self.dp_field = QLineEdit("DP")
        self.use_dp_for_total = QCheckBox("Use DP for total (if available)")
        self.use_dp_for_total.setChecked(False)
        self.drop_multiallelic = QCheckBox("Drop multiallelic sites")
        self.drop_multiallelic.setChecked(True)

        # TSV inputs
        self.ref_count_tsv = QLineEdit()
        btn_r = QPushButton("Browse")
        btn_r.setStyleSheet(GE_BTN_BROWSE_QSS)
        btn_r.clicked.connect(lambda: self._pick_file(self.ref_count_tsv, "TSV (*.tsv *.txt);;All (*.*)"))
        self.total_count_tsv = QLineEdit()
        btn_t = QPushButton("Browse")
        btn_t.setStyleSheet(GE_BTN_BROWSE_QSS)
        btn_t.clicked.connect(lambda: self._pick_file(self.total_count_tsv, "TSV (*.tsv *.txt);;All (*.*)"))

        self.orientation = QComboBox()
        self.orientation.addItems(["markers_rows", "samples_rows"])
        self.write_matrix_tsv = QCheckBox("Write ref/total matrices as TSV (can be huge)")
        self.write_matrix_tsv.setChecked(False)

        # Cached RDS input
        self.counts_rds_in = QLineEdit()
        btn_cr = QPushButton("Browse")
        btn_cr.setStyleSheet(GE_BTN_BROWSE_QSS)
        btn_cr.clicked.connect(lambda: self._pick_file(self.counts_rds_in, "RDS (*.rds);;All (*.*)"))

        prep_form = QFormLayout()
        prep_form.addRow("Ploidy", self.ploidy)
        prep_form.addRow("Input mode", self.input_mode)

        row = QHBoxLayout(); row.addWidget(self.vcf_path); row.addWidget(btn_v)
        prep_form.addRow("VCF path", row)
        row = QHBoxLayout(); row.addWidget(self.ad_field); row.addWidget(QLabel("DP field")); row.addWidget(self.dp_field)
        prep_form.addRow("FORMAT fields", row)
        #prep_form.addRow("", self.use_dp_for_total)
        #prep_form.addRow("", self.drop_multiallelic)

        row = QHBoxLayout(); row.addWidget(self.ref_count_tsv); row.addWidget(btn_r)
        prep_form.addRow("ref_count.tsv", row)
        row = QHBoxLayout(); row.addWidget(self.total_count_tsv); row.addWidget(btn_t)
        prep_form.addRow("total_count.tsv", row)
        #prep_form.addRow("Orientation", self.orientation)
        #prep_form.addRow("", self.write_matrix_tsv)

        row = QHBoxLayout(); row.addWidget(self.counts_rds_in); row.addWidget(btn_cr)
        prep_form.addRow("counts.rds (cached)", row)

        prep_btn = QPushButton("1) Prepare counts (PolyCounts)")
        prep_btn.setStyleSheet(GE_BTN_RUN_QSS)
        prep_btn.clicked.connect(lambda *args, **kwargs: self.run_prepare())

        prep_box = QGroupBox("Prepare counts (VCF/TSV/RDS → poly_counts.rds)")
        v = QVBoxLayout()
        v.addLayout(prep_form)
        v.addWidget(prep_btn)
        prep_box.setLayout(v)

        # ---------- QC ----------
        self.qc_counts_rds = QLineEdit()
        btn_qc_in = QPushButton("Browse")
        btn_qc_in.setStyleSheet(GE_BTN_BROWSE_QSS)
        btn_qc_in.clicked.connect(lambda: self._pick_file(self.qc_counts_rds, "RDS (*.rds);;All (*.*)"))

        self.marker_max_missing = QDoubleSpinBox(); self.marker_max_missing.setRange(0, 1); self.marker_max_missing.setValue(0.5); self.marker_max_missing.setSingleStep(0.05)
        self.sample_max_missing = QDoubleSpinBox(); self.sample_max_missing.setRange(0, 1); self.sample_max_missing.setValue(0.5); self.sample_max_missing.setSingleStep(0.05)
        self.marker_min_mean_depth = QDoubleSpinBox(); self.marker_min_mean_depth.setRange(0, 1e9); self.marker_min_mean_depth.setValue(5); self.marker_min_mean_depth.setDecimals(2)
        self.sample_min_mean_depth = QDoubleSpinBox(); self.sample_min_mean_depth.setRange(0, 1e9); self.sample_min_mean_depth.setValue(5); self.sample_min_mean_depth.setDecimals(2)
        self.min_ref_frac = QDoubleSpinBox(); self.min_ref_frac.setRange(0, 1); self.min_ref_frac.setValue(0.02); self.min_ref_frac.setSingleStep(0.01)
        self.max_ref_frac = QDoubleSpinBox(); self.max_ref_frac.setRange(0, 1); self.max_ref_frac.setValue(0.98); self.max_ref_frac.setSingleStep(0.01)

        qc_form = QFormLayout()
        row = QHBoxLayout(); row.addWidget(self.qc_counts_rds); row.addWidget(btn_qc_in)
        qc_form.addRow("counts_rds", row)
        qc_form.addRow("Marker max missing", self.marker_max_missing)
        qc_form.addRow("Sample max missing", self.sample_max_missing)
        qc_form.addRow("Marker min mean depth", self.marker_min_mean_depth)
        qc_form.addRow("Sample min mean depth", self.sample_min_mean_depth)
        qc_form.addRow("Min ref fraction", self.min_ref_frac)
        qc_form.addRow("Max ref fraction", self.max_ref_frac)

        qc_btn = QPushButton("2) QC/filter counts (→ poly_counts_filtered.rds)")
        qc_btn.setStyleSheet(GE_BTN_RUN_QSS)
        qc_btn.clicked.connect(lambda *args, **kwargs: self.run_qc())

        qc_box = QGroupBox("QC/filter counts")
        v2 = QVBoxLayout()
        v2.addLayout(qc_form)
        v2.addWidget(qc_btn)
        qc_box.setLayout(v2)

        scroll = QScrollArea()
        scroll.setWidgetResizable(True)
        inner = QWidget()
        lay = QVBoxLayout()
        out_form = QFormLayout()
        out_row = QHBoxLayout(); out_row.addWidget(self.output_dir); out_row.addWidget(b_out)
        out_form.addRow("output_folder", out_row)
        out_wrap = QWidget(); out_wrap.setLayout(out_form)
        lay.addWidget(out_wrap)

        lay.addWidget(prep_box)
        lay.addWidget(qc_box)
        lay.addStretch(1)
        inner.setLayout(lay)
        scroll.setWidget(inner)

        root = QVBoxLayout()
        root.addWidget(scroll)
        self.setLayout(root)

        self._sync_mode()

    def _sync_mode(self, *args, **kwargs):
        mode = self.input_mode.currentText()
        is_vcf = mode.startswith("VCF")
        is_tsv = mode.startswith("Counts TSV")
        is_rds = mode.startswith("Counts RDS")

        # VCF controls
        self.vcf_path.setEnabled(is_vcf)
        self.ad_field.setEnabled(is_vcf)
        self.dp_field.setEnabled(is_vcf)
        self.use_dp_for_total.setEnabled(is_vcf)
        self.drop_multiallelic.setEnabled(is_vcf)

        # TSV controls
        self.ref_count_tsv.setEnabled(is_tsv)
        self.total_count_tsv.setEnabled(is_tsv)
        self.orientation.setEnabled(is_tsv)
        self.write_matrix_tsv.setEnabled(is_tsv)

        # RDS controls
        self.counts_rds_in.setEnabled(is_rds)

    def _pick_file(self, lineedit: QLineEdit, filt: str):
        fp, _ = QFileDialog.getOpenFileName(self, "Select file", "", filt)
        if fp:
            lineedit.setText(fp)

    def pick_output_dir(self):
        d = QFileDialog.getExistingDirectory(self, "Select output folder")
        if d:
            try:
                Path(d).mkdir(parents=True, exist_ok=True)
            except Exception:
                pass
            self.output_dir.setText(d)
            self._maybe_init_output_link()

    def _maybe_init_output_link(self):
        folder = (self.output_dir.text() or '').strip()
        if not folder:
            return
        if self.shared_state is not None:
            try:
                self.shared_state.try_init(folder)
            except Exception:
                pass

    def _on_shared_init_folder(self, folder: str):
        if not (self.output_dir.text() or '').strip():
            self.output_dir.setText(str(folder))

    def append_log(self, msg: str):
        self.app_log.append(msg)

    def run_prepare(self):
        mode = self.input_mode.currentText()
        if mode.startswith("VCF"):
            input_mode = "vcf"
        elif mode.startswith("Counts TSV"):
            input_mode = "counts_tsv"
        else:
            input_mode = "counts_rds"

        params = {
            "ploidy": int(self.ploidy.value()),
            "input_mode": input_mode,
            "vcf_path": self.vcf_path.text().strip(),
            "ad_field": self.ad_field.text().strip(),
            "dp_field": self.dp_field.text().strip(),
            "use_dp_for_total": bool(self.use_dp_for_total.isChecked()),
            "drop_multiallelic": bool(self.drop_multiallelic.isChecked()),
            "ref_count_tsv": self.ref_count_tsv.text().strip(),
            "total_count_tsv": self.total_count_tsv.text().strip(),
            "counts_rds": self.counts_rds_in.text().strip(),
            "orientation": self.orientation.currentText().strip(),
            "write_matrix_tsv": bool(self.write_matrix_tsv.isChecked()),
        }

        out_root = (self.output_dir.text() if hasattr(self, 'output_dir') else '').strip()
        if out_root:
            try:
                Path(out_root).mkdir(parents=True, exist_ok=True)
                params['export_dir'] = out_root
            except Exception as e:
                QMessageBox.warning(self, 'Error', f'Cannot create output_folder: {e}')
                return

        run_dir = Path(tempfile.mkdtemp(prefix="poly_prepare_counts_"))
        self.append_log(f"Running plugin={self.PLUGIN_PREP}")
        self.append_log(f"work_dir={run_dir}")
        try:
            out_dir = run_plugin(REGISTRY_PATH, self.PLUGIN_PREP, params, run_dir)
        except Exception as e:
            self.append_log(f"[ERROR] {e}")
            QMessageBox.critical(self, "Run failed", str(e))
            return

        self.last_out_dir = out_dir
        self.append_log(f"Done. out_dir={out_dir}")
        # auto-fill qc input
        rds = out_dir / "poly_counts.rds"
        if rds.exists():
            self.prepared_counts_rds = str(rds)
            self.qc_counts_rds.setText(self.prepared_counts_rds)
        # show outputs
        tsv = out_dir / "counts_marker_summary.tsv"
        if tsv.exists():
            self.results.load_table(tsv)
        png = out_dir / "counts_missingness.png"
        if png.exists():
            self.results.set_plot(png)

    def run_qc(self):
        params = {
            "counts_rds": self.qc_counts_rds.text().strip(),
            "marker_max_missing": float(self.marker_max_missing.value()),
            "sample_max_missing": float(self.sample_max_missing.value()),
            "marker_min_mean_depth": float(self.marker_min_mean_depth.value()),
            "sample_min_mean_depth": float(self.sample_min_mean_depth.value()),
            "min_ref_frac": float(self.min_ref_frac.value()),
            "max_ref_frac": float(self.max_ref_frac.value()),
        }

        out_root = (self.output_dir.text() if hasattr(self, 'output_dir') else '').strip()
        if out_root:
            try:
                Path(out_root).mkdir(parents=True, exist_ok=True)
                params['export_dir'] = out_root
            except Exception as e:
                QMessageBox.warning(self, 'Error', f'Cannot create output_folder: {e}')
                return
        run_dir = Path(tempfile.mkdtemp(prefix="poly_qc_counts_"))
        self.append_log(f"Running plugin={self.PLUGIN_QC}")
        self.append_log(f"work_dir={run_dir}")
        try:
            out_dir = run_plugin(REGISTRY_PATH, self.PLUGIN_QC, params, run_dir)
        except Exception as e:
            self.append_log(f"[ERROR] {e}")
            QMessageBox.critical(self, "Run failed", str(e))
            return

        self.append_log(f"Done. out_dir={out_dir}")
        rds = out_dir / "poly_counts_filtered.rds"
        if rds.exists():
            self.filtered_counts_rds = str(rds)

        tsv = out_dir / "removed_markers.tsv"
        if tsv.exists():
            self.results.load_table(tsv)
        png = out_dir / "qc_counts_missingness.png"
        if png.exists():
            self.results.set_plot(png)

from PySide6.QtCore import QObject, Signal, Slot, QThread

class PluginRunWorker(QObject):
    log = Signal(str)
    finished = Signal(object)   # out_dir (Path)
    failed = Signal(str)

    def __init__(self, registry_path, plugin_id, params, run_dir):
        super().__init__()
        self.registry_path = registry_path
        self.plugin_id = plugin_id
        self.params = params
        self.run_dir = run_dir

    @Slot()
    def run(self):
        try:
            # ここはワーカースレッドで実行される
            out_dir = run_plugin(self.registry_path, self.plugin_id, self.params, self.run_dir)
            self.finished.emit(out_dir)
        except Exception as e:
            self.failed.emit(str(e))


