        b_out.setStyleSheet(GE_BTN_BROWSE_QSS)
        b_out.setToolTip("Select output folder")
        b_out.clicked.connect(self.pick_output_dir)
        try:
            self.output_dir.editingFinished.connect(self._maybe_init_output_link)
        except Exception:
            pass
        if self.shared_state is not None:
            try:
                self.shared_state.sig_init.connect(self._on_shared_init_folder)
            except Exception:
                pass
        self.last_out_dir = None  # type: Path | None

        self.ploidy = QSpinBox(); self.ploidy.setRange(2, 16); self.ploidy.setValue(4)

        self.dosage_tsv = QLineEdit()
        b_dos = QPushButton("Browse")
        b_dos.setStyleSheet(GE_BTN_BROWSE_QSS)
        b_dos.clicked.connect(lambda: self._pick_file(self.dosage_tsv, "TSV (*.tsv *.txt *.csv);;All (*.*)"))

        self.marker_info_tsv = QLineEdit()
        b_map = QPushButton("Browse")
        b_map.setStyleSheet(GE_BTN_BROWSE_QSS)
        b_map.clicked.connect(lambda: self._pick_file(self.marker_info_tsv, "TSV (*.tsv *.txt *.csv);;All (*.*)"))

        self.pheno_tsv = QLineEdit()
        b_ph = QPushButton("Browse")
        b_ph.setStyleSheet(GE_BTN_BROWSE_QSS)
        b_ph.clicked.connect(lambda: self._pick_file(self.pheno_tsv, "TSV (*.tsv *.txt *.csv);;All (*.*)"))

        self.trait = QLineEdit("trait1")

