        self.geno_freq = QLineEdit("")
        self.geno_freq.setPlaceholderText("Optional geno.freq filter (e.g. 0.05)")

        self.thr_method = QComboBox(); self.thr_method.addItems(["M.eff", "Bonferroni", "FDR", "permute"])
        self.thr_level = QLineEdit("0.05")
        self.n_permute = QSpinBox(); self.n_permute.setRange(10, 5_000_000); self.n_permute.setValue(1000)
        self.bp_window = QLineEdit("")
