        form = QFormLayout()
        out_row = QHBoxLayout(); out_row.addWidget(self.output_dir); out_row.addWidget(b_out)
        form.addRow("output_folder", out_row)
        form.addRow("Ploidy", self.ploidy)
        row1 = QHBoxLayout(); row1.addWidget(self.dosage_tsv); row1.addWidget(b_dos)
        form.addRow("dosage.tsv", row1)
        row2 = QHBoxLayout(); row2.addWidget(self.marker_info_tsv); row2.addWidget(b_map)
        form.addRow("marker_info.tsv", row2)
