        import_box = QGroupBox("1) Import (geno.rds → mappoly.data)")
        v = QVBoxLayout(); v.addLayout(import_form); v.addWidget(btn_import)
        import_box.setLayout(v)

        # --- Stage 2: Filter/QC ---
        self.mappoly_data_rds = QLineEdit()
        btn_dat = QPushButton("Browse")
