        self.seg_mode = QComboBox(); self.seg_mode.addItems(["bonferroni", "pval"])
        self.seg_pval = QDoubleSpinBox(); self.seg_pval.setRange(0, 1); self.seg_pval.setDecimals(6); self.seg_pval.setValue(0.05)

        filter_form = QFormLayout()
