    def run_map(self):
        params = {
            "order_rds": self.order_rds.text().strip(),
            "mappoly_data_rds": self.mappoly_data_rds.text().strip(),
            "ncpus": int(self.map_ncpus.value()),
            "update_global_error": bool(self.update_global_error.isChecked()),
            "global_error": float(self.global_error.value()),
        }

        params = self._maybe_add_export_dir(params)
        if params is None:
            return
        run_dir = Path(tempfile.mkdtemp(prefix="poly_mappoly_map_"))
