    def run_export(self):
        params = {
            "map_list_rds": self.map_list_rds.text().strip(),
            "mappoly_data_rds": self.mappoly_data_rds.text().strip(),
            "use_updated": bool(self.use_updated.isChecked()),
            "export_csv": bool(self.export_csv.isChecked()),
            "export_qtlpoly": bool(self.export_qtlpoly.isChecked()),
            "step": float(self.qtl_step.value()),
            "error": float(self.qtl_error.value()),
        }

        params = self._maybe_add_export_dir(params)
        if params is None:
            return
        run_dir = Path(tempfile.mkdtemp(prefix="poly_mappoly_export_"))
        self.append_log(f"Running plugin={self.PLUGIN_EXPORT}")
        self.append_log(f"work_dir={run_dir}")
        try:
            out_dir = run_plugin(REGISTRY_PATH, self.PLUGIN_EXPORT, params, run_dir)
        except Exception as e:
            self.append_log(f"[ERROR] {e}")
            QMessageBox.critical(self, "Run failed", str(e))
            return
        self.append_log(f"Done. out_dir={out_dir}")
        summ = out_dir / "export_summary.tsv"
        if summ.exists():
            self.results.load_table(summ)



