class PolyQTLTab(QWidget):
    PLUGIN_ID = "poly_qtlpoly_scan"
    def __init__(self, app_log: QTextEdit, results: ResultsPane, shared_state=None):
        super().__init__()
        self.app_log = app_log
        self.results = results

        self.shared_state = shared_state

        # output_folder (optional): results will be exported here (core layer copies out/*)
        self.output_dir = QLineEdit()
        self.output_dir.setPlaceholderText("Select output folder (optional)")
        b_out = QPushButton("Browse")
        b_out.setStyleSheet(GE_BTN_BROWSE_QSS)
        b_out.setToolTip("Select output folder")
        b_out.clicked.connect(self.pick_output_dir)
        try:
            self.output_dir.editingFinished.connect(self._maybe_init_output_link)
        except Exception:
            pass
        if self.shared_state is not None:
            try:
                self.shared_state.sig_init.connect(self._on_shared_init_folder)
            except Exception:
                pass

        self.ploidy = QSpinBox()
        self.ploidy.setRange(2, 16)
        self.ploidy.setValue(4)

        # QTLpoly expects genotype conditional probabilities. We use the file exported from the MAPpoly tab.
        self.qtlpoly_export_rds = QLineEdit()
        btn_gp = QPushButton("Browse")
        btn_gp.setStyleSheet(GE_BTN_BROWSE_QSS)
        btn_gp.clicked.connect(lambda: self._pick_file(self.qtlpoly_export_rds, "RDS (*.rds);;All (*.*)"))

        self.pheno_tsv = QLineEdit()
        btn_ph = QPushButton("Browse")
        btn_ph.setStyleSheet(GE_BTN_BROWSE_QSS)
        btn_ph.clicked.connect(lambda: self._pick_file(self.pheno_tsv, "Phenotype TSV (*.tsv *.txt *.csv);;All (*.*)"))

        self.trait = QLineEdit()
        self.trait.setText("trait1")

        # Optional map table to interpolate cM -> bp (if it has both cM and bp columns)
        self.map_markers = QLineEdit()
        btn_map = QPushButton("Browse")
        btn_map.setStyleSheet(GE_BTN_BROWSE_QSS)
        btn_map.clicked.connect(lambda: self._pick_file(self.map_markers, "Map/marker TSV (*.tsv *.txt *.csv);;All (*.*)"))

        self.extra_json = QPlainTextEdit()
        self.extra_json.setPlaceholderText(
            "Additional JSON options (merged into params).\n"
            "Example:\n"
            "{\n"
            "  \"step_cM\": 1,\n"
            "  \"w_size_cM\": 15,\n"
            "  \"threshold_mode\": \"pointwise_manual\",\n"
            "  \"sig_fwd\": 0.01,\n"
            "  \"sig_bwd\": 1e-4,\n"
            "  \"d_sint\": 1.5,\n"
            "  \"n_cores\": 4\n"
            "}\n"
        )

        basic = QFormLayout()
        out_row = QHBoxLayout(); out_row.addWidget(self.output_dir); out_row.addWidget(b_out)
        basic.addRow("output_folder", out_row)
        basic.addRow("Ploidy", self.ploidy)
        row0 = QHBoxLayout(); row0.addWidget(self.qtlpoly_export_rds); row0.addWidget(btn_gp)
        basic.addRow("qtlpoly_export.rds", row0)
        row2 = QHBoxLayout(); row2.addWidget(self.pheno_tsv); row2.addWidget(btn_ph)
        basic.addRow("phenotype.tsv", row2)
        basic.addRow("trait column", self.trait)
        row1 = QHBoxLayout(); row1.addWidget(self.map_markers); row1.addWidget(btn_map)
        basic.addRow("map (optional; cM↔bp)", row1)

        adv = QFormLayout()
        adv.addRow("extra_options (JSON)", self.extra_json)
        adv_box = QGroupBox("Advanced (QTLpoly)")
        adv_box.setCheckable(True)
        adv_box.setChecked(False)
        adv_box.setLayout(adv)

        run_btn = QPushButton("Run")
        run_btn.setStyleSheet(GE_BTN_RUN_QSS)
        run_btn.clicked.connect(lambda *args, **kwargs: self.run())

        box = QGroupBox("QTL mapping: QTLpoly")
        v = QVBoxLayout()
        v.addLayout(basic)
        v.addWidget(run_btn)
        v.addWidget(adv_box)
        box.setLayout(v)

        scroll = QScrollArea()
        scroll.setWidgetResizable(True)
        inner = QWidget()
        lay = QVBoxLayout()
        lay.addWidget(box)
        lay.addStretch(1)
        inner.setLayout(lay)
        scroll.setWidget(inner)

        root = QVBoxLayout()
        root.addWidget(scroll)
        self.setLayout(root)

    def _pick_file(self, lineedit: QLineEdit, filt: str):
        fp, _ = QFileDialog.getOpenFileName(self, "Select file", "", filt)
        if fp:
            lineedit.setText(fp)

    def pick_output_dir(self):
        d = QFileDialog.getExistingDirectory(self, "Select output folder")
        if d:
            try:
                Path(d).mkdir(parents=True, exist_ok=True)
            except Exception:
                pass
            self.output_dir.setText(d)
            self._maybe_init_output_link()

    def _maybe_init_output_link(self):
        folder = (self.output_dir.text() or '').strip()
        if not folder:
            return
        if self.shared_state is not None:
            try:
                self.shared_state.try_init(folder)
            except Exception:
                pass

    def _on_shared_init_folder(self, folder: str):
        if not (self.output_dir.text() or '').strip():
            self.output_dir.setText(str(folder))

    def append_log(self, msg: str):
        self.app_log.append(msg)

    def run(self):
        geno_prob = self.qtlpoly_export_rds.text().strip()
        pheno = self.pheno_tsv.text().strip()
        trait = self.trait.text().strip()

        if not geno_prob or not Path(geno_prob).exists():
            QMessageBox.warning(self, "Error", "qtlpoly_export.rds not set / not found")
            return
        #if not pheno or not Path(pheno).exists():
        #    QMessageBox.warning(self, "Error", "phenotype.tsv not set / not found")
        #    return
        if not trait:
            QMessageBox.warning(self, "Error", "trait column is required")
            return

        extra = self.extra_json.toPlainText().strip()
        extra_dict = {}
        if extra:
            try:
                extra_dict = json.loads(extra)
                if not isinstance(extra_dict, dict):
                    raise ValueError("extra params must be a JSON object")
            except Exception as e:
                self.append_log(f"[poly_qtlpoly_scan] WARNING: invalid extra JSON ignored: {e}")
                QMessageBox.warning(self, "Invalid JSON", f"extra params must be a JSON object.\nIgnored.\n\nError: {e}")
                extra_dict = {}
        params = {
            "ploidy": int(self.ploidy.value()),
            "qtlpoly_export_rds": geno_prob,
            "pheno_tsv": pheno,
            "trait": trait,
            "map_markers_tsv": self.map_markers.text().strip(),
        }

        out_root = (self.output_dir.text() if hasattr(self, 'output_dir') else '').strip()
        if out_root:
            try:
                Path(out_root).mkdir(parents=True, exist_ok=True)
                params['export_dir'] = out_root
            except Exception as e:
                QMessageBox.warning(self, 'Error', f'Cannot create output_folder: {e}')
                return

        if extra_dict:
            params.update(extra_dict)
        run_dir = Path(tempfile.mkdtemp(prefix="poly_qtlpoly_"))
        self.append_log(f"Running plugin={self.PLUGIN_ID}")
        self.append_log(f"work_dir={run_dir}")
        try:
            out_dir = run_plugin(REGISTRY_PATH, self.PLUGIN_ID, params, run_dir)
        except Exception as e:
            self.append_log(f"[ERROR] {e}")
            QMessageBox.critical(self, "Run failed", str(e))
            return
        self.append_log(f"Done. out_dir={out_dir}")
        tsv = out_dir / "peaks.tsv"
        if tsv.exists():
            self.results.load_table(tsv)
        png = out_dir / "lod_plot.png"
        if png.exists():
            self.results.set_plot(png)


class PolyploidHub(QWidget):
    """Polyploid tools hub (scaffold): updog / fitPoly / PolyRAD / polymapR / QTLpoly.

    Philosophy:
      - Keep a shared PolyData (dosage.tsv + marker_info.tsv + sample_info.tsv).
      - Each backend is a thin plugin wrapper; advanced options stay in JSON for flexibility.
    """
    def __init__(self, app_log: QTextEdit, results: ResultsPane):
        super().__init__()
        tabs = QTabWidget()
        state = PolyOutputLinkState()
        tabs.addTab(PolyPrepareTab(app_log, results, state), "Prepare/QC")
        tabs.addTab(PolyUpdogTab(app_log, results, state), "Dosage calling")
        tabs.addTab(PolyGWASpolyTab(app_log, results, state), "GWAS (GWASpoly)")
        tabs.addTab(PolyMappolyWizardTab(app_log, results, state), "Linkage map (MAPpoly)")
        tabs.addTab(PolyQTLTab(app_log, results, state), "QTL (QTLpoly)")

        lay = QVBoxLayout()
        lay.addWidget(tabs)
        self.setLayout(lay)




