    def append_log(self, msg: str):
        ts = time.strftime("%H:%M:%S")
        self.app_log.append(f"[{ts}] {msg}")
    
    def _pick_file(self, le: QLineEdit, filt: str):
        fp, _ = QFileDialog.getOpenFileName(self, "Select file", "", filt)
        if fp:
            le.setText(fp)

    def _pick_export_dir(self):
        d = QFileDialog.getExistingDirectory(self, "Select export folder")
        if d:
            self.ed_export_dir.setText(d)

    def _on_use_org_at_toggled(self, checked: bool):
        # When using org.At.tair.db, n_genes will be overridden in the R runner.
        if checked:
            self._n_genes_prev = int(self.sp_n_genes.value())
            self.sp_n_genes.setEnabled(False)
            self.sp_n_genes.setToolTip("Overridden to the full org.At.tair.db gene set when enabled.")
        else:
            self.sp_n_genes.setEnabled(True)
            try:
                self.sp_n_genes.setValue(int(self._n_genes_prev))
            except Exception:
                pass
            self.sp_n_genes.setToolTip("")

    def _run(self):
        plugin_id = self.PLUGIN_ID
        cond_txt = (self.ed_conditions.text() or "A,B").strip()
        conds = [c.strip() for c in re.split(r"[\s,;]+", cond_txt) if c.strip()]
        if len(conds) < 2:
            QMessageBox.warning(self, "Invalid input", "Conditions must contain at least 2 names separated by commas.")
            return

        params = {
            "seed": int(self.sp_seed.value()),
            "n_genes": int(self.sp_n_genes.value()),
            "use_org_at_tair_db": bool(self.cb_use_org_at.isChecked()),
            "genename_file": str(self.ed_genename_file.text().strip()),
            "org_at_keytype": "TAIR",
            "n_samples_per_group": int(self.sp_n_per_group.value()),
            "conditions": conds,
            "n_batches": int(self.sp_n_batches.value()),
            "prop_de": float(self.ds_prop_de.value()),
            "lfc_sd": float(self.ds_lfc_sd.value()),
            "base_mean": float(self.ds_base_mean.value()),
            "dispersion": float(self.ds_disp.value()),
            "libsize_mean": float(self.ds_libsize_mean.value()),
            "libsize_sd": float(self.ds_libsize_sd.value()),
            "use_tcc": bool(self.cb_use_tcc.isChecked()),
            "export_dir": self.ed_export_dir.text().strip(),
        }

        run_dir = Path(tempfile.mkdtemp(prefix="simulate_rnaseq_"))
        self.append_log(f"Running plugin={plugin_id}")
        self.append_log(f"work_dir={run_dir}")
        try:
            out_dir = run_plugin(REGISTRY_PATH, plugin_id, params, run_dir)
        except Exception as e:
            self.append_log(f"[ERROR] {e}")
            QMessageBox.critical(self, "Generate failed", str(e))
            return

        self.append_log(f"Done. out_dir={out_dir}")
        # simulate_rnaseq runner writes under out/dataset/rnaseq/
        manifest = out_dir / "dataset" / "rnaseq" / "manifest.json"
        if manifest.exists():
            self.append_log(f"manifest={manifest}")
            try:
                self.results.set_text(manifest.read_text(encoding="utf-8"))
            except Exception:
                pass


