    """Generate synthetic datasets for quick end-to-end testing.

    Current scope (v0.1):
      - GWAS/QTL/GP core dataset: map.tsv + geno.tsv + pheno.tsv + split.tsv + manifest.json
      - Backend: internal simulator (always) + optional AlphaSimR (best-effort)

    The generated dataset follows a stable on-disk layout under out_dir/dataset.
    """

    PLUGIN_ID = "simulate_dataset"

